import type {
  NoteWithRelations,
  NoteCreateInput,
  NoteUpdateInput,
  CategoryRecord,
  CategoryCreateInput,
  CategoryUpdateInput,
  NotebookRecord,
  NotebookCreateInput,
  NotebookUpdateInput,
  TagRecord,
  TagCreateInput,
  TagUpdateInput,
  ThemeRecord,
  ThemeCreateInput,
  ThemeUpdateInput,
} from '@/shared/contracts/notes';
import type { DeleteResponse } from '@/shared/contracts/ui/api';
import { api } from '@/shared/lib/api-client';
import {
  createCreateMutationV2,
  createDeleteMutationV2,
  createUpdateMutationV2,
} from '@/shared/lib/query-factories-v2';
import { QUERY_KEYS } from '@/shared/lib/query-keys';

type InvalidationFn<T, U> = (data: T, vars: U) => string[];
type MutationConfig<T, U> = {
  path: string;
  operation: 'create' | 'update' | 'delete';
  resource: string;
  mutationKey: string | string[];
  invalidate?: string[] | InvalidationFn<T, U>;
};

const createNoteMutation = <T, U>(config: MutationConfig<T, U>) => {
  const { path, operation, resource, mutationKey, invalidate = [QUERY_KEYS.notes.all] } = config;
  const meta = {
    source: `notes.hooks.${operation}${resource}`,
    operation,
    resource,
    domain: 'notes',
    mutationKey,
    tags: ['notes', resource, operation],
    description: `${operation === 'create' ? 'Creates' : operation === 'update' ? 'Updates' : 'Deletes'} ${resource}.`,
  };

  switch (operation) {
    case 'create':
      return createCreateMutationV2<T, U>({
        mutationFn: (payload: U) => api.post<T>(path, payload),
        mutationKey,
        meta,
        invalidateKeys: invalidate as string[],
      });
    case 'update':
      return createUpdateMutationV2<T, U & { id: string }>({
        mutationFn: ({ id, ...data }: U & { id: string }) => api.patch<T>(`${path}/${id}`, data),
        mutationKey,
        meta,
        invalidateKeys: invalidate as InvalidationFn<T, U & { id: string }>,
      });
    case 'delete':
      return createDeleteMutationV2<DeleteResponse, string>({
        mutationFn: (id: string) => api.delete<DeleteResponse>(`${path}/${id}`),
        mutationKey,
        meta,
        invalidateKeys: invalidate as string[],
      });
  }
};

export const useCreateNote = () => createNoteMutation<NoteWithRelations, NoteCreateInput>({ path: '/api/notes', operation: 'create', resource: 'notes', mutationKey: QUERY_KEYS.notes.all });
export const useUpdateNote = () => createUpdateMutationV2<NoteWithRelations, NoteUpdateInput & { id: string }>({
    mutationFn: ({ id, ...data }: NoteUpdateInput & { id: string }) => api.patch<NoteWithRelations>(`/api/notes/${id}`, data),
    mutationKey: QUERY_KEYS.notes.all,
    meta: { source: 'notes.hooks.useUpdateNote', operation: 'update', resource: 'notes', domain: 'notes', mutationKey: QUERY_KEYS.notes.all, tags: ['notes', 'update'], description: 'Updates notes.'},
    invalidateKeys: (_d, vars) => [QUERY_KEYS.notes.all, QUERY_KEYS.notes.detail(vars.id)],
});
export const useDeleteNote = () => createNoteMutation<DeleteResponse, string>({ path: '/api/notes', operation: 'delete', resource: 'notes', mutationKey: QUERY_KEYS.notes.all });

export const useCreateNoteFolder = () => createNoteMutation<CategoryRecord, CategoryCreateInput>({ path: '/api/notes/categories', operation: 'create', resource: 'categories', mutationKey: QUERY_KEYS.notes.all });
export const useUpdateNoteFolder = () => createNoteMutation<CategoryRecord, CategoryUpdateInput>({ path: '/api/notes/categories', operation: 'update', resource: 'categories', mutationKey: QUERY_KEYS.notes.all });
export const useDeleteNoteFolder = () => createNoteMutation<DeleteResponse, string>({ path: '/api/notes/categories', operation: 'delete', resource: 'categories', mutationKey: QUERY_KEYS.notes.all });

export const useCreateNotebook = () => createNoteMutation<NotebookRecord, NotebookCreateInput>({ path: '/api/notes/notebooks', operation: 'create', resource: 'notebooks', mutationKey: QUERY_KEYS.notes.notebooks() });
export const useUpdateNotebook = () => createUpdateMutationV2<NotebookRecord, NotebookUpdateInput & { id: string }>({
    mutationFn: ({ id, ...data }: NotebookUpdateInput & { id: string }) => api.patch<NotebookRecord>(`/api/notes/notebooks/${id}`, data),
    mutationKey: QUERY_KEYS.notes.notebooks(),
    meta: { source: 'notes.hooks.useUpdateNotebook', operation: 'update', resource: 'notebooks', domain: 'notes', mutationKey: QUERY_KEYS.notes.notebooks(), tags: ['notes', 'notebooks', 'update'], description: 'Updates notes notebooks.'},
    invalidateKeys: (_d, vars) => [QUERY_KEYS.notes.notebooks(), QUERY_KEYS.notes.detail(vars.id)],
});
export const useDeleteNotebook = () => createNoteMutation<DeleteResponse, string>({ path: '/api/notes/notebooks', operation: 'delete', resource: 'notebooks', mutationKey: QUERY_KEYS.notes.notebooks() });

export const useCreateNoteTag = () => createNoteMutation<TagRecord, TagCreateInput>({ path: '/api/notes/tags', operation: 'create', resource: 'tags', mutationKey: QUERY_KEYS.notes.tags(), invalidate: (_d, v) => [QUERY_KEYS.notes.tags(), QUERY_KEYS.notes.tags(v.notebookId ?? undefined)] });
export const useUpdateNoteTag = () => createNoteMutation<TagRecord, TagUpdateInput>({ path: '/api/notes/tags', operation: 'update', resource: 'tags', mutationKey: QUERY_KEYS.notes.tags() });
export const useDeleteNoteTag = () => createNoteMutation<DeleteResponse, string>({ path: '/api/notes/tags', operation: 'delete', resource: 'tags', mutationKey: QUERY_KEYS.notes.tags() });

export const useCreateNoteTheme = () => createNoteMutation<ThemeRecord, ThemeCreateInput>({ path: '/api/notes/themes', operation: 'create', resource: 'themes', mutationKey: QUERY_KEYS.notes.themes(), invalidate: (_d, v) => [QUERY_KEYS.notes.themes(), QUERY_KEYS.notes.themes(v.notebookId ?? undefined)] });
export const useUpdateNoteTheme = () => createNoteMutation<ThemeRecord, ThemeUpdateInput>({ path: '/api/notes/themes', operation: 'update', resource: 'themes', mutationKey: QUERY_KEYS.notes.themes() });
export const useDeleteNoteTheme = () => createNoteMutation<DeleteResponse, string>({ path: '/api/notes/themes', operation: 'delete', resource: 'themes', mutationKey: QUERY_KEYS.notes.themes() });

import { z } from 'zod';
import {
  noteWithRelationsSchema,
  noteTagSchema,
  noteThemeSchema,
  noteCategorySchema,
  relatedNoteSchema,
} from '@/shared/contracts/notes';
import type {
  CategoryRecord,
  NoteWithRelations,
  TagRecord,
  ThemeRecord,
  RelatedNote,
  FetchNotesParams,
} from '@/shared/contracts/notes';
import type { ListQuery, SingleQuery } from '@/shared/contracts/ui/queries';
import { api } from '@/shared/lib/api-client';
import { createListQueryV2, createSingleQueryV2 } from '@/shared/lib/query-factories-v2';
import { noteKeys } from '@/shared/lib/query-key-exports';

export type { FetchNotesParams };
export * from './useNotebookResource';

const NOTES_STALE_MS = 10_000;

type QueryOptions = {
  enabled?: boolean;
};

const createNoteQuery = <T>(
  queryKey: string[],
  fetchFn: () => Promise<T[]>,
  resource: string,
  options?: QueryOptions
): ListQuery<T> =>
  createListQueryV2({
    queryKey,
    queryFn: fetchFn,
    enabled: options?.enabled ?? true,
    staleTime: NOTES_STALE_MS,
    meta: {
      source: `notes.queries.use${resource}`,
      operation: 'list',
      resource: `notes.${resource.toLowerCase()}`,
      domain: 'notes',
      queryKey,
      tags: ['notes', resource.toLowerCase()],
      description: `Loads notes ${resource.toLowerCase()}.`,
    },
  });

export function useNoteTags(notebookId?: string, options?: QueryOptions): ListQuery<TagRecord> {
  return createNoteQuery(
    noteKeys.tags(notebookId),
    async () => {
      const url = (notebookId !== undefined && notebookId !== '') 
        ? `/api/notes/tags?notebookId=${encodeURIComponent(notebookId)}` 
        : '/api/notes/tags';
      return z.array(noteTagSchema).parse(await api.get<TagRecord[]>(url));
    },
    'Tags',
    options
  );
}

export function useNoteThemes(notebookId?: string, options?: QueryOptions): ListQuery<ThemeRecord> {
  return createNoteQuery(
    noteKeys.themes(notebookId),
    async () => {
      const url = (notebookId !== undefined && notebookId !== '') 
        ? `/api/notes/themes?notebookId=${encodeURIComponent(notebookId)}` 
        : '/api/notes/themes';
      return z.array(noteThemeSchema).parse(await api.get<ThemeRecord[]>(url));
    },
    'Themes',
    options
  );
}

export function useNoteCategories(notebookId?: string | null, options?: QueryOptions): ListQuery<CategoryRecord> {
  return createNoteQuery(
    noteKeys.categories(notebookId ?? undefined),
    async () => {
      const url = (notebookId !== undefined && notebookId !== null && notebookId !== '') 
        ? `/api/notes/categories?notebookId=${encodeURIComponent(notebookId)}` 
        : '/api/notes/categories';
      return z.array(noteCategorySchema).parse(await api.get<CategoryRecord[]>(url));
    },
    'Categories',
    options
  );
}

const appendCsvParam = (search: URLSearchParams, key: string, values: string[] | undefined): void => {
  const normalizedValues = values?.map((val) => val.trim()).filter((val) => val !== '') ?? [];
  if (normalizedValues.length > 0) search.set(key, normalizedValues.join(','));
};

const buildNotesUrl = (params: FetchNotesParams): string => {
  const search = new URLSearchParams();
  const stringParams: (keyof Pick<FetchNotesParams, 'notebookId' | 'search' | 'searchScope'>)[] = ['notebookId', 'search', 'searchScope'];
  const booleanParams: (keyof Pick<FetchNotesParams, 'isPinned' | 'isArchived' | 'isFavorite' | 'truncateContent'>)[] = ['isPinned', 'isArchived', 'isFavorite', 'truncateContent'];

  stringParams.forEach((key) => {
    const val = params[key];
    if (val !== null && val !== undefined && val !== '') search.set(key, val);
  });
  booleanParams.forEach((key) => {
    if (params[key] === true) {
      search.set(key, 'true');
    }
  });

  appendCsvParam(search, 'categoryIds', params.categoryIds);
  appendCsvParam(search, 'tagIds', params.tagIds);
  const query = search.toString();
  return query !== '' ? `/api/notes?${query}` : '/api/notes';
};

export function useNotes(params: FetchNotesParams, options?: QueryOptions): ListQuery<NoteWithRelations> {
  const queryKey = noteKeys.list(params);
  return createListQueryV2({
    queryKey,
    queryFn: async (): Promise<NoteWithRelations[]> => {
      const data = await api.get<NoteWithRelations[]>(buildNotesUrl(params));
      return z.array(noteWithRelationsSchema).parse(data);
    },
    enabled: options?.enabled ?? true,
    staleTime: NOTES_STALE_MS,
    meta: {
      source: 'notes.queries.useNotes',
      operation: 'list',
      resource: 'notes.list',
      domain: 'notes',
      queryKey,
      tags: ['notes', 'list'],
      description: 'Loads notes list.',
    },
  });
}

export function useNote(noteId: string | null, options?: QueryOptions): SingleQuery<NoteWithRelations | null> {
  const queryKey = noteKeys.detail(noteId ?? 'none');
  return createSingleQueryV2({
    queryKey,
    queryFn: async (): Promise<NoteWithRelations | null> => {
      if (noteId === null || noteId === '') return null;
      const data = await api.get<NoteWithRelations>(`/api/notes/${noteId}`);
      return noteWithRelationsSchema.parse(data);
    },
    enabled: options?.enabled !== false && noteId !== null && noteId !== '',
    staleTime: NOTES_STALE_MS,
    meta: {
      source: 'notes.queries.useNote',
      operation: 'detail',
      resource: 'notes.detail',
      domain: 'notes',
      queryKey,
      tags: ['notes', 'detail'],
      description: 'Loads single note detail.',
    },
  });
}

export function useRelatedNotes(noteId: string | null, options?: QueryOptions): ListQuery<RelatedNote> {
  const queryKey = noteKeys.related(noteId ?? 'none');
  return createListQueryV2({
    queryKey,
    queryFn: async (): Promise<RelatedNote[]> => {
      if (noteId === null || noteId === '') return [];
      const data = await api.get<RelatedNote[]>(`/api/notes/${noteId}/related`);
      return z.array(relatedNoteSchema).parse(data);
    },
    enabled: options?.enabled !== false && noteId !== null && noteId !== '',
    staleTime: NOTES_STALE_MS,
    meta: {
      source: 'notes.queries.useRelatedNotes',
      operation: 'list',
      resource: 'notes.related',
      domain: 'notes',
      queryKey,
      tags: ['notes', 'related'],
      description: 'Loads related notes.',
    },
  });
}

export function useNotesLookup(noteIds: string[], options?: QueryOptions): ListQuery<RelatedNote> {
  const ids = noteIds.filter((id) => typeof id === 'string' && id.trim() !== '');
  const queryKey = noteKeys.lookup(ids);

  return createListQueryV2({
    queryKey,
    queryFn: async (): Promise<RelatedNote[]> => {
      if (ids.length === 0) return [];
      const data = await api.get<RelatedNote[]>('/api/notes/lookup', {
        params: { ids: ids.join(',') },
      });
      return z.array(relatedNoteSchema).parse(data);
    },
    enabled: (options?.enabled ?? true) && ids.length > 0,
    staleTime: NOTES_STALE_MS,
    refetchOnMount: false,
    refetchOnWindowFocus: false,
    refetchOnReconnect: false,
    meta: {
      source: 'notes.queries.useNotesLookup',
      operation: 'list',
      resource: 'notes.lookup',
      domain: 'notes',
      queryKey,
      tags: ['notes', 'lookup'],
      description: 'Loads note lookup results for a list of ids.',
    },
  });
}

import { z } from 'zod';
import {
  notebookSchema,
  type NotebookRecord,
} from '@/shared/contracts/notes';
import { api } from '@/shared/lib/api-client';
import { createListQueryV2 } from '@/shared/lib/query-factories-v2';
import { QUERY_KEYS } from '@/shared/lib/query-key-exports';
import type { ListQuery } from '@/shared/contracts/ui/queries';
import {
  useCreateNotebook,
  useUpdateNotebook,
  useDeleteNotebook,
} from './useNoteMutations';

export function useNotebookResource(): {
  listQuery: ListQuery<NotebookRecord>;
  createMutation: ReturnType<typeof useCreateNotebook>;
  updateMutation: ReturnType<typeof useUpdateNotebook>;
  deleteMutation: ReturnType<typeof useDeleteNotebook>;
} {
  const queryKey = QUERY_KEYS.notes.notebooks();

  const listQuery = createListQueryV2<NotebookRecord>({
    queryKey,
    queryFn: async (): Promise<NotebookRecord[]> => {
      const data = await api.get<NotebookRecord[]>('/api/notes/notebooks');
      return z.array(notebookSchema).parse(data);
    },
    meta: {
      source: 'notes.hooks.useNotebookResource.list',
      operation: 'list',
      resource: 'notes.notebooks',
      domain: 'notes',
      queryKey,
      tags: ['notes', 'notebooks'],
      description: 'Loads notes notebooks.',
    },
  });

  const createMutation = useCreateNotebook();
  const updateMutation = useUpdateNotebook();
  const deleteMutation = useDeleteNotebook();

  return {
    listQuery,
    createMutation,
    updateMutation,
    deleteMutation,
  };
}

'use client';

import React from 'react';

import { useNotesAppActions, useNotesAppState } from '@/features/notesapp/hooks/NotesAppContext';
import type { ThemeRecord, NoteWithRelations } from '@/shared/contracts/notes';
import { cn } from '@/shared/utils/ui-utils';
import { setNoteDragData } from '@/shared/utils/drag-drop';

import { renderNoteCardContent } from './list/NoteCardContent';
import { NoteCardFooter } from './list/NoteCardFooter';
import { NoteCardHeader } from './list/NoteCardHeader';

// Hardcoded dark mode fallback theme - consistent with page styling
const FALLBACK_THEME: Omit<ThemeRecord, 'id' | 'createdAt' | 'updatedAt' | 'name' | 'notebookId'> =
  {
    description: 'Default dark theme',
    isDefault: true,
    textColor: '#e5e7eb', // gray-200
    backgroundColor: '#111827', // gray-900
    markdownHeadingColor: '#ffffff', // white
    markdownLinkColor: '#60a5fa', // blue-400
    markdownCodeBackground: '#1f2937', // gray-800
    markdownCodeText: '#e5e7eb', // gray-200
    relatedNoteBorderWidth: 1,
    relatedNoteBorderColor: '#374151', // gray-700
    relatedNoteBackgroundColor: '#1f2937', // gray-800
    relatedNoteTextColor: '#e5e7eb', // gray-200
  };

type NoteCardProps = {
  note: NoteWithRelations;
};

const shouldIgnoreSelectionTarget = (
  target: EventTarget | null,
  currentTarget: HTMLElement
): boolean => {
  if (!(target instanceof HTMLElement)) return false;

  let current: HTMLElement | null = target;
  while (current && current !== currentTarget) {
    const tagName = current.tagName;
    if (
      tagName === 'BUTTON' ||
      tagName === 'A' ||
      tagName === 'INPUT' ||
      tagName === 'TEXTAREA' ||
      tagName === 'SELECT' ||
      tagName === 'SUMMARY'
    ) {
      return true;
    }

    const role = current.getAttribute('role');
    if (
      role === 'button' ||
      role === 'link' ||
      role === 'menuitem' ||
      role === 'option' ||
      current.isContentEditable
    ) {
      return true;
    }

    current = current.parentElement;
  }

  return false;
};

function NoteCardBase({ note }: NoteCardProps): React.JSX.Element {
  const { isFolderTreeCollapsed, getThemeForNote } = useNotesAppState();
  const { setSelectedNote, setIsEditing, setDraggedNoteId } = useNotesAppActions();
  const cardRef = React.useRef<HTMLDivElement | null>(null);

  const enableDrag = !isFolderTreeCollapsed;
  const onSelectNote = (next: NoteWithRelations): void => {
    setSelectedNote(next);
    setIsEditing(false);
  };
  const onDragStart = (noteId: string): void => setDraggedNoteId(noteId);
  const onDragEnd = (): void => setDraggedNoteId(null);
  const onNoteDragStart = (event: React.DragEvent<HTMLElement>): void => {
    setNoteDragData(event.dataTransfer, note.id);
    if (cardRef.current) {
      cardRef.current.style.opacity = '0.5';
    }
    onDragStart(note.id);
  };
  const onNoteDragEnd = (): void => {
    if (cardRef.current) {
      cardRef.current.style.opacity = '1';
    }
    onDragEnd();
  };
  // Use provided theme or fall back to dark mode theme
  const effectiveTheme = getThemeForNote(note) ?? FALLBACK_THEME;

  const normalizedColor = note.color?.toLowerCase().trim();
  // Only use note's custom color if it's not white (default)
  const hasCustomColor = normalizedColor && normalizedColor !== '#ffffff';
  const backgroundColor = hasCustomColor ? normalizedColor : effectiveTheme.backgroundColor;

  const getReadableTextColor = (hexColor: string): string => {
    const normalized = hexColor.replace('#', '');
    if (!/^[0-9a-fA-F]{6}$/.test(normalized)) {
      return '#111827';
    }
    const r = parseInt(normalized.slice(0, 2), 16);
    const g = parseInt(normalized.slice(2, 4), 16);
    const b = parseInt(normalized.slice(4, 6), 16);
    const luminance = (0.2126 * r + 0.7152 * g + 0.0722 * b) / 255;
    return luminance > 0.7 ? '#111827' : '#f8fafc';
  };

  const textColor = hasCustomColor
    ? getReadableTextColor(backgroundColor)
    : effectiveTheme.textColor;

  const selectNote = (): void => {
    onSelectNote(note);
  };

  const handleCardClick = (event: React.MouseEvent<HTMLElement>): void => {
    if (shouldIgnoreSelectionTarget(event.target, event.currentTarget)) {
      return;
    }
    if (event.defaultPrevented) return;
    selectNote();
  };

  const relatedNoteStyle = {
    borderWidth: `${effectiveTheme.relatedNoteBorderWidth ?? 1}px`,
    borderColor: effectiveTheme.relatedNoteBorderColor,
    backgroundColor: effectiveTheme.relatedNoteBackgroundColor,
    color: effectiveTheme.relatedNoteTextColor,
  } as const;

  return (
    <div
      ref={cardRef}
      key={note.id}
      onClick={handleCardClick}
      style={{
        backgroundColor,
        color: textColor,
        ['--tw-prose-body' as never]: textColor,
        ['--tw-prose-headings' as never]: effectiveTheme.markdownHeadingColor ?? textColor,
        ['--note-link-color' as never]: effectiveTheme.markdownLinkColor ?? '#38bdf8',
        ['--note-code-bg' as never]: effectiveTheme.markdownCodeBackground ?? '#0f172a',
        ['--note-code-text' as never]: effectiveTheme.markdownCodeText ?? '#e2e8f0',
        ['--note-inline-code-bg' as never]:
          effectiveTheme.markdownCodeBackground ?? 'rgba(15, 23, 42, 0.12)',
      }}
      className={cn(
        'rounded-lg border border-border/60 p-4 transition',
        'cursor-pointer hover:shadow-md hover:brightness-90'
      )}
    >
      <div>
        <NoteCardHeader
          note={note}
          onSelectNote={onSelectNote}
          enableDrag={enableDrag}
          onNoteDragStart={onNoteDragStart}
          onNoteDragEnd={onNoteDragEnd}
        />
        {renderNoteCardContent({ note })}
        <NoteCardFooter
          note={note}
          backgroundColor={backgroundColor}
          relatedNoteStyle={relatedNoteStyle}
        />
      </div>
    </div>
  );
}

export const NoteCard = React.memo(NoteCardBase);
NoteCard.displayName = 'NoteCard';

'use client';

import { X } from 'lucide-react';
import Image from 'next/image';
import React from 'react';

import {
  NoteFormProvider,
  useNoteEditorContext,
  useNoteFilesContext,
  useNoteFormRuntime,
  useNoteMetadataContext,
} from '@/features/notesapp/context/NoteFormContext';
import type { NoteFormProps } from '@/shared/contracts/notes';
import { Button, Input, Dialog, DialogContent, DialogDescription, DialogTitle } from '@/shared/ui/primitives.public';
import { FormField, FormSection } from '@/shared/ui/forms-and-actions.public';

import { FileAttachments } from './editor/FileAttachments';
import { MarkdownEditor } from './editor/MarkdownEditor';
import { NoteMetadata } from './editor/NoteMetadata';
import { NotesMarkdownToolbar } from './editor/NotesMarkdownToolbar';
import { WysiwygEditor } from './editor/WysiwygEditor';

type NoteFormViewContextValue = {
  formRef?: React.RefObject<HTMLFormElement | null> | undefined;
};

const NoteFormViewContext = React.createContext<NoteFormViewContextValue>({});

function useNoteFormViewContext(): NoteFormViewContextValue {
  return React.useContext(NoteFormViewContext);
}

function NoteFormInner(): React.JSX.Element {
  const { formRef } = useNoteFormViewContext();
  const { note, handleSubmit } = useNoteFormRuntime();
  const { title, setTitle } = useNoteMetadataContext();
  const { editorMode } = useNoteEditorContext();
  const { lightboxImage, setLightboxImage } = useNoteFilesContext();

  return (
    <>
      <form
        id={note ? 'note-edit-form' : undefined}
        ref={formRef}
        onSubmit={(e: React.FormEvent): void => {
          void handleSubmit(e);
        }}
      >
        <FormSection className='p-0 border-none shadow-none bg-transparent space-y-6'>
          <FormField label='Title'>
            <Input
              type='text'
              placeholder='Enter note title'
              value={title}
              onChange={(e: React.ChangeEvent<HTMLInputElement>): void => setTitle(e.target.value)}
              className='w-full rounded-lg border bg-card/40 px-4 py-2 text-white text-lg font-semibold placeholder:text-gray-500 focus:border-blue-500 focus:outline-none focus-visible:ring-2 focus-visible:ring-ring/40 focus-visible:ring-offset-2 focus-visible:ring-offset-background h-12'
              required
             aria-label='Enter note title' title='Enter note title'/>
          </FormField>

          <FormField label='Content'>
            <NotesMarkdownToolbar />
            <div className='mt-2'>
              {editorMode === 'markdown' || editorMode === 'code' ? (
                <MarkdownEditor />
              ) : (
                <WysiwygEditor />
              )}
            </div>
          </FormField>

          <FileAttachments />

          <NoteMetadata showTitle={false} />
        </FormSection>
      </form>

      <Dialog open={Boolean(lightboxImage)} onOpenChange={(open) => !open && setLightboxImage(null)}>
        <DialogContent className='max-w-screen-xl border-none bg-black/90 p-0 shadow-none sm:max-w-screen-xl'>
          <DialogTitle className='sr-only'>Image Preview</DialogTitle>
          <DialogDescription className='sr-only'>
            Full-screen preview of the selected note attachment.
          </DialogDescription>
          <div className='relative h-[90vh] w-[90vw]'>
            {lightboxImage && (
              <Image
                src={lightboxImage}
                alt='Lightbox preview'
                fill
                sizes='90vw'
                className='object-contain'
              />
            )}
            <Button
              type='button'
              variant='ghost'
              size='icon'
              className='absolute right-4 top-4 rounded-full bg-black/20 text-white hover:bg-black/40'
              onClick={() => setLightboxImage(null)}
              aria-label='Close image preview'
              title='Close image preview'
            >
              <X size={24} />
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </>
  );
}

export function NoteForm(
  props: NoteFormProps & {
    formRef?: React.RefObject<HTMLFormElement | null> | undefined;
  }
): React.JSX.Element {
  const { note, onSuccess, formRef } = props;

  const viewContextValue = React.useMemo(
    () => ({
      formRef: formRef ?? undefined,
    }),
    [formRef]
  );

  return (
    <NoteFormProvider note={note ?? null} onSuccess={onSuccess}>
      <NoteFormViewContext.Provider value={viewContextValue}>
        <NoteFormInner />
      </NoteFormViewContext.Provider>
    </NoteFormProvider>
  );
}

'use client';

import { Plus, Pin, Archive, ChevronLeft, ChevronRight, FileText, Palette } from 'lucide-react';
import React, { useMemo } from 'react';

import { useNotesAppActions, useNotesAppState } from '@/features/notesapp/hooks/NotesAppContext';
import type { NoteWithRelations, ThemeRecord } from '@/shared/contracts/notes';
import type { PickerGroup, PickerOption } from '@/shared/contracts/ui/pickers';
import { TriggerButtonBar } from '@/shared/lib/ai-paths/components/trigger-buttons/TriggerButtonBar';
import { Button } from '@/shared/ui/primitives.public';
import { EmptyState, Pagination } from '@/shared/ui/navigation-and-layout.public';
import { DocumentSearchPage } from '@/shared/ui/templates.public';
import { GenericPickerDropdown } from '@/shared/ui/templates/pickers';

import { NoteCard } from './NoteCard';
import { NotesFilters } from './NotesFilters';
import { buildBreadcrumbPath } from '../utils';

type BreadcrumbItem = { id: string | null; name: string; isNote?: boolean };

const DEFAULT_THEME_OPTION: PickerOption = { key: '', label: 'Default' };

const buildThemeOptions = (themes: ThemeRecord[]): PickerOption[] => [
  DEFAULT_THEME_OPTION,
  ...themes.map((theme: ThemeRecord) => ({
    key: theme.id,
    label: theme.name,
  })),
];

export function NoteListView(): React.JSX.Element {
  const {
    settings,
    filters,
    folderTree,
    themes,
    loading,
    selectedFolderId,
    sortedNotes,
    pagedNotes,
    totalPages,
    noteLayoutClassName,
    selectedFolderThemeId,
    isFolderTreeCollapsed,
  } = useNotesAppState();
  const {
    handleThemeChange,
    setSelectedFolderId,
    setSelectedNote,
    setIsEditing,
    setIsCreating,
    setIsFolderTreeCollapsed,
  } = useNotesAppActions();

  const {
    page,
    setPage,
    pageSize,
    setPageSize,
    filterPinned,
    setFilterPinned,
    filterArchived,
    setFilterArchived,
  } = filters;

  const onExpandFolderTree = (): void => setIsFolderTreeCollapsed(false);
  const onCreateNote = (): void => {
    setIsCreating(true);
    setSelectedNote(null);
  };

  const themeOptions = useMemo(() => buildThemeOptions(themes), [themes]);
  const themeGroups = useMemo<PickerGroup[]>(
    () => [
      {
        label: 'Available Themes',
        icon: <Palette className='h-3 w-3' />,
        options: themeOptions,
      },
    ],
    [themeOptions]
  );

  return (
    <DocumentSearchPage
      title={
        selectedFolderId
          ? (buildBreadcrumbPath(selectedFolderId, null, folderTree).slice(-1)[0]?.name ?? 'Notes')
          : 'Notes'
      }
      startAdornment={
        <>
          {isFolderTreeCollapsed ? (
            <Button
              onClick={onExpandFolderTree}
              variant='outline'
              size='xs'
              className='border text-gray-300 hover:bg-muted/50 hover:text-white'
            >
              <ChevronLeft className='-scale-x-100' size={16} />
              <span className='ml-2'>Show Folders</span>
            </Button>
          ) : null}
          <Button
            onClick={onCreateNote}
            className='size-11 rounded-full bg-primary p-0 text-primary-foreground hover:bg-primary/90'
            aria-label='Create note'
            title={'Create note'}>
            <Plus className='size-5' />
          </Button>
        </>
      }
      titleAdornment={
        <div className='flex items-center gap-2'>
          <span className='text-xs text-gray-500'>Theme</span>
          <GenericPickerDropdown
            groups={themeGroups}
            selectedKey={selectedFolderThemeId || ''}
            onSelect={(opt: PickerOption) => {
              void handleThemeChange(opt.key || null);
            }}
            triggerContent={
              <span className='text-xs'>
                {selectedFolderThemeId
                  ? themeGroups
                    .flatMap((g) => g.options)
                    .find((o) => o.key === selectedFolderThemeId)?.label
                  : 'Select theme'}
              </span>
            }
            triggerClassName='w-32 justify-between border border-border/40 rounded bg-card/50 text-gray-400 hover:text-gray-200 px-2'
            ariaLabel='Change folder theme'
          />
        </div>
      }
      endAdornment={
        <>
          <TriggerButtonBar location='note_list' entityType='note' />
          <Pagination
            page={page}
            totalPages={totalPages}
            onPageChange={setPage}
            pageSize={pageSize}
            onPageSizeChange={setPageSize}
            pageSizeOptions={[12, 24, 48]}
            showPageSize
            variant='compact'
          />
        </>
      }
      filters={
        <div className='flex gap-4'>
          <NotesFilters />
          <Button
            onClick={(): void => setFilterPinned(filterPinned === true ? undefined : true)}
            className={`rounded-lg border px-4 py-2 ${
              filterPinned === true
                ? 'border-blue-500 bg-blue-600 text-white'
                : 'border bg-gray-800 text-gray-300'
            }`}
            aria-label='Filter pinned notes'
            aria-pressed={filterPinned === true}
            title='Filter pinned notes'
          >
            <Pin size={20} />
          </Button>
          <Button
            onClick={(): void => setFilterArchived(filterArchived === true ? undefined : true)}
            className={`rounded-lg border px-4 py-2 ${
              filterArchived === true
                ? 'border-gray-500 bg-gray-700 text-white'
                : 'border bg-gray-800 text-gray-300'
            }`}
            aria-label='Filter archived notes'
            aria-pressed={filterArchived === true}
            title='Filter archived notes'
          >
            <Archive size={20} />
          </Button>
        </div>
      }
      breadcrumb={
        settings.selectedFolderId ? (
          <div className='mb-6 flex items-center gap-2 text-sm text-gray-400'>
            {buildBreadcrumbPath(settings.selectedFolderId, null, folderTree).map(
              (crumb: BreadcrumbItem, index: number, array: BreadcrumbItem[]) => (
                <React.Fragment key={index}>
                  <Button
                    variant='ghost'
                    size='xs'
                    onClick={(): void => {
                      if (crumb.id) setSelectedFolderId(crumb.id);
                      setSelectedNote(null);
                      setIsEditing(false);
                    }}
                    className='hover:text-blue-400 transition'
                  >
                    {crumb.name}
                  </Button>
                  {index < array.length - 1 ? (
                    <ChevronRight size={16} className='text-gray-600' />
                  ) : null}
                </React.Fragment>
              )
            )}
          </div>
        ) : null
      }
      loading={loading}
      hasResults={sortedNotes.length > 0}
      emptyState={
        <EmptyState
          title='No notes found'
          description='Create your first note to get started!'
          icon={<FileText className='size-12' />}
          action={
            <Button onClick={onCreateNote}>
              <Plus className='mr-2 size-4' />
              Create Note
            </Button>
          }
        />
      }
    >
      <div className={noteLayoutClassName}>
        {pagedNotes.map((note: NoteWithRelations) => (
          <NoteCard key={note.id} note={note} />
        ))}
      </div>
    </DocumentSearchPage>
  );
