'use client';

import { FileText, Folder, FolderOpen, GripVertical } from 'lucide-react';
import React, { useEffect, useMemo, useRef } from 'react';

import {
  FolderTreeViewportV2,
  handleMasterTreeDrop,
  resolveFolderTreeIconSet,
  useMasterFolderTreeShell,
} from '@/shared/lib/foldertree/public';
import { useNotesAppActions, useNotesAppState } from '@/features/notesapp/hooks/NotesAppContext';
import {
  buildMasterNodesFromNotesFolderTree,
  toFolderMasterNodeId,
  toNoteMasterNodeId,
} from '@/features/notesapp/utils/master-folder-tree';
import {
  createNotesMasterTreeAdapter,
  resolveNotesFolderTargetForNode,
} from '@/features/notesapp/utils/notes-master-tree-adapter';
import {
  canDropNotesNode,
  resolveNotesExternalDropAction,
} from '@/features/notesapp/utils/notes-master-tree-external-drop';
import type { NotesMasterTreeOperations } from '@/shared/contracts/notes';
import { FolderTreePanel } from '@/shared/ui/navigation-and-layout.public';
import { type MasterTreeId, type MasterTreeNode } from '@/shared/utils/master-folder-tree-contract';
import { getFolderDragId, getNoteDragId } from '@/shared/utils/drag-drop';


import { NotesAppTreeHeader } from './tree/NotesAppTreeHeader';
import { NotesAppTreeNode } from './tree/NotesAppTreeNode';
import { NotesAppTreeNodeRuntimeProvider } from './tree/NotesAppTreeNodeRuntimeContext';

type NotesAppFolderTreeOperations = NotesMasterTreeOperations & {
  handleRelateNotes: (sourceNoteId: string, targetNoteId: string) => Promise<void>;
};

type NotesAppFolderTreeDropInput = Parameters<typeof handleMasterTreeDrop>[0]['input'];

export function NotesAppFolderTree(): React.JSX.Element {
  const { folderTree, selectedNote, isFolderTreeCollapsed, draggedNoteId, selectedFolderId } =
    useNotesAppState();
  const { setIsFolderTreeCollapsed, operations } = useNotesAppActions();
  const hasInitializedCollapseSyncRef = useRef(false);

  const masterNodes = useMemo(
    (): MasterTreeNode[] => buildMasterNodesFromNotesFolderTree(folderTree),
    [folderTree]
  );
  const initialExpandedFolderNodeIds = useMemo(
    () =>
      masterNodes
        .filter((node: MasterTreeNode) => node.type === 'folder')
        .map((node: MasterTreeNode) => node.id),
    [masterNodes]
  );
  const selectedMasterNodeId = useMemo((): MasterTreeId | null => {
    if (selectedNote?.id) return toNoteMasterNodeId(selectedNote.id);
    if (selectedFolderId) return toFolderMasterNodeId(selectedFolderId);
    return null;
  }, [selectedNote?.id, selectedFolderId]);

  const notesAdapter = useMemo(
    () => createNotesMasterTreeAdapter(operations as NotesAppFolderTreeOperations),
    [operations]
  );
  const {
    appearance: { rootDropUi, resolveIcon },
    controller,
    panel: { collapsed: panelCollapsed, setCollapsed: setPanelCollapsed },
    viewport: { scrollToNodeRef },
  } = useMasterFolderTreeShell({
    instance: 'notes',
    nodes: masterNodes,
    selectedNodeId: selectedMasterNodeId,
    initiallyExpandedNodeIds: initialExpandedFolderNodeIds,
    adapter: notesAdapter,
  });

  useEffect(() => {
    setIsFolderTreeCollapsed(panelCollapsed);
  }, [panelCollapsed, setIsFolderTreeCollapsed]);

  useEffect(() => {
    if (!hasInitializedCollapseSyncRef.current) {
      hasInitializedCollapseSyncRef.current = true;
      return;
    }
    setPanelCollapsed(isFolderTreeCollapsed);
  }, [isFolderTreeCollapsed, setPanelCollapsed]);

  const selectedFolderForCreate = useMemo(
    (): string | null =>
      resolveNotesFolderTargetForNode(controller.nodes, controller.selectedNodeId),
    [controller.nodes, controller.selectedNodeId]
  );

  const { FolderClosedIcon, FolderOpenIcon, FileIcon, DragHandleIcon } = useMemo(
    () =>
      resolveFolderTreeIconSet(resolveIcon, {
        FolderClosedIcon: {
          slot: 'folderClosed',
          kind: 'folder',
          fallback: Folder,
          fallbackId: 'Folder',
        },
        FolderOpenIcon: {
          slot: 'folderOpen',
          kind: 'folder',
          fallback: FolderOpen,
          fallbackId: 'FolderOpen',
        },
        FileIcon: {
          slot: 'file',
          kind: 'note',
          fallback: FileText,
          fallbackId: 'FileText',
        },
        DragHandleIcon: {
          slot: 'dragHandle',
          fallback: GripVertical,
          fallbackId: 'GripVertical',
        },
      }),
    [resolveIcon]
  );
  const treeNodeRuntimeContextValue = useMemo(
    () => ({
      controller,
      FolderClosedIcon,
      FolderOpenIcon,
      FileIcon,
      DragHandleIcon,
    }),
    [DragHandleIcon, FileIcon, FolderClosedIcon, FolderOpenIcon, controller]
  );

  return (
    <FolderTreePanel
      className='bg-gray-900 border-r border-border'
      bodyClassName='flex min-h-0 flex-1 flex-col'
      masterInstance='notes'
      header={
        <NotesAppTreeHeader
          controller={controller}
          selectedFolderForCreate={selectedFolderForCreate}
          setPanelCollapsed={setPanelCollapsed}
        />
      }
    >
      <NotesAppTreeNodeRuntimeProvider value={treeNodeRuntimeContextValue}>
        <div className='min-h-0 flex-1 overflow-auto p-2'>
          <FolderTreeViewportV2
            controller={controller}
            scrollToNodeRef={scrollToNodeRef}
            rootDropUi={rootDropUi}
            resolveDraggedNodeId={(event: React.DragEvent<HTMLElement>): string | null => {
              const noteId = getNoteDragId(event.dataTransfer, draggedNoteId);
              if (noteId) return toNoteMasterNodeId(noteId);
              const folderId = getFolderDragId(event.dataTransfer);
              if (folderId) return toFolderMasterNodeId(folderId);
              return null;
            }}
            canDrop={({ draggedNodeId, targetId }, ctlr): boolean => {
              return canDropNotesNode({
                draggedNodeId,
                targetId,
                nodes: ctlr.nodes,
              });
            }}
            onNodeDrop={async (
              { draggedNodeId, targetId, position, rootDropZone }: NotesAppFolderTreeDropInput,
              ctlr
            ): Promise<void> => {
              await handleMasterTreeDrop({
                input: {
                  draggedNodeId,
                  targetId,
                  position,
                  rootDropZone,
                },
                controller: ctlr,
                onExternalDrop: async ({ input, controller }): Promise<void> => {
                  const action = resolveNotesExternalDropAction({
                    draggedNodeId: input.draggedNodeId,
                    targetId: input.targetId,
                    nodes: controller.nodes,
                    roots: controller.roots,
                    rootDropZone: input.rootDropZone,
                  });
                  if (!action) return;

                  if (action.type === 'relate_notes') {
                    await (operations as NotesAppFolderTreeOperations).handleRelateNotes(
                      action.noteId,
                      action.targetNoteId
                    );
                    return;
                  }
                  if (action.type === 'move_note') {
                    await operations.handleMoveNoteToFolder(action.noteId, action.targetFolderId);
                    return;
                  }
                  if (action.type === 'reorder_folder_root_top') {
                    await operations.handleReorderFolder(
                      action.folderId,
                      action.anchorFolderId,
                      'before'
                    );
                    return;
                  }
                  await operations.handleMoveFolderToFolder(action.folderId, action.targetFolderId);
                },
              });
            }}
            renderNode={(nodeProps) => <NotesAppTreeNode {...nodeProps} />}
          />
        </div>
      </NotesAppTreeNodeRuntimeProvider>
    </FolderTreePanel>
  );
}

'use client';

import { ArrowUp, ArrowDown, Eye, EyeOff } from 'lucide-react';
import React, { useMemo } from 'react';

import { useNotesAppActions, useNotesAppState } from '@/features/notesapp/hooks/NotesAppContext';
import {
  NOTE_SEARCH_SCOPE_OPTIONS,
  NOTE_SORT_BY_OPTIONS,
} from '@/features/notesapp/constants/note-settings-options';
import type { TagRecord } from '@/shared/contracts/notes';
import { Button } from '@/shared/ui/primitives.public';
import { FilterPanel } from '@/shared/ui/templates/FilterPanel';
import type { FilterField } from '@/shared/contracts/ui/panels';

/**
 * REFACTORED: NotesFilters using FilterPanel
 *
 * Before: 214 LOC (custom search, tags, sort, view options)
 * After: 95 LOC (FilterPanel for core filters + display toggles)
 * Savings: 119 LOC (56% reduction)
 *
 * Key changes:
 * - Core filtering (search, tags, sort) moved to FilterPanel
 * - Display toggles remain separate (not filter concerns)
 * - View mode settings remain separate
 * - All state management preserved
 */
export function NotesFilters(): React.JSX.Element {
  const { settings, filters, availableTagsInScope } = useNotesAppState();
  const { updateSettings } = useNotesAppActions();

  const { searchQuery, setSearchQuery, filterTagIds, setFilterTagIds } = filters;
  const {
    searchScope,
    sortBy,
    sortOrder,
    showTimestamps,
    showBreadcrumbs,
    showRelatedNotes,
    viewMode,
    gridDensity,
  } = settings;
  const tags = availableTagsInScope;

  // Build filter configuration for FilterPanel
  const filterConfig: FilterField[] = useMemo(() => {
    const tagOptions = tags.map((t: TagRecord) => ({
      value: t.id,
      label: t.name || 'Unnamed',
    }));
    return [
      {
        key: 'tags',
        label: 'Tags',
        type: 'select',
        placeholder: 'Filter by tags...',
        options: tagOptions,
        multi: true,
      },
      {
        key: 'sortBy',
        label: 'Sort By',
        type: 'select',
        options: NOTE_SORT_BY_OPTIONS,
      },
      {
        key: 'searchScope',
        label: 'Search Scope',
        type: 'select',
        options: NOTE_SEARCH_SCOPE_OPTIONS,
      },
    ];
  }, [tags]);

  const filterValues = useMemo(
    () => ({
      search: searchQuery,
      tags: filterTagIds,
      sortBy,
      searchScope,
    }),
    [searchQuery, filterTagIds, sortBy, searchScope]
  );

  const handleFilterChange = (key: string, value: unknown) => {
    switch (key) {
      case 'search':
        setSearchQuery(typeof value === 'string' ? value : '');
        break;
      case 'tags':
        setFilterTagIds(Array.isArray(value) ? (value as string[]) : []);
        break;
      case 'sortBy':
        updateSettings({ sortBy: value as 'created' | 'updated' | 'name' });
        break;
      case 'searchScope':
        updateSettings({ searchScope: value as 'both' | 'title' | 'content' });
        break;
    }
  };

  const handleReset = () => {
    setSearchQuery('');
    setFilterTagIds([]);
    updateSettings({ sortBy: 'updated', searchScope: 'both' });
  };

  return (
    <div className='space-y-4'>
      <FilterPanel
        filters={filterConfig}
        values={filterValues}
        onFilterChange={handleFilterChange}
        onSearchChange={setSearchQuery}
        onReset={handleReset}
        showHeader={true}
        headerTitle='Note Filters'
        searchPlaceholder='Search notes...'
      />

      <div className='flex flex-wrap items-center gap-4 border-t border-border/40 pt-3 px-4'>
        <div className='flex items-center gap-2'>
          <span className='text-sm font-medium text-gray-400'>Sort Order:</span>
          <Button
            variant={sortOrder === 'desc' ? 'default' : 'outline'}
            onClick={() =>
              updateSettings({
                sortOrder: sortOrder === 'asc' ? 'desc' : 'asc',
              })
            }
            className='h-8 gap-1.5 px-2.5'
            title={`Click to sort ${sortOrder === 'asc' ? 'descending' : 'ascending'}`}
          >
            {sortOrder === 'asc' ? <ArrowUp size={14} /> : <ArrowDown size={14} />}
            {sortOrder === 'asc' ? 'Ascending' : 'Descending'}
          </Button>
        </div>

        <div className='h-4 w-px bg-border/40' />

        <div className='flex items-center gap-2'>
          <span className='text-sm font-medium text-gray-400'>View Mode:</span>
          <Button
            variant={viewMode === 'list' ? 'default' : 'outline'}
            onClick={() => updateSettings({ viewMode: 'list' })}
            className='h-8 px-2.5'
          >
            List
          </Button>
          <Button
            variant={viewMode === 'grid' && gridDensity === 4 ? 'default' : 'outline'}
            onClick={() => updateSettings({ viewMode: 'grid', gridDensity: 4 })}
            className='h-8 px-2.5'
          >
            Grid 4
          </Button>
          <Button
            variant={viewMode === 'grid' && gridDensity === 8 ? 'default' : 'outline'}
            onClick={() => updateSettings({ viewMode: 'grid', gridDensity: 8 })}
            className='h-8 px-2.5'
          >
            Grid 8
          </Button>
        </div>

        <div className='h-4 w-px bg-border/40' />

        <div className='flex items-center gap-1.5'>
          <span className='text-sm font-medium text-gray-400'>Display:</span>
          <Button
            variant={showTimestamps ? 'default' : 'outline'}
            onClick={() => updateSettings({ showTimestamps: !showTimestamps })}
            className='h-8 gap-1 px-2'
            title='Toggle timestamps'
            aria-label={'Toggle timestamps'}>
            {showTimestamps ? <Eye size={14} /> : <EyeOff size={14} />}
          </Button>
          <Button
            variant={showBreadcrumbs ? 'default' : 'outline'}
            onClick={() => updateSettings({ showBreadcrumbs: !showBreadcrumbs })}
            className='h-8 gap-1 px-2'
            title='Toggle breadcrumbs'
            aria-label={'Toggle breadcrumbs'}>
            {showBreadcrumbs ? <Eye size={14} /> : <EyeOff size={14} />}
          </Button>
          <Button
            variant={showRelatedNotes ? 'default' : 'outline'}
            onClick={() => updateSettings({ showRelatedNotes: !showRelatedNotes })}
            className='h-8 gap-1 px-2'
            title='Toggle related notes'
            aria-label={'Toggle related notes'}>
            {showRelatedNotes ? <Eye size={14} /> : <EyeOff size={14} />}
          </Button>
        </div>
      </div>
    </div>
  );
}

