  if (!selectedNote) return null;

  return (
    <div className={`${UI_CENTER_ROW_RELAXED_CLASSNAME} mb-4`}>
      <Button
        onClick={(): void => {
          if (isEditing) {
            setIsEditing(false);
          } else {
            setSelectedNote(null);
          }
        }}
        className='min-w-[80px] border border-white/20 hover:border-white/40'
      >
        Back
      </Button>
      <Button
        type='button'
