      <div className='ml-auto'>
        <TriggerButtonBar
          location='note_modal'
          entityType='note'
          entityId={selectedNote.id}
          getEntityJson={() => selectedNote as Record<string, unknown>}
        />
      </div>
    </div>
  );
}

