'use client';

import React, { useMemo } from 'react';

import { useNotesAppActions, useNotesAppState } from '@/features/notesapp/hooks/NotesAppContext';
import { useToast } from '@/shared/ui/primitives.public';
import { sanitizeHtml } from '@/shared/utils/sanitization';

import { NoteDetailRelatedNotes } from './NoteDetailRelatedNotes';
import { renderMarkdownToHtml } from '../../utils';

export function NoteDetailPreview(): React.JSX.Element | null {
  const { selectedNote, selectedNoteTheme } = useNotesAppState();
  const { setIsEditing } = useNotesAppActions();

  if (!selectedNote) return null;

  const { toast } = useToast();

  const getReadableTextColor = (hexColor: string): string => {
    const normalized = hexColor.replace('#', '');
    if (!/^[0-9a-fA-F]{6}$/.test(normalized)) {
      return '#f8fafc';
    }
    const r = parseInt(normalized.slice(0, 2), 16);
    const g = parseInt(normalized.slice(2, 4), 16);
    const b = parseInt(normalized.slice(4, 6), 16);
    const luminance = (0.2126 * r + 0.7152 * g + 0.0722 * b) / 255;
    return luminance > 0.7 ? '#0f172a' : '#f8fafc';
  };

  const fallbackTheme = useMemo(
    () => ({
      textColor: '#e5e7eb',
      backgroundColor: '#111827',
      markdownHeadingColor: '#f9fafb',
      markdownLinkColor: '#93c5fd',
      markdownCodeBackground: '#1f2937',
      markdownCodeText: '#e5e7eb',
      relatedNoteBorderWidth: 1,
      relatedNoteBorderColor: '#374151',
      relatedNoteBackgroundColor: '#1f2937',
      relatedNoteTextColor: '#e5e7eb',
    }),
    []
  );

  const effectivePreviewTheme = selectedNoteTheme ?? fallbackTheme;

  const previewStyle = useMemo((): React.CSSProperties => {
    const normalizedColor = selectedNote?.color?.toLowerCase().trim();
    const isDefaultColor = !normalizedColor || normalizedColor === '#ffffff';
    const color = !isDefaultColor
      ? (normalizedColor ?? selectedNote?.color ?? effectivePreviewTheme.backgroundColor)
      : effectivePreviewTheme.backgroundColor ||
        normalizedColor ||
        selectedNote?.color ||
        '#1f2937';
    const hex = color.replace('#', '');
    if (!/^[0-9a-fA-F]{6}$/.test(hex)) {
      return { backgroundColor: color };
    }
    const r = parseInt(hex.slice(0, 2), 16);
    const g = parseInt(hex.slice(2, 4), 16);
    const b = parseInt(hex.slice(4, 6), 16);
    const luminance = (0.2126 * r + 0.7152 * g + 0.0722 * b) / 255;
    const borderColor = luminance > 0.78 ? 'rgba(15, 23, 42, 0.35)' : 'rgba(148, 163, 184, 0.2)';
    return {
      backgroundColor: color,
      borderColor,
      boxShadow: luminance > 0.78 ? '0 0 0 1px rgba(15, 23, 42, 0.12)' : undefined,
    };
  }, [selectedNote?.color, effectivePreviewTheme.backgroundColor]);

  const previewTextColor = useMemo((): string => {
    const normalizedColor = selectedNote?.color?.toLowerCase().trim();
    const isDefaultColor = !normalizedColor || normalizedColor === '#ffffff';
    const background = !isDefaultColor
      ? (normalizedColor ?? selectedNote?.color ?? effectivePreviewTheme.backgroundColor)
      : effectivePreviewTheme.backgroundColor ||
        normalizedColor ||
        selectedNote?.color ||
        '#1f2937';
    if (effectivePreviewTheme.textColor && !isDefaultColor) {
      return getReadableTextColor(background);
    }
    return effectivePreviewTheme.textColor ?? getReadableTextColor(background);
  }, [selectedNote?.color, effectivePreviewTheme.backgroundColor, effectivePreviewTheme.textColor]);

  const previewTypographyStyle = useMemo(
    () => ({
      color: previewTextColor,
      ['--tw-prose-body' as never]: previewTextColor,
      ['--tw-prose-headings' as never]:
        effectivePreviewTheme.markdownHeadingColor ?? previewTextColor,
      ['--tw-prose-lead' as never]: previewTextColor,
      ['--tw-prose-bold' as never]: previewTextColor,
      ['--tw-prose-counters' as never]: previewTextColor,
      ['--tw-prose-bullets' as never]: previewTextColor,
      ['--tw-prose-quotes' as never]: previewTextColor,
      ['--tw-prose-quote-borders' as never]: 'rgba(148, 163, 184, 0.35)',
      ['--tw-prose-hr' as never]: 'rgba(148, 163, 184, 0.35)',
      ['--note-link-color' as never]: effectivePreviewTheme.markdownLinkColor ?? '#38bdf8',
      ['--note-code-bg' as never]: effectivePreviewTheme.markdownCodeBackground ?? '#0f172a',
      ['--note-code-text' as never]: effectivePreviewTheme.markdownCodeText ?? '#e2e8f0',
      ['--note-inline-code-bg' as never]:
        effectivePreviewTheme.markdownCodeBackground ?? 'rgba(15, 23, 42, 0.12)',
    }),
    [previewTextColor, effectivePreviewTheme]
  );

  const contentRenderer = renderMarkdownToHtml as (val: string) => string;
  const previewContentRef = React.useRef<HTMLDivElement | null>(null);
  const copyResetTimeoutRef = React.useRef<number | null>(null);

  React.useEffect(() => {
    const previewContent = previewContentRef.current;
    if (!previewContent) return;

    const revealCopyButton = (event: MouseEvent, visible: boolean): void => {
      const target = event.target;
      if (!(target instanceof HTMLElement)) return;
      const wrapper = target.closest('[data-code]');
      const button = wrapper?.querySelector('[data-copy-code]');
      if (button instanceof HTMLElement) {
        button.style.opacity = visible ? '1' : '0';
      }
    };

    const handleClick = (event: MouseEvent): void => {
      const target = event.target;
      if (!(target instanceof HTMLElement)) return;
      const copyButton = target.closest('[data-copy-code]');
      if (!(copyButton instanceof HTMLButtonElement)) return;
      const wrapper = copyButton.closest('[data-code]');
      const encoded = wrapper?.getAttribute('data-code');
      if (!encoded) return;
      const originalLabel = copyButton.textContent;
      void navigator.clipboard
        .writeText(decodeURIComponent(encoded))
        .then((): void => {
          copyButton.textContent = 'Copied';
          if (copyResetTimeoutRef.current !== null) {
            window.clearTimeout(copyResetTimeoutRef.current);
          }
          copyResetTimeoutRef.current = window.setTimeout((): void => {
            copyResetTimeoutRef.current = null;
            copyButton.textContent = originalLabel ?? 'Copy';
          }, 1500);
        })
        .catch((): void => {
          toast('Failed to copy code', { variant: 'error' });
        });
    };

    const handleMouseOver = (event: MouseEvent): void => revealCopyButton(event, true);
    const handleMouseOut = (event: MouseEvent): void => revealCopyButton(event, false);

    previewContent.addEventListener('mouseover', handleMouseOver);
    previewContent.addEventListener('mouseout', handleMouseOut);
    previewContent.addEventListener('click', handleClick);

    return (): void => {
      previewContent.removeEventListener('mouseover', handleMouseOver);
      previewContent.removeEventListener('mouseout', handleMouseOut);
      previewContent.removeEventListener('click', handleClick);
      if (copyResetTimeoutRef.current !== null) {
        window.clearTimeout(copyResetTimeoutRef.current);
        copyResetTimeoutRef.current = null;
      }
    };
  }, [toast]);

  return (
    <div
      className='flex-1 overflow-y-auto rounded-lg border border-border/60 bg-card/40 p-6 cursor-text'
      onDoubleClick={() => setIsEditing(true)}
      style={previewStyle}
    >
      <h1 className='mb-4 text-3xl font-bold' style={{ color: previewTextColor }}>
        {selectedNote.title}
      </h1>
      <div
        ref={previewContentRef}
        className='prose max-w-none'
        style={previewTypographyStyle}
        dangerouslySetInnerHTML={{
          __html: sanitizeHtml(
            typeof selectedNote.editorType === 'string' && selectedNote.editorType === 'wysiwyg'
              ? selectedNote.content
              : contentRenderer(selectedNote.content)
          ),
        }}
      />

      <NoteDetailRelatedNotes />

      <div className='mt-8 pt-4 border-t border-border flex gap-6 text-sm text-gray-500'>
        <span>Created: {new Date(selectedNote.createdAt || 0).toLocaleString()}</span>
        <span>
          Modified:{' '}
          {selectedNote.updatedAt
            ? new Date(selectedNote.updatedAt || 0).toLocaleString()
            : 'Never'}
        </span>
      </div>
    </div>
  );
}

'use client';

import { X } from 'lucide-react';
import React, { useMemo } from 'react';

import { useNotesLookup } from '@/features/notesapp/api/useNoteQueries';
import { useNotesAppActions, useNotesAppState } from '@/features/notesapp/hooks/NotesAppContext';
import type {
  NoteRelationWithSource,
  NoteRelationWithTarget,
  RelatedNote,
} from '@/shared/contracts/notes';
import { Button } from '@/shared/ui/primitives.public';

export function NoteDetailRelatedNotes(): React.JSX.Element | null {
  const { selectedNote, selectedNoteTheme } = useNotesAppState();
  const { handleSelectNoteFromTree, handleUnlinkRelatedNote } = useNotesAppActions();

  const onSelectRelatedNote = (id: string): void => {
    void handleSelectNoteFromTree(id);
  };

  const onUnlinkRelatedNote = (id: string): Promise<void> => handleUnlinkRelatedNote(id);

  const relatedNotes = useMemo((): RelatedNote[] => {
    if (!selectedNote) return [];
    if (selectedNote.relations && selectedNote.relations.length > 0) {
      return selectedNote.relations;
    }

    const build = (
      id: string | undefined,
      title: string | undefined,
      color: string | null | undefined
    ): RelatedNote | null =>
      id ? { id, title: title ?? 'Untitled note', color: color ?? null } : null;

    const fromRelations = (selectedNote.relationsFrom ?? [])
      .map((relation: NoteRelationWithTarget) =>
        build(
          relation.targetNote?.id ?? relation.targetNoteId,
          relation.targetNote?.title,
          relation.targetNote?.color
        )
      )
      .filter((item: RelatedNote | null): item is RelatedNote => Boolean(item));

    const toRelations = (selectedNote.relationsTo ?? [])
      .map((relation: NoteRelationWithSource) =>
        build(
          relation.sourceNote?.id ?? relation.sourceNoteId,
          relation.sourceNote?.title,
          relation.sourceNote?.color
        )
      )
      .filter((item: RelatedNote | null): item is RelatedNote => Boolean(item));

    return [...fromRelations, ...toRelations];
  }, [selectedNote]);

  const relationIds = useMemo(
    (): string[] =>
      relatedNotes
        .map((rel: RelatedNote) => rel.id)
        .filter(
          (id: string, index: number, array: string[]): boolean =>
            array.findIndex((entry: string): boolean => entry === id) === index
        ),
    [relatedNotes]
  );

  const { data: linkedDetails } = useNotesLookup(relationIds);

  const relatedPreviewNotes = useMemo(() => {
    const map: Record<string, RelatedNote> = {};
    (linkedDetails ?? []).forEach((n) => {
      map[n.id] = {
        id: n.id,
        title: n.title,
        color: n.color,
        content: n.content ?? undefined,
      };
    });
    return map;
  }, [linkedDetails]);

  const fallbackTheme = useMemo(
    () => ({
      relatedNoteBorderWidth: 1,
      relatedNoteBorderColor: '#374151',
      relatedNoteBackgroundColor: '#1f2937',
      relatedNoteTextColor: '#e5e7eb',
    }),
    []
  );

  const effectivePreviewTheme = selectedNoteTheme ?? fallbackTheme;

  const relatedPreviewStyle = useMemo(
    () => ({
      borderWidth: `${effectivePreviewTheme.relatedNoteBorderWidth ?? 1}px`,
      borderColor: effectivePreviewTheme.relatedNoteBorderColor ?? 'rgba(15, 23, 42, 0.2)',
      backgroundColor: effectivePreviewTheme.relatedNoteBackgroundColor ?? 'rgba(15, 23, 42, 0.05)',
      color: effectivePreviewTheme.relatedNoteTextColor ?? '#f8fafc',
    }),
    [effectivePreviewTheme]
  );

  if (!selectedNote || relatedNotes.length === 0) return null;

  return (
    <div className='mt-6 space-y-4'>
      <div className='space-y-2'>
        <div className='text-xs uppercase tracking-wide text-gray-400'>Related Notes</div>
        <div className='flex flex-wrap gap-2'>
          {relatedNotes
            .filter(
              (noteItem: RelatedNote, index: number, array: RelatedNote[]) =>
                array.findIndex((item: RelatedNote) => item.id === noteItem.id) === index
            )
            .map((related: RelatedNote) => {
              const relatedNote = relatedPreviewNotes[related.id];
              return (
                <div
                  key={related.id}
                  className='relative w-40 rounded-md border border-border/60 bg-card/30 p-2 text-left text-xs transition hover:bg-muted/40'
                  style={relatedPreviewStyle}
                >
                  <button
                    type='button'
                    onClick={(): void => onSelectRelatedNote(related.id)}
                    className='flex w-full flex-col rounded-sm pr-6 text-left focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-sky-400/70 focus-visible:ring-offset-2 focus-visible:ring-offset-slate-950'
                    aria-label={`Open related note ${relatedNote?.title ?? related.title}`}
                  >
                    <div className='truncate font-semibold'>
                      {relatedNote?.title ?? related.title}
                    </div>
                    <div className='line-clamp-2 text-[11px] opacity-80'>
                      {relatedNote?.content ?? 'No content'}
                    </div>
                  </button>
                  <Button
                    type='button'
                    onClick={(event: React.MouseEvent<HTMLButtonElement>): void => {
                      event.stopPropagation();
                      void onUnlinkRelatedNote(related.id);
                    }}
                    className='absolute right-2 top-2 opacity-70 hover:opacity-100'
                    aria-label='Unlink related note'
                    title={'Unlink related note'}>
                    <X size={12} />
                  </Button>
                </div>
              );
            })}
        </div>
      </div>
    </div>
  );
}

'use client';

import { Upload, FileIcon, Link2, Trash2 } from 'lucide-react';
import Image from 'next/image';
import React from 'react';

import {
  useNoteFilesContext,
  useNoteFormRuntime,
} from '@/features/notesapp/context/NoteFormContext';
import type { NoteFileRecord } from '@/shared/contracts/notes';
import type { FileUploadHelpers } from '@/shared/contracts/ui/base';
import { Button, Label, Card } from '@/shared/ui/primitives.public';
import { FileUploadTrigger } from '@/shared/ui/forms-and-actions.public';
import { LoadingState } from '@/shared/ui/navigation-and-layout.public';

export function FileAttachments(): React.JSX.Element {
  const { note } = useNoteFormRuntime();
  const {
    noteFiles,
    MAX_SLOTS: maxSlots,
    uploadingSlots,
    getNextAvailableSlot,
    handleFileUpload: onFileUpload,
    handleMultiFileUpload: onMultiFileUpload,
    handleFileDelete: onFileDelete,
    insertFileReference: onInsertFileReference,
    formatFileSize,
    isImageFile,
  } = useNoteFilesContext();

  if (!note?.id) {
    return (
      <Card
        variant='subtle-compact'
        padding='md'
        className='border-dashed border-border/60 bg-card/30 text-center text-sm text-gray-400'
      >
        Save the note first to enable file attachments ({maxSlots} slots available)
      </Card>
    );
  }

  return (
    <div className='space-y-2'>
      <Label className='mb-2 block text-sm font-medium text-white'>
        Attachments ({noteFiles.length}/{maxSlots} slots used)
      </Label>
      <div className='flex flex-wrap gap-3'>
        {((): React.JSX.Element => {
          const nextSlot = getNextAvailableSlot();
          const isUploading = nextSlot !== null && uploadingSlots.has(nextSlot);
          return (
            <Card
              variant='subtle-compact'
              padding='none'
              className='relative h-20 w-20 border-border bg-card/40'
              onDragOver={(e: React.DragEvent): void => e.preventDefault()}
              onDrop={(e: React.DragEvent): void => {
                if (nextSlot === null) return;
                e.preventDefault();
                const file = e.dataTransfer.files[0];
                if (file) {
                  void onFileUpload(nextSlot, file);
                }
              }}
            >
              {isUploading ? (
                <LoadingState size='sm' />
              ) : nextSlot === null ? (
                <div className='flex h-full items-center justify-center text-[10px] text-gray-500'>
                  Full
                </div>
              ) : (
                <Label className='flex h-full cursor-pointer flex-col items-center justify-center text-gray-500 hover:bg-card/60 hover:text-gray-400 transition-colors'>
                  <FileUploadTrigger
                    multiple
                    asChild
                    onFilesSelected={(files: File[], helpers?: FileUploadHelpers) =>
                      onMultiFileUpload(files, helpers)
                    }
                  >
                    <span className='flex h-full w-full flex-col items-center justify-center'>
                      <Upload size={14} />
                      <span className='mt-1 text-[10px]'>Upload</span>
                      <span className='mt-0.5 text-[10px] text-gray-400'>
                        {maxSlots - noteFiles.length} left
                      </span>
                    </span>
                  </FileUploadTrigger>
                </Label>
              )}
            </Card>
          );
        })()}

        {noteFiles.map((file: NoteFileRecord) => (
          <Card
            key={file.slotIndex}
            variant='subtle-compact'
            padding='none'
            className='relative h-20 w-24 border-border bg-card/50'
          >
            <div className='group relative h-full'>
              {isImageFile(file.mimetype) ? (
                <Image
                  src={file.filepath}
                  alt={file.filename}
                  width={96}
                  height={80}
                  className='h-full w-full rounded-md object-cover'
                />
              ) : (
                <div className='flex h-full flex-col items-center justify-center p-2'>
                  <FileIcon className='h-6 w-6 text-gray-400' />
                  <span className='mt-1 text-[10px] text-gray-400 truncate w-full text-center'>
                    {file.filename.length > 12 ? `${file.filename.slice(0, 10)  }...` : file.filename}
                  </span>
                </div>
              )}
              <div className='absolute inset-0 flex items-center justify-center gap-2 rounded-md bg-black/60 opacity-0 transition-opacity group-hover:opacity-100'>
                <Button
                  type='button'
                  onClick={(): void => onInsertFileReference(file)}
                  variant='solid'
                  size='icon'
                  className='h-7 w-7'
                  title='Insert into content'
                  aria-label={'Insert into content'}>
                  <Link2 size={12} />
                </Button>
                <Button
                  type='button'
                  onClick={(): void => {
                    void onFileDelete(file.slotIndex);
                  }}
                  variant='solid-destructive'
                  size='icon'
                  className='h-7 w-7'
                  title='Delete file'
                  aria-label={'Delete file'}>
                  <Trash2 size={12} />
                </Button>
              </div>
              <div className='absolute bottom-0 left-0 right-0 rounded-b-md bg-black/70 px-1 py-0.5 text-[9px] text-gray-300 truncate'>
                {formatFileSize(file.size)}
              </div>
            </div>
          </Card>
        ))}
      </div>
      <p className='text-xs text-gray-500'>
        Drag and drop files or click to upload. Max 10MB per file.
      </p>
    </div>
  );
}

