import React from 'react';

import {
  MarkdownToolbar as DocumentMarkdownToolbar,
  MarkdownToolbarProvider,
} from '@/shared/lib/document-editor/public';
import {
  useNoteContentContext,
  useNoteEditorContext,
  useNoteFilesContext,
} from '@/features/notesapp/context/NoteFormContext';
import { useMarkdownEditor } from '@/features/notesapp/hooks/useMarkdownEditor';
import type { NoteFileRecord } from '@/shared/contracts/notes';


export function NotesMarkdownToolbar(): React.JSX.Element {
  const { content, setContent, undo, redo, canUndo, canRedo } = useNoteContentContext();
  const {
    textColor,
    setTextColor,
    fontFamily,
    setFontFamily,
    showPreview,
    setShowPreview,
    editorMode,
    setEditorMode,
    isEditorModeLocked,
    isMigrating,
    handleMigrateToWysiwyg,
    handleMigrateToMarkdown,
    contentRef,
  } = useNoteEditorContext();
  const { noteFiles, insertFileReference } = useNoteFilesContext();
  const markdownToolbarActions = useMarkdownEditor({
    content,
    setContent,
    contentRef,
  });

  const fileReferenceOptions = React.useMemo(
    () =>
      noteFiles.map((file: NoteFileRecord) => {
        const cleanedName = file.filename.replace(/^slot-\d+-\d+-/, '');
        const shortName = cleanedName.length > 15 ? `${cleanedName.slice(0, 15)}...` : cleanedName;
        return {
          value: String(file.slotIndex),
          label: `Slot ${file.slotIndex + 1}: ${shortName}`,
        };
      }),
    [noteFiles]
  );
  const toolbarContextValue = React.useMemo(
    () => ({
      mode: editorMode,
      onModeChange: setEditorMode,
      isModeLocked: isEditorModeLocked,
      isMigrating,
      onMigrateToWysiwyg: (): void => {
        void handleMigrateToWysiwyg(content);
      },
      onMigrateToMarkdown: (): void => {
        void handleMigrateToMarkdown(content);
      },
      showPreview,
      onTogglePreview: (): void => {
        setShowPreview(!showPreview);
      },
      onUndo: undo,
      onRedo: redo,
      canUndo,
      canRedo,
      textColor,
      onTextColorChange: setTextColor,
      fontFamily,
      onFontFamilyChange: setFontFamily,
      fileReferenceOptions,
      onInsertFileReference: (value: string): void => {
        const slotIndex = Number.parseInt(value, 10);
        const targetFile = noteFiles.find((file: NoteFileRecord) => file.slotIndex === slotIndex);
        if (!targetFile) return;
        insertFileReference(targetFile);
      },
      ...markdownToolbarActions,
    }),
    [
      canRedo,
      canUndo,
      content,
      editorMode,
      fileReferenceOptions,
      fontFamily,
      handleMigrateToMarkdown,
      handleMigrateToWysiwyg,
      insertFileReference,
      isEditorModeLocked,
      isMigrating,
      markdownToolbarActions,
      noteFiles,
      redo,
      setEditorMode,
      setFontFamily,
      setShowPreview,
      setTextColor,
      showPreview,
      textColor,
      undo,
    ]
  );

  return (
    <MarkdownToolbarProvider value={toolbarContextValue}>
      <DocumentMarkdownToolbar />
    </MarkdownToolbarProvider>
  );
}

import Image from 'next/image';
import React from 'react';

import type { NoteFileRecord } from '@/shared/contracts/notes';
import type { NoteWithRelations } from '@/shared/contracts/notes';
import { Tag } from '@/shared/ui/forms-and-actions.public';
import { sanitizeHtml } from '@/shared/utils/sanitization';

import { renderMarkdownToHtml } from '../../utils';

export type NoteCardContentProps = {
  note: NoteWithRelations;
};

export function renderNoteCardContent(props: NoteCardContentProps): React.JSX.Element {
  const { note } = props;
  let html =
    (note.editorType as string) === 'wysiwyg' ? note.content : renderMarkdownToHtml(note.content);
  // Remove image tags from preview to avoid duplication with thumbnail
  html = html.replace(/<img[^>]*>/g, '');
  // Also remove image paragraphs (markdown renders images in <p> tags)
  html = html.replace(/<p>\s*<\/p>/g, '');
  const sanitizedContentHtml = sanitizeHtml(html);

  const thumbnailFile = note.files?.find(
    (file: NoteFileRecord) => file.mimetype?.startsWith('image/') && file.filepath
  );

  return (
    <div className='pt-0'>
      {thumbnailFile && (
        <div className='mb-3 overflow-hidden rounded-md border'>
          <Image
            src={thumbnailFile.filepath}
            alt={thumbnailFile.filename}
            width={320}
            height={180}
            className='h-28 w-full object-cover'
            sizes='(min-width: 1024px) 240px, 100vw'
          />
        </div>
      )}
      <div
        className='mb-3 max-h-36 overflow-hidden text-sm prose prose-sm'
        dangerouslySetInnerHTML={{ __html: sanitizedContentHtml }}
      />
      <div className='flex flex-wrap gap-2'>
        {note.tags?.map((nt: { tagId: string; tag: { color?: string | null; name?: string } }) => (
          <Tag key={nt.tagId} color={nt.tag.color ?? null} label={nt.tag.name || 'Unnamed'} />
        ))}
      </div>
    </div>
  );
}

import type {
  NoteRelationWithSource,
  NoteRelationWithTarget,
  NoteWithRelations,
  RelatedNote,
} from '@/shared/contracts/notes';

const buildRelatedNote = (
  id: string | undefined,
  title: string | undefined,
  color: string | null | undefined
): RelatedNote | null => (id ? { id, title: title ?? 'Untitled note', color: color ?? null } : null);

const fromTargetRelation = (relation: NoteRelationWithTarget): RelatedNote | null =>
  buildRelatedNote(
    relation.targetNote?.id ?? relation.targetNoteId,
    relation.targetNote?.title,
    relation.targetNote?.color
  );

const fromSourceRelation = (relation: NoteRelationWithSource): RelatedNote | null =>
  buildRelatedNote(
    relation.sourceNote?.id ?? relation.sourceNoteId,
    relation.sourceNote?.title,
    relation.sourceNote?.color
  );

export const resolveNoteCardFooterRelatedNotes = (note: NoteWithRelations): RelatedNote[] => {
  if (note.relations && note.relations.length > 0) {
    return note.relations;
  }

  return [...(note.relationsFrom ?? []).map(fromTargetRelation), ...(note.relationsTo ?? []).map(fromSourceRelation)]
    .filter((item: RelatedNote | null): item is RelatedNote => Boolean(item));
};

export const dedupeRelatedNotes = (relatedNotes: RelatedNote[]): RelatedNote[] => {
  const seen = new Set<string>();

  return relatedNotes.filter((item) => {
    if (seen.has(item.id)) {
      return false;
    }

    seen.add(item.id);
    return true;
  });
};

export const shouldRenderNoteCardFooter = (input: {
  relatedNotes: RelatedNote[];
  showBreadcrumbs: boolean;
  showRelatedNotes: boolean;
  showTimestamps: boolean;
}): boolean =>
  input.showTimestamps ||
  input.showBreadcrumbs ||
  (input.showRelatedNotes && input.relatedNotes.length > 0);

'use client';

import React from 'react';

import { useNotesAppActions, useNotesAppState } from '@/features/notesapp/hooks/NotesAppContext';
import type {
  NoteWithRelations,
  RelatedNote,
} from '@/shared/contracts/notes';
import { Breadcrumbs } from '@/shared/ui/navigation-and-layout.public';

import { buildBreadcrumbPath, darkenColor } from '../../utils';
import {
  dedupeRelatedNotes,
  resolveNoteCardFooterRelatedNotes,
  shouldRenderNoteCardFooter,
} from './NoteCardFooter.helpers';

type BreadcrumbItem = { id: string | null; name: string };

export type NoteCardFooterProps = {
  note: NoteWithRelations;
  backgroundColor: string;
  relatedNoteStyle: React.CSSProperties;
};

export function NoteCardFooter(props: NoteCardFooterProps): React.JSX.Element | null {
  const { note, backgroundColor, relatedNoteStyle } = props;
  const { folderTree, settings } = useNotesAppState();
  const { setSelectedFolderId, setSelectedNote, setIsEditing } = useNotesAppActions();

  const showTimestamps = settings.showTimestamps;
  const showBreadcrumbs = settings.showBreadcrumbs;
  const showRelatedNotes = settings.showRelatedNotes;

  const onSelectFolder = (folderId: string | null): void => {
    setSelectedFolderId(folderId);
    setSelectedNote(null);
    setIsEditing(false);
  };

  const breadcrumbs = React.useMemo(
    () =>
      buildBreadcrumbPath(
        note.categories?.[0]?.categoryId || null,
        null,
        folderTree
      ) as BreadcrumbItem[],
    [note.categories, folderTree]
  );

  const relatedNotes = React.useMemo((): RelatedNote[] => resolveNoteCardFooterRelatedNotes(note), [note]);

  if (
    !shouldRenderNoteCardFooter({
      relatedNotes,
      showBreadcrumbs,
      showRelatedNotes,
      showTimestamps,
    })
  ) {
    return null;
  }

  return (
    <div className='flex flex-col items-stretch pt-2 mt-2 border-t border-white/10'>
      {showTimestamps && (
        <div className='flex flex-col gap-0.5 text-[10px] text-gray-500'>
          <span>Created: {new Date(note.createdAt || 0).toLocaleString()}</span>
          <span>
            Modified: {note.updatedAt ? new Date(note.updatedAt || 0).toLocaleString() : 'Never'}
          </span>
        </div>
      )}
      {showBreadcrumbs && (
        <div className={showTimestamps ? 'mt-3' : ''}>
          <Breadcrumbs
            scrollable
            backgroundColor={darkenColor(backgroundColor, 20)}
            items={breadcrumbs.map((crumb) => ({
              label: crumb.name,
              onClick: (e) => {
                e.stopPropagation();
                if (crumb.id) onSelectFolder(crumb.id);
              },
            }))}
          />
        </div>
      )}

      {showRelatedNotes && relatedNotes.length > 0 && (
        <div className='mt-2 flex flex-wrap gap-2'>
          {dedupeRelatedNotes(relatedNotes)
            .slice(0, 4)
            .map((related: RelatedNote) => (
              <div
                key={related.id}
                className='w-24 cursor-pointer rounded-md px-2 py-1 text-[10px]'
                style={relatedNoteStyle}
              >
                <div className='truncate font-semibold'>{related.title}</div>
                <div className='line-clamp-2 text-[9px] opacity-80'>No content</div>
              </div>
            ))}
        </div>
      )}
    </div>
  );
}

