  setSelectedNote: (note: NoteWithRelations | null) => void;
  setIsCreating: (isCreating: boolean) => void;
  setSelectedFolderId: (folderId: string | null) => void;
  setIsFolderTreeCollapsed: (isCollapsed: boolean) => void;
  setPanelCollapsed: (collapsed: boolean) => void;
  onSelectAllNotes: () => void;
  onToggleFavorites: () => void;
  handleUndoFolderTree: (steps: number) => Promise<void>;
  handleCreateFolder: (parentId?: string | null) => Promise<void>;
};

export function NotesAppTreeHeader({
  controller,
  selectedFolderForCreate,
  setPanelCollapsed,
}: NotesAppTreeHeaderProps): React.JSX.Element {
  const { settings, filters, undoStack, undoHistory } = useNotesAppState();
  const {
    setSelectedNote,
    setIsEditing,
    setIsCreating,
    setIsFolderTreeCollapsed,
    handleUndoFolderTree,
    handleUndoAtIndex,
    setSelectedFolderId,
    operations,
  } = useNotesAppActions();

  const isAllNotesActive = !settings.selectedFolderId && !settings.selectedNoteId;
  const actionsRuntimeValue: NotesAppTreeHeaderActionsRuntimeValue = {
    selectedFolderForCreate,
    undoStackLength: undoStack.length,
    isAllNotesActive,
    isFavoritesFilterActive: filters.filterFavorite === true,
    setSelectedNote,
    setIsCreating,
    setSelectedFolderId,
    setIsFolderTreeCollapsed,
    setPanelCollapsed,
    onSelectAllNotes: () => {
      setSelectedFolderId(null);
      setSelectedNote(null);
      setIsEditing(false);
      controller.selectNode(null);
    },
    onToggleFavorites: () => {
      filters.handleToggleFavoritesFilter(setSelectedFolderId, setSelectedNote, setIsEditing);
    },
    handleUndoFolderTree,
    handleCreateFolder: (operations as NotesTreeHeaderOperations).handleCreateFolder,
  };

  return (
    <TreeHeader
      title='Folders'
      actions={
        <>
          <Button
            onClick={(): void => {
              void actionsRuntimeValue.handleCreateFolder(actionsRuntimeValue.selectedFolderForCreate);
            }}
            size='sm'
            variant='outline'
            className='h-7 w-7 p-0 border text-gray-300 hover:bg-muted/50'
            title='Add folder'
            aria-label='Add folder'
          >
            <FolderPlus className='size-4' />
          </Button>
          <Button
            onClick={(): void => {
              actionsRuntimeValue.setSelectedFolderId(actionsRuntimeValue.selectedFolderForCreate);
              actionsRuntimeValue.setIsCreating(true);
              actionsRuntimeValue.setSelectedNote(null);
            }}
            size='sm'
            variant='outline'
            className='h-7 w-7 p-0 border text-gray-300 hover:bg-muted/50'
            title='Add note'
            aria-label='Add note'
          >
            <FilePlus className='size-4' />
          </Button>
          <Button
            onClick={(): void => {
              void actionsRuntimeValue.handleUndoFolderTree(1);
            }}
            size='sm'
            variant='outline'
            className='h-7 px-2 border text-gray-300 hover:bg-muted/50'
            disabled={actionsRuntimeValue.undoStackLength === 0}
          >
            Undo
          </Button>
          <Button
            onClick={(): void => {
              actionsRuntimeValue.setIsFolderTreeCollapsed(true);
              actionsRuntimeValue.setPanelCollapsed(true);
            }}
            size='sm'
            variant='outline'
            className='h-7 w-7 p-0 border text-gray-300 hover:bg-muted/50'
            title='Collapse folder tree'
            aria-label='Collapse folder tree'
          >
            <ChevronRight className='size-4' />
          </Button>
        </>
      }
    >
      <Button
        onClick={actionsRuntimeValue.onSelectAllNotes}
        className={`w-full justify-start gap-2 px-2 py-1.5 text-left text-sm ${
          actionsRuntimeValue.isAllNotesActive
            ? 'bg-blue-600 text-white'
            : 'text-gray-300 hover:bg-muted/50'
        }`}
      >
        <Folder className='size-4' />
        <span>All Notes</span>
      </Button>
      <Button
        onClick={actionsRuntimeValue.onToggleFavorites}
        className={`mt-1 w-full justify-start gap-2 px-2 py-1.5 text-left text-sm ${
          actionsRuntimeValue.isFavoritesFilterActive
            ? 'bg-yellow-500/20 text-yellow-200'
            : 'text-gray-300 hover:bg-muted/50'
        }`}
      >
        <Star className='size-4' />
        <span>Favorites</span>
      </Button>
        {undoHistory.length > 0 && (
          <div className='mt-3 rounded border border-border bg-card/60 p-2 text-xs text-gray-300'>
            <div className='mb-2 text-[10px] uppercase tracking-wide text-gray-500'>History</div>
            <div className='space-y-1'>
              {undoHistory.slice(0, 10).map((entry: { label: string }, index: number) => (
                <Button
                  key={`${entry.label}-${index}`}
                  type='button'
                  onClick={(): void => handleUndoAtIndex(index)}
                  className='flex w-full items-center justify-between rounded px-1.5 py-1 text-left text-gray-300 hover:bg-muted/50'
                >
                  <span className='truncate'>{entry.label}</span>
                </Button>
              ))}
            </div>
          </div>
        )}
    </TreeHeader>
  );
}

'use client';

import { ChevronDown, ChevronRight, FilePlus, FolderPlus, Copy, Edit2, Trash2 } from 'lucide-react';
import React from 'react';

import type { FolderTreeViewportRenderNodeInput as NotesAppTreeNodeProps } from '@/shared/lib/foldertree/public';
import { useNotesAppActions } from '@/features/notesapp/hooks/NotesAppContext';
import {
  fromFolderMasterNodeId,
  fromNoteMasterNodeId,
} from '@/features/notesapp/utils/master-folder-tree';
import { DOCUMENTATION_MODULE_IDS } from '@/shared/contracts/documentation';
import type { NotesMasterTreeOperations } from '@/shared/contracts/notes';
import { getDocumentationTooltip } from '@/shared/lib/documentation/tooltips';
import { Button, Input, Tooltip } from '@/shared/ui/primitives.public';
import { cn } from '@/shared/utils/ui-utils';

import { useNotesAppTreeNodeRuntimeContext } from './NotesAppTreeNodeRuntimeContext';

export type { NotesAppTreeNodeProps };

type NotesAppTreeNodeOperations = NotesMasterTreeOperations & {
  handleCreateFolder: (parentId?: string | null) => Promise<void>;
  handleDuplicateNote: (noteId: string) => Promise<void>;
  handleDeleteFolder: (folderId: string) => Promise<void>;
  handleDeleteNoteFromTree: (noteId: string) => Promise<void>;
};

export function NotesAppTreeNode(props: NotesAppTreeNodeProps): React.JSX.Element {
  const {
    node,
    depth,
    hasChildren,
    isExpanded,
    isSelected,
    isRenaming,
    select,
    toggleExpand,
    startRename,
  } = props;

  const { controller, FolderClosedIcon, FolderOpenIcon, FileIcon, DragHandleIcon } =
    useNotesAppTreeNodeRuntimeContext();
  const {
    setSelectedFolderId,
    setSelectedNote,
    setIsEditing,
    setIsCreating,
    handleSelectNoteFromTree,
    operations,
  } = useNotesAppActions();

  const folderId = fromFolderMasterNodeId(node.id);
  const noteId = fromNoteMasterNodeId(node.id);
  const isFolder = Boolean(folderId);
  const canToggle = isFolder && hasChildren;
  const Icon = isFolder ? (isExpanded ? FolderOpenIcon : FolderClosedIcon) : FileIcon;
  const handleSelectNode = (event: React.MouseEvent<HTMLElement>): void => {
    select(event as React.MouseEvent<HTMLDivElement>);
    if (folderId) {
      setSelectedFolderId(folderId);
      setSelectedNote(null);
      setIsEditing(false);
    } else if (noteId) {
      void handleSelectNoteFromTree(noteId);
    }
  };

  return (
    <div
      className={cn(
        'group flex items-center gap-1 rounded px-2 py-1.5 text-sm transition-colors',
        isSelected ? 'bg-blue-600 text-white shadow-sm' : 'text-gray-300 hover:bg-muted/40'
      )}
      style={{ marginLeft: `${depth * 16}px` }}
    >
      <DragHandleIcon className='size-3 shrink-0 text-gray-500 opacity-0 transition-opacity group-hover:opacity-100' />
      {canToggle ? (
        <Button
          variant='ghost'
          size='sm'
          onClick={(event: React.MouseEvent<HTMLButtonElement>): void => {
            event.stopPropagation();
            toggleExpand();
          }}
          className='size-4 p-0 text-gray-500 hover:bg-white/10 hover:text-gray-300'
          aria-label={isExpanded ? `Collapse ${node.name}` : `Expand ${node.name}`}
          title={isExpanded ? `Collapse ${node.name}` : `Expand ${node.name}`}>
          {isExpanded ? <ChevronDown className='size-3' /> : <ChevronRight className='size-3' />}
        </Button>
      ) : (
        <span className='inline-flex size-4 items-center justify-center text-xs opacity-30'>•</span>
      )}
      {isRenaming ? (
        <Input
          ref={(node) => {
            node?.focus();
          }}
          value={controller.renameDraft}
          aria-label={`Rename ${node.name}`}
          onChange={(event: React.ChangeEvent<HTMLInputElement>): void => {
            controller.updateRenameDraft(event.target.value);
          }}
          onBlur={(): void => {
            void controller.commitRename();
          }}
          onKeyDown={(event: React.KeyboardEvent<HTMLInputElement>): void => {
            if (event.key === 'Enter') {
              event.preventDefault();
              void controller.commitRename();
            } else if (event.key === 'Escape') {
              event.preventDefault();
              controller.cancelRename();
            }
          }}
          onClick={(event: React.MouseEvent<HTMLInputElement>): void => event.stopPropagation()}
          className='h-7 min-w-0 flex-1 border-blue-500 bg-gray-800 px-1 py-0.5 text-sm text-white outline-none'
         title='Input field'/>
      ) : (
        <button
          type='button'
          onClick={handleSelectNode}
          aria-pressed={isSelected}
          aria-label={`Select ${node.name}`}
          className='flex min-w-0 flex-1 items-center gap-2 rounded-sm text-left focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-sky-400/70 focus-visible:ring-offset-2 focus-visible:ring-offset-slate-950'
        >
          <Icon className='size-3.5 shrink-0' />
          <span className='truncate'>{node.name}</span>
        </button>
      )}

      {!isRenaming && (
        <div className='ml-auto hidden items-center gap-1 group-hover:flex'>
          {folderId ? (
            <>
              <Tooltip
                content={
                  getDocumentationTooltip(DOCUMENTATION_MODULE_IDS.notesapp, 'notesapp_add_note') ??
                  'Add note'
                }
              >
                <Button
                  variant='ghost'
                  size='sm'
                  onClick={(event: React.MouseEvent<HTMLButtonElement>): void => {
                    event.stopPropagation();
                    setSelectedFolderId(folderId);
                    setSelectedNote(null);
                    setIsCreating(true);
                  }}
                  aria-label='Add note'
                  className='size-6 p-0 text-gray-400 hover:bg-white/10 hover:text-white'
                  title={'Add note'}>
                  <FilePlus className='size-3' />
                </Button>
              </Tooltip>
              <Tooltip
                content={
                  getDocumentationTooltip(
                    DOCUMENTATION_MODULE_IDS.notesapp,
                    'notesapp_add_subfolder'
                  ) ?? 'Add subfolder'
                }
              >
                <Button
                  variant='ghost'
                  size='sm'
                  onClick={(event: React.MouseEvent<HTMLButtonElement>): void => {
                    event.stopPropagation();
                    void (operations as NotesAppTreeNodeOperations).handleCreateFolder(folderId);
                  }}
                  aria-label='Add subfolder'
                  className='size-6 p-0 text-gray-400 hover:bg-white/10 hover:text-white'
                  title={'Add subfolder'}>
                  <FolderPlus className='size-3' />
                </Button>
              </Tooltip>
            </>
          ) : null}
          {noteId ? (
            <Tooltip
              content={
                getDocumentationTooltip(
                  DOCUMENTATION_MODULE_IDS.notesapp,
                  'notesapp_duplicate_note'
                ) ?? 'Duplicate note'
              }
            >
              <Button
                variant='ghost'
                size='sm'
                onClick={(event: React.MouseEvent<HTMLButtonElement>): void => {
                  event.stopPropagation();
                  void (operations as NotesAppTreeNodeOperations).handleDuplicateNote(noteId);
                }}
                aria-label='Duplicate note'
                className='size-6 p-0 text-gray-400 hover:bg-white/10 hover:text-white'
                title={'Duplicate note'}>
                <Copy className='size-3' />
              </Button>
            </Tooltip>
          ) : null}
          <Tooltip
            content={
              getDocumentationTooltip(DOCUMENTATION_MODULE_IDS.notesapp, 'notesapp_rename') ??
              'Rename'
            }
          >
            <Button
              variant='ghost'
              size='sm'
              onClick={(event: React.MouseEvent<HTMLButtonElement>): void => {
                event.stopPropagation();
                startRename();
              }}
              aria-label='Rename'
              className='size-6 p-0 text-gray-400 hover:bg-white/10 hover:text-white'
              title={'Rename'}>
              <Edit2 className='size-3' />
            </Button>
          </Tooltip>
          <Tooltip
            content={
              getDocumentationTooltip(DOCUMENTATION_MODULE_IDS.notesapp, 'notesapp_delete') ??
              'Delete'
            }
          >
            <Button
              variant='ghost'
              size='sm'
              onClick={(event: React.MouseEvent<HTMLButtonElement>): void => {
                event.stopPropagation();
                if (folderId) {
                  void (operations as NotesAppTreeNodeOperations).handleDeleteFolder(folderId);
                  return;
                }
                if (noteId) {
                  void (operations as NotesAppTreeNodeOperations).handleDeleteNoteFromTree(noteId);
                }
              }}
              aria-label='Delete'
              className='size-6 p-0 text-rose-400 hover:bg-red-500/20 hover:text-rose-300'
              title={'Delete'}>
              <Trash2 className='size-3' />
            </Button>
          </Tooltip>
        </div>
      )}
    </div>
  );
}

'use client';

import React, {
  useState,
  useMemo,
  useEffect,
  useRef,
  useCallback,
} from 'react';

import type { NoteWithRelations, TagRecord } from '@/shared/contracts/notes';
import { useUndo } from '@/shared/hooks/ui/use-undo';
import { useToast } from '@/shared/ui/primitives.public';
import { logClientCatch } from '@/shared/utils/observability/client-error-logger';

import { useNotesAppActions, useNotesAppState } from '../hooks/NotesAppContext';
import { useNoteSettingsState } from '../hooks/NoteSettingsContext';
import { useEditorMode } from '../hooks/useEditorMode';
import {
  useCreateNoteMutation,
  useUpdateNoteMutation,
  useCreateNoteFileMutation,
  useDeleteNoteFileMutation,
} from '../hooks/useNoteData';
import { useNoteFileAttachments } from '../hooks/useNoteFileAttachments';
import { useNoteFormDerivedState } from '../hooks/useNoteFormDerivedState';
import { useNoteFormFiles } from '../hooks/useNoteFormFiles';
import { useNoteMetadata } from '../hooks/useNoteMetadata';
import { useNoteTags } from '../hooks/useNoteTags';
import { NoteContentContext, type NoteContentData } from './note-form/NoteContentContext';
import { NoteEditorContext, type NoteEditorData } from './note-form/NoteEditorContext';
import { NoteFilesContext, type NoteFilesData } from './note-form/NoteFilesContext';
import { NoteFoldersContext, type NoteFoldersData } from './note-form/NoteFoldersContext';
import {
  NoteFormRuntimeContext,
  type NoteFormRuntimeData,
} from './note-form/NoteFormRuntimeContext';
import { NoteMetadataContext, type NoteMetadataData } from './note-form/NoteMetadataContext';
import {
  NoteRelationsContext,
  type NoteRelationsData,
} from './note-form/NoteRelationsContext';
import { NoteTagsContext, type NoteTagsData } from './note-form/NoteTagsContext';

export {
  useNoteFormRuntime,
  useNoteContentContext,
  useNoteMetadataContext,
  useNoteEditorContext,
  useNoteFilesContext,
  useNoteTagsContext,
  useNoteFoldersContext,
  useNoteRelationsContext,
} from './NoteFormContext.hooks';

export function NoteFormProvider({
  note = null,
  onSuccess,
  children,
}: {
  note?: NoteWithRelations | null;
  onSuccess: () => void;
  children: React.ReactNode;
}): React.JSX.Element {
  const {
    folderTree,
    tags: availableTags,
    selectedNotebookId,
    selectedFolderId: defaultFolderId,
    selectedFolderTheme,
    selectedNoteTheme,
  } = useNotesAppState();
  const { fetchTags, handleSelectNoteFromTree, handleFilterByTag, setIsCreating } =
    useNotesAppActions();

  const { settings } = useNoteSettingsState();
  const { toast } = useToast();

  const {
    state: content,
    setState: setContent,
    undo,
    redo,
    canUndo,
    canRedo,
    resetHistory,
  } = useUndo(note?.content || '');

  const {
    title,
    setTitle,
    color,
    setColor,
    isPinned,
    setIsPinned,
    isArchived,
    setIsArchived,
    isFavorite,
    setIsFavorite,
    getReadableTextColor,
  } = useNoteMetadata(note);

  const {
    editorMode,
    setEditorMode,
    isEditorModeLocked,
    isMigrating,
    handleMigrateToWysiwyg,
    handleMigrateToMarkdown,
  } = useEditorMode(note, settings.editorMode);

  const {
    noteFiles,
    setNoteFiles,
    uploadingSlots,
    addUploadingSlot,
    removeUploadingSlot,
    lightboxImage,
    openLightbox,
    closeLightbox,
    isPasting,
    setIsPasting,
    MAX_SLOTS,
    removeFile,
  } = useNoteFileAttachments(note?.files);

  const setLightboxImage = (imgSrc: string | null): void => {
    if (imgSrc) {
      openLightbox(imgSrc);
    } else {
      closeLightbox();
    }
  };

  const {
    selectedTagIds,
    tagInput,
    setTagInput,
    isTagDropdownOpen,
    setIsTagDropdownOpen,
    filteredTags,
    handleAddTag,
    handleCreateTag,
    handleRemoveTag,
  } = useNoteTags(
    note?.tags?.map((t: { tagId: string; tag: TagRecord }): string => t.tagId) || [],
    availableTags,
    selectedNotebookId,
    note?.notebookId,
    fetchTags
  );

  const [selectedFolderId, setSelectedFolderId] = useState<string>(
    note?.categories?.[0]?.categoryId || defaultFolderId || ''
  );
  const {
    flatFolders,
    selectedRelatedNotes,
    setSelectedRelatedNotes,
    relatedNoteQuery,
    setRelatedNoteQuery,
    isRelatedDropdownOpen,
    setIsRelatedDropdownOpen,
    relatedNoteResults,
    isRelatedLoading,
    handleSelectRelatedNote,
    effectiveTheme,
    contentBackground,
    contentTextColor,
    previewTypographyStyle,
  } = useNoteFormDerivedState({
    color,
    folderTree,
    getReadableTextColor,
    handleSelectNoteFromTree,
    note,
    selectedFolderTheme,
    selectedNoteTheme,
    selectedNotebookId,
    setIsCreating,
  });

  const [showPreview, setShowPreview] = useState(false);
  const [textColor, setTextColor] = useState('#ffffff');
  const [fontFamily, setFontFamily] = useState('inherit');

  const [editorWidth, setEditorWidth] = useState<number | null>(null);
  const [isDraggingSplitter, setIsDraggingSplitter] = useState(false);
  const editorSplitRef = useRef<HTMLDivElement | null>(null);
  const contentRef = useRef<HTMLTextAreaElement | null>(null);

  const createNoteMutation = useCreateNoteMutation();
  const updateNoteMutation = useUpdateNoteMutation();
  const createFileMutation = useCreateNoteFileMutation(note?.id);
  const deleteFileMutation = useDeleteNoteFileMutation(note?.id);
  const {
    getNextAvailableSlot,
    isImageFile,
    formatFileSize,
    handleFileUpload,
    handleFileDelete,
    handlePaste,
    handleMultiFileUpload,
    insertFileReference,
  } = useNoteFormFiles({
    addUploadingSlot,
    content,
    contentRef,
    createFile: createFileMutation.mutateAsync,
    deleteFile: deleteFileMutation.mutateAsync,
    maxSlots: MAX_SLOTS,
    noteFiles,
    noteId: note?.id,
    removeFile,
    removeUploadingSlot,
    setContent,
    setIsPasting,
    setNoteFiles,
    settingsAutoformatOnPaste: settings.autoformatOnPaste,
    toast,
  });

  const handleSubmit = useCallback(
    async (e: React.FormEvent): Promise<void> => {
      e.preventDefault();
      if (!title || !content) return;

      try {
        const baseData = {
          title,
          content,
          color: color.toLowerCase().trim(),
          isPinned,
          isArchived,
          isFavorite,
          tagIds: selectedTagIds,
          relatedNoteIds: selectedRelatedNotes.map((rel: { id: string }): string => rel.id),
          categoryIds: selectedFolderId ? [selectedFolderId] : [],
          notebookId: selectedNotebookId ?? note?.notebookId ?? null,
        };

        if (note) {
          await updateNoteMutation.mutateAsync({ id: note.id, ...baseData });
        } else {
          await createNoteMutation.mutateAsync({
            ...baseData,
            editorType: editorMode,
          });
        }

        toast(note ? 'Note updated successfully' : 'Note created successfully');
        onSuccess();
      } catch (error: unknown) {
        logClientCatch(error, {
          source: 'NoteForm',
          action: 'saveNote',
          noteId: note?.id,
        });
        const message = error instanceof Error ? error.message : 'Failed to save note';
        toast(message, { variant: 'error' });
      }
    },
    [
      title,
      content,
      note,
      editorMode,
      color,
      isPinned,
      isArchived,
      isFavorite,
      selectedTagIds,
      selectedRelatedNotes,
      selectedFolderId,
      selectedNotebookId,
      updateNoteMutation,
      createNoteMutation,
      toast,
      onSuccess,
    ]
  );

  useEffect((): void => {
    if (note?.id) {
      resetHistory(note.content);
    }
  }, [note?.id, note?.content, resetHistory]);

  const contentValue = useMemo<NoteContentData>(
    () => ({
      content,
      setContent,
      undo,
      redo,
      canUndo,
      canRedo,
    }),
    [content, setContent, undo, redo, canUndo, canRedo]
  );

  const metadataValue = useMemo<NoteMetadataData>(
    () => ({
      title,
      setTitle,
      color,
      setColor,
      isPinned,
      setIsPinned,
      isArchived,
      setIsArchived,
      isFavorite,
      setIsFavorite,
      getReadableTextColor,
    }),
    [title, setTitle, color, setColor, isPinned, isArchived, isFavorite, getReadableTextColor]
  );

  const editorValue = useMemo<NoteEditorData>(
    () => ({
      editorMode,
      setEditorMode,
      isEditorModeLocked,
      isMigrating,
      handleMigrateToWysiwyg,
      handleMigrateToMarkdown,
      showPreview,
      setShowPreview,
      textColor,
      setTextColor,
      fontFamily,
      setFontFamily,
      editorWidth,
      setEditorWidth,
      isDraggingSplitter,
      setIsDraggingSplitter,
      editorSplitRef,
      contentRef,
      effectiveTheme,
      contentBackground,
      contentTextColor,
      previewTypographyStyle,
    }),
    [
      editorMode,
      setEditorMode,
      isEditorModeLocked,
      isMigrating,
      handleMigrateToWysiwyg,
      handleMigrateToMarkdown,
      showPreview,
      setShowPreview,
      textColor,
      setTextColor,
      fontFamily,
      setFontFamily,
      editorWidth,
      setEditorWidth,
      isDraggingSplitter,
      effectiveTheme,
      contentBackground,
      contentTextColor,
      previewTypographyStyle,
    ]
  );

  const filesValue = useMemo<NoteFilesData>(
    () => ({
      noteFiles,
      uploadingSlots,
      addUploadingSlot,
      removeUploadingSlot,
      lightboxImage,
      setLightboxImage,
      isPasting,
      setIsPasting,
      MAX_SLOTS,
      handleFileUpload,
      handleMultiFileUpload,
      handleFileDelete,
      insertFileReference,
      getNextAvailableSlot,
      handlePaste,
      formatFileSize,
      isImageFile,
    }),
    [
      noteFiles,
      uploadingSlots,
      addUploadingSlot,
      removeUploadingSlot,
      lightboxImage,
      isPasting,
      MAX_SLOTS,
      handleFileUpload,
      handleMultiFileUpload,
      handleFileDelete,
      insertFileReference,
      getNextAvailableSlot,
      handlePaste,
      formatFileSize,
      isImageFile,
    ]
  );

  const tagsValue = useMemo<NoteTagsData>(
    () => ({
      selectedTagIds,
      tagInput,
      setTagInput,
      isTagDropdownOpen,
      setIsTagDropdownOpen,
      filteredTags,
      handleAddTag,
      handleCreateTag,
      handleRemoveTag,
      availableTags,
      handleFilterByTag,
    }),
    [
      selectedTagIds,
      tagInput,
      isTagDropdownOpen,
      filteredTags,
      handleAddTag,
      handleCreateTag,
      handleRemoveTag,
      availableTags,
      handleFilterByTag,
    ]
  );

  const foldersValue = useMemo<NoteFoldersData>(
    () => ({
      selectedFolderId,
      setSelectedFolderId,
      flatFolders,
    }),
    [selectedFolderId, setSelectedFolderId, flatFolders]
  );

  const relationsValue = useMemo<NoteRelationsData>(
    () => ({
      selectedRelatedNotes,
      setSelectedRelatedNotes,
      relatedNoteQuery,
      setRelatedNoteQuery,
      isRelatedDropdownOpen,
      setIsRelatedDropdownOpen,
      relatedNoteResults,
      isRelatedLoading,
      handleSelectRelatedNote,
    }),
    [
      selectedRelatedNotes,
      relatedNoteQuery,
      isRelatedDropdownOpen,
      relatedNoteResults,
      isRelatedLoading,
      handleSelectRelatedNote,
    ]
  );

  const runtimeValue = useMemo<NoteFormRuntimeData>(
    () => ({
      note,
      setIsCreating,
      handleSubmit,
    }),
    [note, setIsCreating, handleSubmit]
  );

  return (
    <NoteContentContext.Provider value={contentValue}>
      <NoteMetadataContext.Provider value={metadataValue}>
        <NoteEditorContext.Provider value={editorValue}>
          <NoteFilesContext.Provider value={filesValue}>
            <NoteTagsContext.Provider value={tagsValue}>
              <NoteFoldersContext.Provider value={foldersValue}>
                <NoteRelationsContext.Provider value={relationsValue}>
                  <NoteFormRuntimeContext.Provider value={runtimeValue}>
                    {children}
                  </NoteFormRuntimeContext.Provider>
                </NoteRelationsContext.Provider>
              </NoteFoldersContext.Provider>
            </NoteTagsContext.Provider>
          </NoteFilesContext.Provider>
        </NoteEditorContext.Provider>
      </NoteMetadataContext.Provider>
    </NoteContentContext.Provider>
  );
}

'use client';

import { useQueryClient } from '@tanstack/react-query';
import React, { createContext, useState, useCallback, useMemo, useEffect } from 'react';

import {
  useNoteSettingsActions,
  useNoteSettingsState,
} from '@/features/notesapp/hooks/NoteSettingsContext';
import {
  useNoteData,
  useUpdateNoteMutation,
  useDeleteNoteMutation,
  useUpdateCategoryMutation,
} from '@/features/notesapp/hooks/useNoteData';
import { useNoteFilters } from '@/features/notesapp/hooks/useNoteFilters';
import { useNoteOperations } from '@/features/notesapp/hooks/useNoteOperations';
import { useNoteTheme } from '@/features/notesapp/hooks/useNoteTheme';
import type { UndoAction } from '@/shared/contracts/notes';
import type {
  NoteWithRelations,
} from '@/shared/contracts/notes';
import { useToast } from '@/shared/ui/primitives.public';
import { ConfirmModal, PromptModal } from '@/shared/ui/templates/modals';
import { logClientCatch } from '@/shared/utils/observability/client-error-logger';

import { useNotesAppDerivedState } from './useNotesAppDerivedState';
import { useNotesAppDialogs } from './useNotesAppDialogs';
import { useNotesAppEntityHandlers } from './useNotesAppEntityHandlers';

import type { NotesAppActionsValue, NotesAppStateValue } from './NotesAppContext.types';

export const NotesAppStateContext = createContext<NotesAppStateValue | null>(null);
export const NotesAppActionsContext = createContext<NotesAppActionsValue | null>(null);

export function NotesAppProvider({ children }: { children: React.ReactNode }): React.JSX.Element {
  const { settings } = useNoteSettingsState();
  const { updateSettings } = useNoteSettingsActions();
  const { toast } = useToast();
  const queryClient = useQueryClient();

  // Mutations
  const updateNoteMutation = useUpdateNoteMutation();
  const deleteNoteMutation = useDeleteNoteMutation();
  const updateCategoryMutation = useUpdateCategoryMutation();

  // Local UI State
  const [selectedNote, setSelectedNote] = useState<NoteWithRelations | null>(null);
  const [isEditing, setIsEditing] = useState<boolean>(false);
  const [isCreating, setIsCreating] = useState<boolean>(false);
  const [draggedNoteId, setDraggedNoteId] = useState<string | null>(null);
  const [isFolderTreeCollapsed, setIsFolderTreeCollapsed] = useState<boolean>(false);
  const [undoStack, setUndoStack] = useState<UndoAction[]>([]);

  useEffect(() => {
    updateSettings({ selectedNoteId: selectedNote?.id ?? null });
  }, [selectedNote?.id, updateSettings]);
  const { confirmation, setConfirmation, confirmAction, prompt, setPrompt, promptAction } =
    useNotesAppDialogs();

  // Settings helpers

  const setSelectedFolderId = useCallback(
    (id: string | null): void => {
      updateSettings({ selectedFolderId: id });
    },
    [updateSettings]
  );

  const setSelectedNotebookId = useCallback(
    (id: string | null): void => {
      updateSettings({ selectedNotebookId: id });
    },
    [updateSettings]
  );

  // Hooks
  const filters = useNoteFilters({ settings, updateSettings });

  const {
    notes,
    setNotes,
    tags,
    themes,
    notebook,
    setNotebook,
    folderTree,
    loading,
    notesRef,
    folderTreeRef,
    fetchNotes,
    fetchFolderTree,
    fetchTags,
  } = useNoteData({
    selectedNotebookId: settings.selectedNotebookId ?? null,
    selectedFolderId: settings.selectedFolderId ?? null,
    searchQuery: filters.debouncedSearchQuery,
    searchScope: settings.searchScope,
    filterPinned: filters.filterPinned,
    filterArchived: filters.filterArchived,
    filterFavorite: filters.filterFavorite,
    filterTagIds: filters.filterTagIds,
    setSelectedNotebookId,
  });

  const operations = useNoteOperations({
    selectedNotebookId: settings.selectedNotebookId ?? null,
    notesRef,
    folderTreeRef,
    fetchNotes,
    fetchFolderTree,
    setUndoStack,
    toast,
    setSelectedFolderId,
    setSelectedNote,
    selectedNote,
    confirmAction,
    promptAction,
  });

  const themeLogic = useNoteTheme({
    themes,
    notebook,
    folderTree,
    selectedFolderId: settings.selectedFolderId ?? null,
    selectedNotebookId: settings.selectedNotebookId ?? null,
    selectedNote,
    fetchFolderTree,
    setNotebook,
  });

  const {
    sortedNotes,
    pagedNotes,
    totalPages,
    noteLayoutClassName,
    availableTagsInScope,
    undoHistory,
  } = useNotesAppDerivedState({
    filters,
    notes,
    settings,
    undoStack,
  });

  const {
    handleSelectNoteFromTree,
    handleCreateSuccess,
    handleFilterByTag,
    handleUpdateSuccess,
    handleToggleFavorite,
    handleUnlinkRelatedNote,
    handleDeleteNote,
    fetchTagsAction,
  } = useNotesAppEntityHandlers({
    confirmAction,
    deleteNote: deleteNoteMutation.mutateAsync,
    fetchFolderTree,
    fetchNotes,
    fetchTags,
    filters,
    queryClient,
    selectedNote,
    setNotes,
    setIsCreating,
    setIsEditing,
    setSelectedFolderId,
    setSelectedNote,
    toast,
    updateNote: updateNoteMutation.mutateAsync,
    updateSettings,
  });

  // Undo Logic
  const applyUndoAction = useCallback(
    async (action: UndoAction): Promise<void> => {
      if (action.type === 'moveNote') {
        await updateNoteMutation.mutateAsync({
          id: action.noteId,
          categoryIds: action.fromFolderId ? [action.fromFolderId] : [],
        });
        return;
      }
      if (action.type === 'moveFolder') {
        await updateCategoryMutation.mutateAsync({
          id: action.folderId,
          parentId: action.fromParentId ?? null,
        });
        return;
      }
      if (action.type === 'renameFolder') {
        await updateCategoryMutation.mutateAsync({
          id: action.folderId,
          name: action.fromName,
        });
        return;
      }
      if (action.type === 'renameNote') {
        await updateNoteMutation.mutateAsync({
          id: action.noteId,
          title: action.fromTitle,
        });
      }
    },
    [updateNoteMutation, updateCategoryMutation]
  );

  const handleUndoFolderTree = useCallback(
    async (count: number = 1): Promise<void> => {
      const actionsToUndo: UndoAction[] = undoStack.slice(0, count);
      if (actionsToUndo.length === 0) return;
      setUndoStack((prev: UndoAction[]): UndoAction[] => prev.slice(count));
      try {
        for (const action of actionsToUndo) {
          await applyUndoAction(action);
        }
      } catch (error: unknown) {
        logClientCatch(error, {
          source: 'NotesAppProvider',
          action: 'undoFolderTree',
          count,
        });
        toast('Failed to undo', { variant: 'error' });
      }
    },
    [undoStack, applyUndoAction, toast]
  );

  const handleUndoAtIndex = useCallback(
    (index: number): void => {
      const count: number = Math.max(1, index + 1);
      void handleUndoFolderTree(count);
    },
    [handleUndoFolderTree]
  );

  const stateValue: NotesAppStateValue = useMemo(
    () => ({
      settings,
      filters,
      folderTree,
      tags,
      themes,
      loading,
      selectedNote,
      selectedFolderId: settings.selectedFolderId ?? null,
      selectedNotebookId: settings.selectedNotebookId ?? null,
      isEditing,
      isCreating,
      isFolderTreeCollapsed,
      draggedNoteId,
      sortedNotes,
      pagedNotes,
      totalPages,
      noteLayoutClassName,
      availableTagsInScope,
      selectedFolderThemeId: themeLogic.selectedFolderThemeId,
      selectedFolderTheme: themeLogic.selectedFolderTheme,
      selectedNoteTheme: themeLogic.selectedNoteTheme,
      getThemeForNote: themeLogic.getThemeForNote,
      confirmation,
      prompt,
      undoStack,
      undoHistory,
    }),
    [
      settings,
      filters,
      folderTree,
      tags,
      themes,
      loading,
      selectedNote,
      isEditing,
      isCreating,
      isFolderTreeCollapsed,
      draggedNoteId,
      sortedNotes,
      pagedNotes,
      totalPages,
      noteLayoutClassName,
      availableTagsInScope,
      themeLogic.selectedFolderThemeId,
      themeLogic.selectedFolderTheme,
      themeLogic.selectedNoteTheme,
      themeLogic.getThemeForNote,
      confirmation,
      prompt,
      undoStack,
      undoHistory,
    ]
  );

  const actionsValue: NotesAppActionsValue = useMemo(
    () => ({
      updateSettings,
      setSelectedNote,
      setIsEditing,
      setIsCreating,
      setIsFolderTreeCollapsed,
      setDraggedNoteId,
      handleThemeChange: themeLogic.handleThemeChange,
      fetchTags: fetchTagsAction,
      setSelectedFolderId,
      handleSelectNoteFromTree,
      handleToggleFavorite,
      handleDeleteNote,
      handleUpdateSuccess,
      handleCreateSuccess,
      handleUnlinkRelatedNote,
      handleFilterByTag,
      setConfirmation,
      confirmAction,
      setPrompt,
      promptAction,

      operations,
      handleUndoFolderTree,
      handleUndoAtIndex,
      fetchFolderTree,
    }),
    [
      settings,
      updateSettings,
      filters,
      folderTree,
      tags,
      themes,
      loading,
      selectedNote,
      isEditing,
      isCreating,
      isFolderTreeCollapsed,
      draggedNoteId,
      sortedNotes,
      pagedNotes,
      totalPages,
      noteLayoutClassName,
      availableTagsInScope,
      themeLogic.handleThemeChange,
      fetchTagsAction,
      setSelectedFolderId,
      handleSelectNoteFromTree,
      handleToggleFavorite,
      handleDeleteNote,
      handleUpdateSuccess,
      handleCreateSuccess,
      handleUnlinkRelatedNote,
      handleFilterByTag,
      setConfirmation,
      confirmAction,
      setPrompt,
      promptAction,
      operations,
      handleUndoFolderTree,
      handleUndoAtIndex,
      fetchFolderTree,
    ]
  );

  return (
    <NotesAppStateContext.Provider value={stateValue}>
      <NotesAppActionsContext.Provider value={actionsValue}>
        {children}
        <ConfirmModal
          isOpen={Boolean(confirmation)}
          onClose={() => setConfirmation(null)}
          title={confirmation?.title ?? ''}
          message={confirmation?.message ?? ''}
          confirmText={confirmation?.confirmText ?? 'Confirm'}
          isDangerous={confirmation?.isDangerous ?? false}
          onConfirm={async () => {
            if (confirmation?.onConfirm) {
              await confirmation.onConfirm();
            }
            setConfirmation(null);
          }}
        />
        <PromptModal
          open={Boolean(prompt)}
          onClose={() => setPrompt(null)}
          title={prompt?.title ?? ''}
          message={prompt?.message ?? ''}
          label={prompt?.label ?? ''}
          defaultValue={prompt?.defaultValue ?? ''}
          placeholder={prompt?.placeholder ?? ''}
          required={prompt?.required ?? false}
          onConfirm={async (value) => {
            if (prompt?.onConfirm) {
              await prompt.onConfirm(value);
            }
            setPrompt(null);
          }}
        />
      </NotesAppActionsContext.Provider>
    </NotesAppStateContext.Provider>
  );
}
export { useNotesAppState, useNotesAppActions } from './useNotesAppContextHooks';

'use client';

import { useState, useEffect } from 'react';

import type { NoteEditorType } from '@/shared/contracts/notes';
import { ApiError } from '@/shared/lib/api-client';
import { useToast } from '@/shared/ui/primitives.public';
import { logClientCatch } from '@/shared/utils/observability/client-error-logger';

// Why: Editor mode (markdown/wysiwyg) has complex migration logic:
// - Existing notes lock to their type
// - New notes use preferences
// - Conversion requires async HTML/Markdown transformation
// - Migration involves API calls and content updates
// Extracting this prevents NoteForm bloat and makes migrations testable.
export function useEditorMode(
  note: {
    id?: string;
    editorType?: string;
    content?: string;
    [key: string]: unknown;
  } | null,
  settingsEditorMode: NoteEditorType
): {
  editorMode: NoteEditorType;
  setEditorMode: (mode: NoteEditorType) => void;
  isEditorModeLocked: boolean;
  isMigrating: boolean;
  handleMigrateToWysiwyg: (content: string, onSuccess?: () => void) => Promise<string | undefined>;
  handleMigrateToMarkdown: (content: string, onSuccess?: () => void) => Promise<string | undefined>;
} {
  const { toast } = useToast();
  const [editorMode, setEditorMode] = useState<NoteEditorType>(
    (note?.editorType as NoteEditorType) || settingsEditorMode
  );
  const [isMigrating, setIsMigrating] = useState(false);

  // Sync editor mode from note's editorType
  useEffect((): void => {
    if (note?.editorType) {
      setEditorMode(note.editorType as NoteEditorType);
    } else {
      setEditorMode(settingsEditorMode);
    }
  }, [note?.id, note?.editorType, settingsEditorMode]);

  const isEditorModeLocked = Boolean(note?.id);

  const handleEditorModeChange = (mode: NoteEditorType): void => {
    if (!note?.id) {
      setEditorMode(mode);
    }
  };

  const convertMarkdownToHtml = (markdown: string): string => {
    let html = markdown;
    html = html.replace(/^### (.+)$/gm, '<h3>$1</h3>');
    html = html.replace(/^## (.+)$/gm, '<h2>$1</h2>');
    html = html.replace(/^# (.+)$/gm, '<h1>$1</h1>');
    html = html.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
    html = html.replace(/\*(.+?)\*/g, '<em>$1</em>');
    html = html.replace(/`(.+?)`/g, '<code>$1</code>');
    html = html.replace(/^- (.+)$/gm, '<li>$1</li>');
    html = html.replace(/(<li>.*<\/li>\n?)+/g, '<ul>$&</ul>');
    html = html
      .split('\n\n')
      .map((p: string) => {
        if (!p.startsWith('<')) return `<p>${p}</p>`;
        return p;
      })
      .join('\n');
    return html;
  };

  const convertHtmlToMarkdown = async (html: string): Promise<string> => {
    const TurndownService = (await import('turndown')).default;
    const turndownService = new TurndownService({
      headingStyle: 'atx',
      codeBlockStyle: 'fenced',
    });
    return turndownService.turndown(html);
  };

  const handleMigrateToWysiwyg = async (
    content: string,
    onSuccess?: () => void
  ): Promise<string | undefined> => {
    if (!note?.id) return;

    setIsMigrating(true);
    try {
      const htmlContent = convertMarkdownToHtml(content);

      const res = await fetch(`/api/notes/${note.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          content: htmlContent,
          editorType: 'wysiwyg',
        }),
      });

      if (!res.ok) {
        throw new ApiError('Failed to migrate note', res.status);
      }

      setEditorMode('wysiwyg');
      toast('Note migrated to WYSIWYG format', { variant: 'success' });
      onSuccess?.();
      return htmlContent;
    } catch (error) {
      logClientCatch(error, {
        source: 'useEditorMode',
        action: 'migrateToWysiwyg',
        noteId: note.id,
      });
      toast('Failed to migrate note', { variant: 'error' });
      throw error;
    } finally {
      setIsMigrating(false);
    }
  };

  const handleMigrateToMarkdown = async (
    content: string,
    onSuccess?: () => void
  ): Promise<string | undefined> => {
    if (!note?.id) return;

    setIsMigrating(true);
    try {
      const markdownContent = await convertHtmlToMarkdown(content);

      const res = await fetch(`/api/notes/${note.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          content: markdownContent,
          editorType: 'markdown',
        }),
      });

      if (!res.ok) {
        throw new ApiError('Failed to migrate note', res.status);
      }

      setEditorMode('markdown');
      toast('Note migrated to Markdown format', { variant: 'success' });
      onSuccess?.();
      return markdownContent;
    } catch (error) {
      logClientCatch(error, {
        source: 'useEditorMode',
        action: 'migrateToMarkdown',
        noteId: note.id,
      });
      toast('Failed to migrate note', { variant: 'error' });
      throw error;
    } finally {
      setIsMigrating(false);
    }
  };

  return {
    editorMode,
    setEditorMode: handleEditorModeChange,
    isEditorModeLocked,
    isMigrating,
    handleMigrateToWysiwyg,
    handleMigrateToMarkdown,
  };
}

'use client';

import { useCallback } from 'react';

import type { MarkdownToolbarActionHandlers as UseMarkdownEditorReturn } from '@/shared/lib/document-editor/public';

export type UseMarkdownEditorProps = {
  content: string;
  setContent: (value: string) => void;
  contentRef: React.RefObject<HTMLTextAreaElement | null>;
};

export type { UseMarkdownEditorReturn };

export function useMarkdownEditor({
  content,
  setContent,
  contentRef,
}: UseMarkdownEditorProps): UseMarkdownEditorReturn {
  const applyWrap = useCallback(
    (prefix: string, suffix: string, placeholder: string): void => {
      const textarea = contentRef.current;
      if (!textarea) return;
      const start = textarea.selectionStart;
      const end = textarea.selectionEnd;
      const selected = content.slice(start, end) || placeholder;
      const nextValue = content.slice(0, start) + prefix + selected + suffix + content.slice(end);
      setContent(nextValue);
      requestAnimationFrame((): void => {
        const cursor = start + prefix.length + selected.length + suffix.length;
        textarea.focus();
        textarea.setSelectionRange(cursor, cursor);
      });
    },
    [content, setContent, contentRef]
  );

  const insertAtCursor = useCallback(
    (value: string): void => {
      const textarea = contentRef.current;
      if (!textarea) return;
      const start = textarea.selectionStart;
      const end = textarea.selectionEnd;
      const nextValue = content.slice(0, start) + value + content.slice(end);
      setContent(nextValue);
      requestAnimationFrame((): void => {
        const cursor = start + value.length;
        textarea.focus();
        textarea.setSelectionRange(cursor, cursor);
      });
    },
    [content, setContent, contentRef]
  );

  const applyLinePrefix = useCallback(
    (prefix: string): void => {
      const textarea = contentRef.current;
      if (!textarea) return;
      const start = textarea.selectionStart;
      const end = textarea.selectionEnd;
      const blockStart = content.lastIndexOf('\n', start - 1) + 1;
      const blockEndIndex = content.indexOf('\n', end);
      const blockEnd = blockEndIndex === -1 ? content.length : blockEndIndex;
      const block = content.slice(blockStart, blockEnd);
      const updated = block
        .split(/\r?\n/)
        .map((line: string): string => (line.trim().length ? `${prefix}${line}` : line))
        .join('\n');
      const nextValue = content.slice(0, blockStart) + updated + content.slice(blockEnd);
      setContent(nextValue);
      requestAnimationFrame((): void => {
        textarea.focus();
        textarea.setSelectionRange(blockStart, blockStart + updated.length);
      });
    },
    [content, setContent, contentRef]
  );

  const applySpanStyle = useCallback(
    (colorValue: string, fontValue: string): void => {
      const textarea = contentRef.current;
      if (!textarea) return;
      const start = textarea.selectionStart;
      const end = textarea.selectionEnd;
      const selected = content.slice(start, end);
      const styleParts: string[] = [];
      if (colorValue) {
        styleParts.push(`color: ${colorValue}`);
      }
      if (fontValue && fontValue !== 'inherit') {
        styleParts.push(`font-family: ${fontValue}`);
      }
      const styleAttribute = styleParts.length > 0 ? ` style=" ${styleParts.join('; ')}"` : '';
      const openingTag = `<span${styleAttribute}>`;
      const closingTag = '</span>';
      const wrapped = `${openingTag}${selected}${closingTag}`;
      const nextValue = content.slice(0, start) + wrapped + content.slice(end);
      setContent(nextValue);
      requestAnimationFrame((): void => {
        const cursor = selected.length > 0 ? start + wrapped.length : start + openingTag.length;
        textarea.focus();
        textarea.setSelectionRange(cursor, cursor);
      });
    },
    [content, setContent, contentRef]
  );

  const applyBulletList = useCallback(() => {
    const textarea = contentRef.current;
    if (!textarea) return;
    const start = textarea.selectionStart;
    const end = textarea.selectionEnd;

    if (start === end) {
      const insert = '- ';
      const nextValue = content.slice(0, start) + insert + content.slice(end);
      setContent(nextValue);
      requestAnimationFrame((): void => {
        const cursor = start + insert.length;
        textarea.focus();
        textarea.setSelectionRange(cursor, cursor);
      });
      return;
    }

    const blockStart = content.lastIndexOf('\n', start - 1) + 1;
    const blockEndIndex = content.indexOf('\n', end);
    const blockEnd = blockEndIndex === -1 ? content.length : blockEndIndex;
    const block = content.slice(blockStart, blockEnd);
    const updated = block
      .split(/\r?\n/)
      .map((line: string): string => (line.trim().startsWith('- ') ? line : `- ${line}`))
      .join('\n');
    const nextValue = content.slice(0, blockStart) + updated + content.slice(blockEnd);
    setContent(nextValue);
    requestAnimationFrame((): void => {
      textarea.focus();
      textarea.setSelectionRange(blockStart, blockStart + updated.length);
    });
  }, [content, setContent, contentRef]);

  const applyChecklist = useCallback(() => {
    const textarea = contentRef.current;
    if (!textarea) return;
    const start = textarea.selectionStart;
    const end = textarea.selectionEnd;
    const blockStart = content.lastIndexOf('\n', start - 1) + 1;
    const blockEndIndex = content.indexOf('\n', end);
    const blockEnd = blockEndIndex === -1 ? content.length : blockEndIndex;
    const block = content.slice(blockStart, blockEnd);
    const updated = block
      .split(/\r?\n/)
      .map((line: string): string => (line.trim().startsWith('- [') ? line : `- [ ] ${line}`))
      .join('\n');
    const nextValue = content.slice(0, blockStart) + updated + content.slice(blockEnd);
    setContent(nextValue);
    requestAnimationFrame((): void => {
      textarea.focus();
      textarea.setSelectionRange(blockStart, blockStart + updated.length);
    });
  }, [content, setContent, contentRef]);

  return {
    onApplyWrap: applyWrap,
    onApplyLinePrefix: applyLinePrefix,
    onInsertAtCursor: insertAtCursor,
    onApplyBulletList: applyBulletList,
    onApplyChecklist: applyChecklist,
    onApplySpanStyle: applySpanStyle,
  };
}

