    {
      relationsFrom?: string[];
      relationsTo?: string[];
    }
  >({
    mutationFn: (variables) => api.put<void>(`/api/notes/${noteId}/relations`, variables),
    mutationKey,
    meta: {
      source: 'notes.hooks.useUpdateNoteRelationsMutation',
      operation: 'update',
      resource: 'notes.relations',
      domain: 'notes',
      mutationKey,
      tags: ['notes', 'relations', 'update'],
      description: 'Updates notes relations.'},
    invalidate: (queryClient) => invalidateNoteDetail(queryClient, noteId),
  });
};

export const useCreateNoteFileMutation = (noteId?: string) => {
  const mutationKey = QUERY_KEYS.notes.detail(noteId ?? 'none');
  return createMutationV2<
    NoteFileRecord,
    {
      slotIndex: number;
      file: File;
      onProgress?: (loaded: number, total?: number) => void;
        }
        >({
          mutationFn: async ({
            slotIndex,
            file,
            onProgress,
          }: {
      slotIndex: number;
      file: File;
      onProgress?: (loaded: number, total?: number) => void;
    }): Promise<NoteFileRecord> => {
            if (!noteId) throw new ApiError('Note ID is required for file upload', 400);
            const formData = new FormData();
            formData.append('file', file);
            formData.append('slotIndex', slotIndex.toString());

            const { uploadWithProgress } = await import('@/shared/utils/upload-with-progress');
            const result = await uploadWithProgress<NoteFileRecord | { error?: string }>(
              `/api/notes/${noteId}/files`,
              {
                formData,
                onProgress,
              }
            );
            if (!result.ok) {
              const error = result.data as { error?: string };
              throw new ApiError(error.error || 'Failed to upload note file', 400);
            }
            return result.data as NoteFileRecord;
          },
          mutationKey,
          meta: {
            source: 'notes.hooks.useCreateNoteFileMutation',
            operation: 'upload',
            resource: 'notes.files',
            domain: 'notes',
            mutationKey,
            tags: ['notes', 'files', 'upload'],
            description: 'Uploads notes files.'},
          invalidate: async (queryClient) => {
            if (noteId) {
              await invalidateNoteDetail(queryClient, noteId);
            }
          },
        });
};

export const useDeleteNoteFileMutation = (noteId?: string) => {
  const mutationKey = QUERY_KEYS.notes.detail(noteId ?? 'none');
  return createDeleteMutationV2<DeleteResponse, number>({
    mutationFn: (slotIndex) => {
      if (!noteId) throw new ApiError('Note ID is required for file deletion', 400);
      return api.delete<DeleteResponse>(`/api/notes/${noteId}/files/${slotIndex}`);
    },
    mutationKey,
    meta: {
      source: 'notes.hooks.useDeleteNoteFileMutation',
      operation: 'delete',
      resource: 'notes.files',
      domain: 'notes',
      mutationKey,
      tags: ['notes', 'files', 'delete'],
      description: 'Deletes notes files.'},
    invalidate: async (queryClient) => {
      if (noteId) {
        await invalidateNoteDetail(queryClient, noteId);
      }
    },
  });
};

// --- Composite Hook ---

export interface UseNoteDataResult {
  notes: NoteWithRelations[];
  setNotes: (
    updater: NoteWithRelations[] | ((prev: NoteWithRelations[] | undefined) => NoteWithRelations[])
  ) => void;
  tags: TagRecord[];
  themes: ThemeRecord[];
  notebook: NotebookRecord | null;
  setNotebook: (
    updater:
      | NotebookRecord
      | null
      | ((prev: NotebookRecord | null | undefined) => NotebookRecord | null)
  ) => void;
  folderTree: CategoryWithChildren[];
  loading: boolean;
  notesRef: React.MutableRefObject<NoteWithRelations[]>;
  folderTreeRef: React.MutableRefObject<CategoryWithChildren[]>;
  fetchNotes: () => Promise<void>;
  fetchFolderTree: () => Promise<void>;
  fetchTags: () => Promise<void>;
}

export function useNoteData({
  selectedNotebookId,
  selectedFolderId,
  searchQuery,
  searchScope,
  filterPinned,
  filterArchived,
  filterFavorite,
  filterTagIds,
  setSelectedNotebookId,
}: UseNoteDataProps): UseNoteDataResult {
  const notesRef = useRef<NoteWithRelations[]>([]);
  const folderTreeRef = useRef<CategoryWithChildren[]>([]);
  const queryClient = useQueryClient();

  // Queries
  const filters = useMemo(
    () => ({
      search: searchQuery,
      searchScope,
      ...(filterPinned !== undefined && { isPinned: filterPinned }),
      ...(filterArchived !== undefined && { isArchived: filterArchived }),
      ...(filterFavorite !== undefined && { isFavorite: filterFavorite }),
      tagIds: filterTagIds,
      categoryIds: selectedFolderId ? [selectedFolderId] : [],
      notebookId: selectedNotebookId,
      truncateContent: true,
    }),
    [
      searchQuery,
      searchScope,
      filterPinned,
      filterArchived,
      filterFavorite,
      filterTagIds,
      selectedFolderId,
      selectedNotebookId,
    ]
  );

  const notesQuery = useNotes(filters);

  const notebooksQuery = useNoteTree();
  const tagsQuery = useNoteTags();
  const themesQuery = useNoteThemes();
  const categoriesQuery = useNoteCategories(selectedNotebookId);

  // Derived state
  const notes = useMemo(() => notesQuery.data || [], [notesQuery.data]);
  const notebooks = useMemo(() => notebooksQuery.data || [], [notebooksQuery.data]);
  const tags = tagsQuery.data || [];
  const themes = themesQuery.data || [];
  const categories = useMemo(() => categoriesQuery.data || [], [categoriesQuery.data]);

  const notebook = useMemo(
    () => notebooks.find((n: NotebookRecord) => n.id === selectedNotebookId) || null,
    [notebooks, selectedNotebookId]
  );

  // Sync refs for imperative access
  useEffect(() => {
    notesRef.current = notes;
  }, [notes]);

  // Build folder tree
  const folderTree = useMemo(() => {
    if (!categories.length) {
      return [];
    }

    const categoryMap = new Map<string, CategoryWithChildren>();

    // Initialize map
    categories.forEach((cat: CategoryRecord) => {
      if (selectedNotebookId && cat.notebookId !== selectedNotebookId) return;
      categoryMap.set(cat.id, {
        ...cat,
        children: [],
        notes: [],
        _count: { notes: 0 },
      });
    });

    const roots: CategoryWithChildren[] = [];

    // Build tree
    categoryMap.forEach((node: CategoryWithChildren) => {
      if (node.parentId && categoryMap.has(node.parentId)) {
        categoryMap.get(node.parentId)!.children.push(node);
      } else {
        roots.push(node);
      }
    });

    // Sort by sortIndex or name
    const sortNodes = (nodes: CategoryWithChildren[]): void => {
      nodes.sort((a: CategoryWithChildren, b: CategoryWithChildren) => {
        if (a.sortIndex !== null && b.sortIndex !== null) {
          return (a.sortIndex ?? 0) - (b.sortIndex ?? 0);
        }
        return a.name.localeCompare(b.name);
      });
      nodes.forEach((node: CategoryWithChildren) => sortNodes(node.children));
    };

    sortNodes(roots);
    return roots;
  }, [categories, selectedNotebookId]);

  // Update folderTreeRef in useEffect
  useEffect(() => {
    folderTreeRef.current = folderTree;
  }, [folderTree]);

  // Initial selection
  useEffect(() => {
    if (!selectedNotebookId && notebooks.length > 0) {
      setSelectedNotebookId(notebooks[0]!.id);
    }
  }, [selectedNotebookId, notebooks, setSelectedNotebookId]);

  const setNotes = useCallback(
    (
      updater:
        | NoteWithRelations[]
        | ((prev: NoteWithRelations[] | undefined) => NoteWithRelations[])
    ): void => {
      queryClient.setQueryData(noteKeys.list(filters), updater);
    },
    [queryClient, filters]
  );

  const setNotebook = useCallback(
    (
      updater:
        | NotebookRecord
        | null
        | ((prev: NotebookRecord | null | undefined) => NotebookRecord | null)
    ): void => {
      queryClient.setQueryData(noteKeys.detail(selectedNotebookId ?? ''), updater);
    },
    [queryClient, selectedNotebookId]
  );

  return {
    notes,
    setNotes,
    tags,
    themes,
    notebook,
    setNotebook,
    folderTree,
    loading: notesQuery.isLoading || notebooksQuery.isLoading,
    notesRef,
    folderTreeRef,
    fetchNotes: async (): Promise<void> => {
      void (await notesQuery.refetch());
    },
    fetchFolderTree: async (): Promise<void> => {
      void (await categoriesQuery.refetch());
    },
    fetchTags: async (): Promise<void> => {
      void (await tagsQuery.refetch());
    },
  };
}

'use client';

import { useState } from 'react';

import type { NoteFileRecord } from '@/shared/contracts/notes';

// Why: File attachment management has multiple interdependent states:
// - Upload slots track in-progress uploads
// - Multiple files can be attached with validation
// - Lightbox for preview management
// - Paste handling for direct image insertion
// Extracting prevents form component bloat and makes attachment logic testable.
export function useNoteFileAttachments(initialFiles: NoteFileRecord[] = []): {
  noteFiles: NoteFileRecord[];
  setNoteFiles: React.Dispatch<React.SetStateAction<NoteFileRecord[]>>;
  uploadingSlots: Set<number>;
  addUploadingSlot: (slotIndex: number) => void;
  removeUploadingSlot: (slotIndex: number) => void;
  isSlotUploading: (slotIndex: number) => boolean;
  lightboxImage: string | null;
  openLightbox: (imageUrl: string) => void;
  closeLightbox: () => void;
  isPasting: boolean;
  setIsPasting: (isPasting: boolean) => void;
  MAX_SLOTS: number;
  canAddMoreFiles: () => boolean;
  addFile: (file: NoteFileRecord) => boolean;
  removeFile: (fileId: string) => void;
  updateFile: (fileId: string, updates: Partial<NoteFileRecord>) => void;
} {
  const [noteFiles, setNoteFiles] = useState<NoteFileRecord[]>(initialFiles);
  const [uploadingSlots, setUploadingSlots] = useState<Set<number>>(new Set());
  const [lightboxImage, setLightboxImage] = useState<string | null>(null);
  const [isPasting, setIsPasting] = useState(false);

  const MAX_SLOTS = 10;

  const addUploadingSlot = (slotIndex: number): void => {
    setUploadingSlots((prev: Set<number>) => new Set([...prev, slotIndex]));
  };

  const removeUploadingSlot = (slotIndex: number): void => {
    setUploadingSlots((prev: Set<number>) => {
      const next = new Set(prev);
      next.delete(slotIndex);
      return next;
    });
  };

  const isSlotUploading = (slotIndex: number): boolean => uploadingSlots.has(slotIndex);

  const canAddMoreFiles = (): boolean => noteFiles.length < MAX_SLOTS;

  const addFile = (file: NoteFileRecord): boolean => {
    if (canAddMoreFiles()) {
      setNoteFiles((prev: NoteFileRecord[]) => [...prev, file]);
      return true;
    }
    return false;
  };

  const removeFile = (fileId: string): void => {
    setNoteFiles((prev: NoteFileRecord[]) => prev.filter((f: NoteFileRecord) => f.id !== fileId));
  };

  const updateFile = (fileId: string, updates: Partial<NoteFileRecord>): void => {
    setNoteFiles((prev: NoteFileRecord[]) =>
      prev.map((f: NoteFileRecord) => (f.id === fileId ? { ...f, ...updates } : f))
    );
  };

  const openLightbox = (imageUrl: string): void => {
    setLightboxImage(imageUrl);
  };

  const closeLightbox = (): void => {
    setLightboxImage(null);
  };

  return {
    noteFiles,
    setNoteFiles,
    uploadingSlots,
    addUploadingSlot,
    removeUploadingSlot,
    isSlotUploading,
    lightboxImage,
    openLightbox,
    closeLightbox,
    isPasting,
    setIsPasting,
    MAX_SLOTS,
    canAddMoreFiles,
    addFile,
    removeFile,
    updateFile,
  };
}

'use client';

import { useState, useEffect, useCallback } from 'react';

import type { UseNoteFiltersProps, UseNoteFiltersResult } from '@/shared/contracts/notes';
import type { NoteWithRelations } from '@/shared/contracts/notes';

export function useNoteFilters({
  settings,
  updateSettings: _updateSettings,
}: UseNoteFiltersProps): UseNoteFiltersResult {
  const [searchQuery, setSearchQuery] = useState('');
  const [debouncedSearchQuery, setDebouncedSearchQuery] = useState(searchQuery);
  const [filterPinned, setFilterPinned] = useState<boolean | undefined>(undefined);
  const [filterArchived, setFilterArchived] = useState<boolean | undefined>(undefined);
  const [filterFavorite, setFilterFavorite] = useState<boolean | undefined>(undefined);
  const [filterTagIds, setFilterTagIds] = useState<string[]>([]);
  const [highlightTagId, setHighlightTagId] = useState<string | null>(null);

  // Pagination
  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState(24);

  // Debounce search
  useEffect((): void | (() => void) => {
    const timer = setTimeout((): void => {
      if (searchQuery !== debouncedSearchQuery) {
        setDebouncedSearchQuery(searchQuery);
        setPage(1);
      }
    }, 250);
    return (): void => clearTimeout(timer);
  }, [searchQuery, debouncedSearchQuery]);

  // Reset page when settings change
  const [prevSettingsKey, setPrevSettingsKey] = useState('');
  const currentSettingsKey = `${settings.selectedFolderId ?? ''}-${settings.sortBy ?? ''}-${settings.sortOrder ?? ''}-${settings.selectedNotebookId ?? ''}`;

  if (currentSettingsKey !== prevSettingsKey) {
    setPrevSettingsKey(currentSettingsKey);
    setPage(1);
  }

  // Clear highlight tag
  useEffect((): void | (() => void) => {
    if (!highlightTagId) return;
    const timer = setTimeout((): void => {
      setHighlightTagId(null);
    }, 2000);
    return (): void => clearTimeout(timer);
  }, [highlightTagId]);

  const handleFilterByTag = useCallback(
    (
      tagId: string,
      setSelectedFolderId: (id: string | null) => void,
      setSelectedNote: (val: NoteWithRelations | null) => void,
      setIsEditing: (val: boolean) => void
    ): void => {
      setSelectedFolderId(null);
      setFilterTagIds([tagId]);
      setSearchQuery('');
      setSelectedNote(null);
      setIsEditing(false);
      setHighlightTagId(tagId);
      setPage(1);
    },
    []
  );

  const handleToggleFavoritesFilter = useCallback(
    (
      setSelectedFolderId: (id: string | null) => void,
      setSelectedNote: (val: NoteWithRelations | null) => void,
      setIsEditing: (val: boolean) => void
    ): void => {
      setFilterFavorite((prev: boolean | undefined) => (prev ? undefined : true));
      setSelectedFolderId(null);
      setSelectedNote(null);
      setIsEditing(false);
      setPage(1);
    },
    []
  );

  const setFilterPinnedWithPage = (v: boolean | undefined): void => {
    setFilterPinned(v);
    setPage(1);
  };

  const setFilterArchivedWithPage = (v: boolean | undefined): void => {
    setFilterArchived(v);
    setPage(1);
  };

  const setFilterFavoriteWithPage = (v: boolean | undefined): void => {
    setFilterFavorite(v);
    setPage(1);
  };

  const setFilterTagIdsWithPage = (ids: string[]): void => {
    setFilterTagIds(ids);
    setPage(1);
  };

  return {
    searchQuery,
    setSearchQuery,
    debouncedSearchQuery,
    filterPinned,
    setFilterPinned: setFilterPinnedWithPage,
    filterArchived,
    setFilterArchived: setFilterArchivedWithPage,
    filterFavorite,
    setFilterFavorite: setFilterFavoriteWithPage,
    filterTagIds,
    setFilterTagIds: setFilterTagIdsWithPage,
    highlightTagId,
    setHighlightTagId,
    page,
    setPage,
    pageSize,
    setPageSize,
    handleFilterByTag,
    handleToggleFavoritesFilter,
  };
}

'use client';

import { type UseQueryResult } from '@tanstack/react-query';
import { useState, useMemo, useEffect, useCallback } from 'react';

import type {
  CategoryWithChildren,
  NoteRelationRecord,
  NoteWithRelations,
  RelatedNote,
  ThemeRecord,
} from '@/shared/contracts/notes';
import { api } from '@/shared/lib/api-client';
import { createListQueryV2, createMultiQueryV2 } from '@/shared/lib/query-factories-v2';
import { normalizeQueryKey } from '@/shared/lib/query-key-utils';
import { QUERY_KEYS } from '@/shared/lib/query-keys';

import type { RelatedNoteItem } from '../context/note-form/NoteRelationsContext';

const FALLBACK_THEME = {
  id: 'fallback',
  name: 'Fallback Dark',
  createdAt: new Date(),
  updatedAt: new Date(),
  textColor: '#e5e7eb',
  backgroundColor: '#111827',
  markdownHeadingColor: '#ffffff',
  markdownLinkColor: '#60a5fa',
  markdownCodeBackground: '#1f2937',
  markdownCodeText: '#e5e7eb',
  relatedNoteBorderWidth: 1,
  relatedNoteBorderColor: '#374151',
  relatedNoteBackgroundColor: '#1f2937',
  relatedNoteTextColor: '#e5e7eb',
};

const flattenFolderTree = (
  folders: CategoryWithChildren[],
  level: number = 0
): Array<{ id: string; name: string; level: number }> => {
  const result: Array<{ id: string; name: string; level: number }> = [];
  for (const folder of folders) {
    result.push({ id: folder.id, name: folder.name, level });
    if (folder.children.length > 0) {
      result.push(...flattenFolderTree(folder.children, level + 1));
    }
  }
  return result;
};

export function useNoteFormDerivedState({
  color,
  folderTree,
  getReadableTextColor,
  handleSelectNoteFromTree,
  note,
  selectedFolderTheme,
  selectedNoteTheme,
  selectedNotebookId,
  setIsCreating,
}: {
  color: string;
  folderTree: CategoryWithChildren[];
  getReadableTextColor: (bgColor: string) => string;
  handleSelectNoteFromTree: (noteId: string) => Promise<void>;
  note: NoteWithRelations | null;
  selectedFolderTheme: ThemeRecord | null;
  selectedNoteTheme: ThemeRecord | null;
  selectedNotebookId: string | null;
  setIsCreating: (val: boolean) => void;
}) {
  const flatFolders = useMemo(
    () => flattenFolderTree(folderTree),
    [folderTree]
  );

  const initialCombinedRelations = useMemo((): RelatedNoteItem[] => {
    if (!note) return [];
    return [
      ...(note.relations ?? []).map((rel: RelatedNote) => ({
        id: rel.id,
        title: rel.title,
        color: rel.color ?? null,
        content: '',
      })),
      ...(note.relationsFrom ?? [])
        .map((rel: NoteRelationRecord & { targetNote?: RelatedNote }) =>
          rel.targetNote
            ? {
              id: rel.targetNote.id,
              title: rel.targetNote.title,
              color: rel.targetNote.color ?? null,
              content: '',
            }
            : null
        )
        .filter((item: RelatedNoteItem | null): item is RelatedNoteItem => Boolean(item)),
      ...(note.relationsTo ?? [])
        .map((rel: NoteRelationRecord & { sourceNote?: RelatedNote }) =>
          rel.sourceNote
            ? {
              id: rel.sourceNote.id,
              title: rel.sourceNote.title,
              color: rel.sourceNote.color ?? null,
              content: '',
            }
            : null
        )
        .filter((item: RelatedNoteItem | null): item is RelatedNoteItem => Boolean(item)),
    ].filter(
      (item: RelatedNoteItem, index: number, array: RelatedNoteItem[]) =>
        array.findIndex((entry: RelatedNoteItem) => entry.id === item.id) === index
    );
  }, [note]);

  const [selectedRelatedNotes, setSelectedRelatedNotes] =
    useState<RelatedNoteItem[]>(initialCombinedRelations);

  const relatedNotesQueries = createMultiQueryV2({
    queries: selectedRelatedNotes.map((rel: RelatedNoteItem) => {
      const queryKey = normalizeQueryKey(QUERY_KEYS.notes.detail(rel.id));
      return {
        queryKey,
        queryFn: () => api.get<NoteWithRelations>(`/api/notes/${rel.id}`),
        staleTime: 1000 * 60 * 5,
        meta: {
          source: 'notes.context.NoteFormContext.relatedNotes',
          operation: 'detail',
          resource: 'notes',
          description: 'Loads notes.',
          domain: 'global',
          queryKey,
          tags: ['notes', 'detail', 'related'],
        },
      };
    }),
  });

  useEffect(() => {
    const updated = selectedRelatedNotes.map((item: RelatedNoteItem, index: number) => {
      const query = relatedNotesQueries[index] as UseQueryResult<NoteWithRelations, Error>;
      if (query?.data) {
        return {
          ...item,
          content: query.data.content ?? '',
          title: query.data.title ?? item.title,
          color: query.data.color ?? item.color ?? null,
        };
      }
      return item;
    });
    if (JSON.stringify(updated) !== JSON.stringify(selectedRelatedNotes)) {
      setSelectedRelatedNotes(updated);
    }
  }, [relatedNotesQueries, selectedRelatedNotes]);

  const [relatedNoteQuery, setRelatedNoteQuery] = useState('');
  const [isRelatedDropdownOpen, setIsRelatedDropdownOpen] = useState(false);

  const relatedNoteSearchQuery = createListQueryV2<NoteWithRelations>({
    queryKey: QUERY_KEYS.notes.search(relatedNoteQuery),
    queryFn: async (): Promise<NoteWithRelations[]> => {
      if (!relatedNoteQuery) return [];
      const resolvedNotebookId = selectedNotebookId ?? note?.notebookId ?? null;
      return api.get<NoteWithRelations[]>('/api/notes', {
        params: {
          search: relatedNoteQuery,
          searchScope: 'title',
          ...(resolvedNotebookId ? { notebookId: resolvedNotebookId } : {}),
        },
      });
    },
    enabled: Boolean(relatedNoteQuery),
    meta: {
      source: 'notes.context.NoteFormContext.relatedNoteSearch',
      operation: 'list',
      resource: 'notes.search',
      domain: 'global',
      tags: ['notes', 'search', 'related'],
      description: 'Loads notes search.',
    },
  });

  const { data: relatedNoteResults = [], isFetching: isRelatedLoading } = relatedNoteSearchQuery;

  const handleSelectRelatedNote = useCallback(
    (noteId: string): void => {
      if (!note) {
        setIsCreating(false);
      }
      void handleSelectNoteFromTree(noteId);
    },
    [handleSelectNoteFromTree, note, setIsCreating]
  );

  const resolvedFolderTheme = note ? selectedNoteTheme : selectedFolderTheme;
  const effectiveTheme = (resolvedFolderTheme ?? FALLBACK_THEME) as ThemeRecord;
  const hasCustomColor: boolean = color !== '#ffffff';
  const contentBackground: string = hasCustomColor ? color : effectiveTheme.backgroundColor;
  const contentTextColor: string = hasCustomColor
    ? getReadableTextColor(contentBackground)
    : effectiveTheme.textColor;

  const previewTypographyStyle: React.CSSProperties = useMemo(
    (): React.CSSProperties => ({
      color: contentTextColor,
      ['--tw-prose-body' as never]: contentTextColor,
      ['--tw-prose-headings' as never]: effectiveTheme.markdownHeadingColor ?? contentTextColor,
      ['--tw-prose-lead' as never]: contentTextColor,
      ['--tw-prose-bold' as never]: contentTextColor,
      ['--tw-prose-counters' as never]: contentTextColor,
      ['--tw-prose-bullets' as never]: contentTextColor,
      ['--tw-prose-quotes' as never]: contentTextColor,
      ['--tw-prose-quote-borders' as never]: 'rgba(148, 163, 184, 0.35)',
      ['--tw-prose-hr' as never]: 'rgba(148, 163, 184, 0.35)',
      ['--note-link-color' as never]: effectiveTheme.markdownLinkColor,
      ['--note-code-bg' as never]: effectiveTheme.markdownCodeBackground,
      ['--note-code-text' as never]: effectiveTheme.markdownCodeText,
      ['--note-inline-code-bg' as never]: effectiveTheme.markdownCodeBackground,
    }),
    [contentTextColor, effectiveTheme]
  );

  return {
    flatFolders,
    selectedRelatedNotes,
    setSelectedRelatedNotes,
    relatedNoteQuery,
    setRelatedNoteQuery,
    isRelatedDropdownOpen,
    setIsRelatedDropdownOpen,
    relatedNoteResults,
    isRelatedLoading,
    handleSelectRelatedNote,
    effectiveTheme,
    contentBackground,
    contentTextColor,
    previewTypographyStyle,
  };
}

'use client';

import { useCallback } from 'react';

import type { NoteFileRecord } from '@/shared/contracts/notes';
import type { Toast } from '@/shared/contracts/ui/base';
import { logClientCatch } from '@/shared/utils/observability/client-error-logger';

import { autoformatMarkdown } from '../utils';

export function useNoteFormFiles({
  addUploadingSlot,
  content,
  contentRef,
  createFile,
  deleteFile,
  maxSlots,
  noteFiles,
  noteId,
  removeFile,
  removeUploadingSlot,
  setContent,
  setIsPasting,
  setNoteFiles,
  settingsAutoformatOnPaste,
  toast,
}: {
  addUploadingSlot: (slotIndex: number) => void;
  content: string;
  contentRef: React.RefObject<HTMLTextAreaElement | null>;
  createFile: (input: {
    slotIndex: number;
    file: File;
    onProgress?: (loaded: number, total?: number) => void;
  }) => Promise<NoteFileRecord>;
  deleteFile: (slotIndex: number) => Promise<unknown>;
  maxSlots: number;
  noteFiles: NoteFileRecord[];
  noteId: string | undefined;
  removeFile: (fileId: string) => void;
  removeUploadingSlot: (slotIndex: number) => void;
  setContent: (content: string) => void;
  setIsPasting: (isPasting: boolean) => void;
  setNoteFiles: React.Dispatch<React.SetStateAction<NoteFileRecord[]>>;
  settingsAutoformatOnPaste: boolean;
  toast: Toast;
}) {
  const getNextAvailableSlot = useCallback((): number | null => {
    const usedSlots: Set<number> = new Set(
      noteFiles.map((file: NoteFileRecord): number => file.slotIndex)
    );
    for (let index = 0; index < maxSlots; index += 1) {
      if (!usedSlots.has(index)) return index;
    }
    return null;
  }, [maxSlots, noteFiles]);

  const isImageFile = useCallback((mimetype: string): boolean => mimetype.startsWith('image/'), []);

  const formatFileSize = useCallback((bytes: number): string => {
    if (bytes < 1024) return `${bytes} B`;
    if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
    return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
  }, []);

  const handleFileUpload = useCallback(
    async (
      slotIndex: number,
      file: File,
      helpers?: { reportProgress: (loaded: number, total?: number) => void }
    ): Promise<void> => {
      if (!noteId) {
        toast('Please save the note first before uploading files');
        return;
      }

      if (file.size > 10 * 1024 * 1024) {
        toast('File size exceeds 10MB limit');
        return;
      }

      addUploadingSlot(slotIndex);

      try {
        const newFile = await createFile({
          slotIndex,
          file,
          onProgress: (loaded: number, total?: number) => helpers?.reportProgress(loaded, total),
        });
        setNoteFiles((previous: NoteFileRecord[]): NoteFileRecord[] =>
          [...previous.filter((item: NoteFileRecord): boolean => item.slotIndex !== slotIndex), newFile].sort(
            (left: NoteFileRecord, right: NoteFileRecord): number => left.slotIndex - right.slotIndex
          )
        );
        toast('File uploaded successfully');
      } catch (error: unknown) {
        logClientCatch(error, {
          source: 'NoteForm',
          action: 'uploadFile',
          noteId,
          slotIndex,
        });
        const message = error instanceof Error ? error.message : 'Failed to upload file';
        toast(message);
      } finally {
        removeUploadingSlot(slotIndex);
      }
    },
    [addUploadingSlot, createFile, noteId, removeUploadingSlot, setNoteFiles, toast]
  );

  const handleFileDelete = useCallback(
    async (slotIndex: number): Promise<void> => {
      if (!noteId) return;

      try {
        await deleteFile(slotIndex);
        removeFile(
          noteFiles.find((file: NoteFileRecord): boolean => file.slotIndex === slotIndex)?.id || ''
        );
        toast('File deleted successfully');
      } catch (error: unknown) {
        logClientCatch(error, {
          source: 'NoteForm',
          action: 'deleteFile',
          noteId,
          slotIndex,
        });
        toast('Failed to delete file');
      }
    },
    [deleteFile, noteFiles, noteId, removeFile, toast]
  );

  const handlePaste = useCallback(
    async (event: React.ClipboardEvent): Promise<void> => {
      const uploadPastedImage = async (file: File): Promise<void> => {
        if (!noteId) {
          toast('Please save the note first before pasting images');
          return;
        }

        const nextSlot: number | null = getNextAvailableSlot();
        if (nextSlot === null) {
          toast('All file slots are full. Delete a file to paste a new image.');
          return;
        }

        if (file.size > 10 * 1024 * 1024) {
          toast('Image size exceeds 10MB limit');
          return;
        }

        setIsPasting(true);
        addUploadingSlot(nextSlot);

        const textarea: HTMLTextAreaElement | null = contentRef.current;
        const cursorPosition: number = textarea?.selectionStart ?? content.length;

        try {
          const timestamp: number = Date.now();
          const extension: string = file.type.split('/')[1] || 'png';
          const renamedFile: File = new File([file], `pasted-image-${timestamp}.${extension}`, {
            type: file.type,
          });

          const newFile = await createFile({
            slotIndex: nextSlot,
            file: renamedFile,
          });

          setNoteFiles((previous: NoteFileRecord[]): NoteFileRecord[] =>
            [...previous.filter((item: NoteFileRecord): boolean => item.slotIndex !== nextSlot), newFile].sort(
              (left: NoteFileRecord, right: NoteFileRecord): number => left.slotIndex - right.slotIndex
            )
          );

          const altText: string = renamedFile.name;
          const reference: string = `![${altText}](${newFile.filepath})`;
          const nextValue: string =
            content.slice(0, cursorPosition) + reference + content.slice(cursorPosition);
          setContent(nextValue);

          toast('Image pasted and uploaded');
        } catch (error: unknown) {
          logClientCatch(error, {
            source: 'NoteForm',
            action: 'uploadPastedImage',
            noteId,
          });
          toast('Failed to upload pasted image');
        } finally {
          setIsPasting(false);
          removeUploadingSlot(nextSlot);
        }
      };

      const pastedText: string | undefined = event.clipboardData?.getData('text/plain');
      if (pastedText) {
        if (settingsAutoformatOnPaste) {
          event.preventDefault();
          const formattedText: string = autoformatMarkdown(pastedText);
          const textarea: HTMLTextAreaElement | null = contentRef.current;
          const selectionStart: number = textarea?.selectionStart ?? content.length;
          const selectionEnd: number = textarea?.selectionEnd ?? content.length;
          const newContent: string =
            content.slice(0, selectionStart) + formattedText + content.slice(selectionEnd);
          setContent(newContent);
          window.requestAnimationFrame((): void => {
            if (textarea) {
              const newPosition: number = selectionStart + formattedText.length;
              textarea.selectionStart = newPosition;
              textarea.selectionEnd = newPosition;
              textarea.focus();
            }
          });
        }
        return;
      }

      const items: DataTransferItemList | undefined = event.clipboardData?.items;
      if (!items) return;

      for (let index = 0; index < items.length; index += 1) {
        const item: DataTransferItem | null = items[index] ?? null;
        if (item?.type.startsWith('image/')) {
          event.preventDefault();
          const file: File | null = item.getAsFile();
          if (!file) return;
          await uploadPastedImage(file);
          return;
        }
      }

      const pastedFiles: FileList | undefined = event.clipboardData?.files;
      if (pastedFiles && pastedFiles.length > 0) {
        const file: File | null = pastedFiles[0] ?? null;
        if (file?.type.startsWith('image/')) {
          event.preventDefault();
          await uploadPastedImage(file);
        }
      }
    },
    [
      addUploadingSlot,
      content,
      contentRef,
      createFile,
      getNextAvailableSlot,
      noteId,
      removeUploadingSlot,
      setContent,
      setIsPasting,
      setNoteFiles,
      settingsAutoformatOnPaste,
      toast,
    ]
  );

  const handleMultiFileUpload = useCallback(
    async (
      files: FileList | File[],
      helpers?: { setProgress: (value: number) => void }
    ): Promise<void> => {
      const queue: File[] = Array.from(files);
      for (let index = 0; index < queue.length; index += 1) {
        const file = queue[index]!;
        const nextSlot: number | null = getNextAvailableSlot();
        if (nextSlot === null) {
          toast('All file slots are full. Delete a file to upload more.');
          return;
        }
        await handleFileUpload(nextSlot, file, {
          reportProgress: (loaded: number, total?: number) => {
            if (!helpers || !total) return;
            const pct = Math.min(100, Math.max(0, Math.round((loaded / total) * 100)));
            const combined = Math.round(((index + pct / 100) / queue.length) * 100);
            helpers.setProgress(combined);
          },
        });
      }
    },
    [getNextAvailableSlot, handleFileUpload, toast]
  );

  const insertFileReference = useCallback((file: NoteFileRecord): void => {
    window.dispatchEvent(new CustomEvent('note-insert-file', { detail: file }));
  }, []);

  return {
    getNextAvailableSlot,
    isImageFile,
    formatFileSize,
    handleFileUpload,
    handleFileDelete,
    handlePaste,
    handleMultiFileUpload,
    insertFileReference,
  };
}

'use client';

import { useState } from 'react';

// Why: Note metadata (title, color, status flags) has synchronized state:
// - Title syncs when note changes
// - Color requires normalization and contrast calculation
// - Pins/archives/favorites need reactive updates
// Extracting prevents prop drilling and makes metadata updates testable.
export function useNoteMetadata(
  note: {
    id?: string;
    title?: string;
    color?: string | null;
    isPinned?: boolean;
    isArchived?: boolean;
    isFavorite?: boolean;
    [key: string]: unknown;
  } | null
): {
  title: string;
  setTitle: (title: string) => void;
  color: string;
  setColor: (color: string) => void;
  isPinned: boolean;
  setIsPinned: (isPinned: boolean) => void;
  isArchived: boolean;
  setIsArchived: (isArchived: boolean) => void;
  isFavorite: boolean;
  setIsFavorite: (isFavorite: boolean) => void;
  getReadableTextColor: (hex: string) => string;
} {
  const [title, setTitle] = useState(note?.title || '');
  const [color, setColor] = useState(note?.color?.toLowerCase().trim() || '#ffffff');
  const [isPinned, setIsPinned] = useState(note?.isPinned || false);
  const [isArchived, setIsArchived] = useState(note?.isArchived || false);
  const [isFavorite, setIsFavorite] = useState(note?.isFavorite || false);

  const [prevNoteId, setPrevNoteId] = useState(note?.id);

  // Sync when note changes - adjusting state during render
  if (note?.id !== prevNoteId) {
    setPrevNoteId(note?.id);
    setTitle(note?.title || '');
    setColor(note?.color?.toLowerCase().trim() || '#ffffff');
    setIsPinned(note?.isPinned || false);
    setIsArchived(note?.isArchived || false);
    setIsFavorite(note?.isFavorite || false);
  }

  const getReadableTextColor = (hex: string): string => {
    const normalized = hex.replace('#', '');
    if (normalized.length !== 6) return '#f8fafc';
    const num = parseInt(normalized, 16);
    const r = (num >> 16) & 0xff;
    const g = (num >> 8) & 0xff;
    const b = num & 0xff;
    const luminance = (0.2126 * r + 0.7152 * g + 0.0722 * b) / 255;
    return luminance > 0.7 ? '#0f172a' : '#f8fafc';
  };

  return {
    title,
    setTitle,
    color,
    setColor,
    isPinned,
    setIsPinned,
    isArchived,
    setIsArchived,
    isFavorite,
    setIsFavorite,
    getReadableTextColor,
  };
}

'use client';

import { useQueryClient } from '@tanstack/react-query';
import { useCallback } from 'react';

import type { UseNoteOperationsProps } from '@/shared/contracts/notes';
import type { UndoAction } from '@/shared/contracts/notes';
import type {
  NoteWithRelations,
  CategoryWithChildren,
  NoteRelationWithTarget,
} from '@/shared/contracts/notes';
import { ApiError } from '@/shared/lib/api-client';
import { fetchQueryV2 } from '@/shared/lib/query-factories-v2';
import { QUERY_KEYS } from '@/shared/lib/query-keys';
import { logClientCatch } from '@/shared/utils/observability/client-error-logger';
import { findTreeNodeById, findTreeNodeParentId } from '@/shared/utils/tree-operations';

import {
  useCreateCategoryMutation,
  useDeleteCategoryMutation,
  useUpdateCategoryMutation,
  useCreateNoteMutation,
  useDeleteNoteMutation,
  useUpdateNoteMutation,
} from './useNoteData';

const NOTES_STALE_MS = 10_000;

export function useNoteOperations({
  selectedNotebookId,
  notesRef,
  folderTreeRef,
  setUndoStack,
  toast,
  setSelectedFolderId,
  setSelectedNote,
  selectedNote,
  confirmAction,
  promptAction,
}: UseNoteOperationsProps): {
  handleCreateFolder: (parentId?: string | null) => Promise<void>;
  handleDeleteFolder: (folderId: string) => Promise<void>;
  handleRenameFolder: (folderId: string, newName: string) => Promise<void>;
  handleDuplicateNote: (noteId: string) => Promise<void>;
  handleDeleteNoteFromTree: (noteId: string) => Promise<void>;
  handleRenameNote: (noteId: string, newTitle: string) => Promise<void>;
  handleMoveNoteToFolder: (noteId: string, folderId: string | null) => Promise<void>;
  handleMoveFolderToFolder: (folderId: string, targetParentId: string | null) => Promise<void>;
  handleReorderFolder: (
    folderId: string,
    targetId: string,
    position: 'before' | 'after'
  ) => Promise<void>;
  handleRelateNotes: (sourceNoteId: string, targetNoteId: string) => Promise<void>;
} {
  const queryClient = useQueryClient();
  const createCategoryMutation = useCreateCategoryMutation();
  const deleteCategoryMutation = useDeleteCategoryMutation();
  const updateCategoryMutation = useUpdateCategoryMutation();
  const createNoteMutation = useCreateNoteMutation();
  const deleteNoteMutation = useDeleteNoteMutation();
  const updateNoteMutation = useUpdateNoteMutation();

  const handleCreateFolder = useCallback(
    async (parentId?: string | null): Promise<void> => {
      promptAction({
        title: 'New Folder',
        label: 'Folder Name',
        placeholder: 'e.g. Work, Ideas, etc.',
        required: true,
        onConfirm: async (folderName) => {
          try {
            if (!selectedNotebookId) return;
            const created = await createCategoryMutation.mutateAsync({
              name: folderName,
              parentId: parentId ?? null,
              notebookId: selectedNotebookId,
              themeId: null,
              color: null,
              sortIndex: null,
            });

            if (created?.id) {
              setSelectedFolderId(created.id);
            }
            toast('Folder created successfully');
          } catch (error: unknown) {
            logClientCatch(error, { source: 'useNoteOperations.handleCreateFolder' });
            toast('Failed to create folder', { variant: 'error' });
          }
        },
      });
    },
    [selectedNotebookId, createCategoryMutation, setSelectedFolderId, toast, promptAction]
  );

  const handleDeleteFolder = useCallback(
    async (folderId: string): Promise<void> => {
      confirmAction({
        title: 'Delete Folder?',
        message:
          'Delete this folder and all its contents (subfolders, notes, and attachments)? This action cannot be undone.',
        confirmText: 'Delete Folder',
        isDangerous: true,
        onConfirm: async () => {
          try {
            await deleteCategoryMutation.mutateAsync(folderId);
            toast('Folder deleted successfully');
          } catch (error: unknown) {
            logClientCatch(error, {
              source: 'useNoteOperations.handleDeleteFolder',
              folderId,
            });
            toast('Failed to delete folder', { variant: 'error' });
          }
        },
      });
    },
    [deleteCategoryMutation, toast, confirmAction]
  );

  const handleRenameFolder = useCallback(
    async (folderId: string, newName: string): Promise<void> => {
      const currentFolder = findTreeNodeById<CategoryWithChildren>(
        folderTreeRef.current || [],
        folderId
      );
      const previousName = (currentFolder?.name as string) ?? '';
      try {
        await updateCategoryMutation.mutateAsync({
          id: folderId,
          name: newName,
        });

        if (previousName && previousName !== newName) {
          setUndoStack((prev: UndoAction[]) => [
            {
              type: 'renameFolder',
              folderId,
              fromName: previousName,
              toName: newName,
            },
            ...prev,
          ]);
        }
        toast('Folder renamed successfully');
      } catch (error: unknown) {
        logClientCatch(error, {
          source: 'useNoteOperations.handleRenameFolder',
          folderId,
          newName,
        });
        toast('Failed to rename folder', { variant: 'error' });
      }
    },
    [folderTreeRef, updateCategoryMutation, setUndoStack, toast]
  );

  const handleDuplicateNote = useCallback(
    async (noteId: string): Promise<void> => {
      try {
        const note = await fetchQueryV2<NoteWithRelations>(queryClient, {
          queryKey: QUERY_KEYS.notes.detail(noteId),
          queryFn: async (): Promise<NoteWithRelations> => {
            const response = await fetch(`/api/notes/${noteId}`);
            if (!response.ok) throw new ApiError('Failed to fetch note', response.status);
            return response.json() as Promise<NoteWithRelations>;
          },
          staleTime: NOTES_STALE_MS,
          meta: {
            source: 'notes.hooks.useNoteOperations.handleDuplicateNote',
            operation: 'detail',
            resource: 'notes.detail',
            domain: 'notes',
            queryKey: QUERY_KEYS.notes.detail(noteId),
            tags: ['notes', 'detail', 'fetch'],
            description: 'Loads notes detail.'},
        })();

        const baseTitle = note.title.replace(/\s*\(\d+\)$/, '');
        let newTitle = `${baseTitle} (1)`;

        const existingNotes = (notesRef.current || []).filter(
          (n: NoteWithRelations) => n.title.startsWith(baseTitle) && n.title !== note.title
        );
        if (existingNotes.length > 0) {
          const numbers = existingNotes
            .map((n: NoteWithRelations) => {
              const match = n.title.match(/\((\d+)\)$/);
              return match?.[1] ? parseInt(match[1], 10) : 0;
            })
            .filter((n: number) => n > 0);
          const maxNumber = Math.max(0, ...numbers);
          newTitle = `${baseTitle} (${maxNumber + 1})`;
        }

        const normalizedEditorType: 'markdown' | 'wysiwyg' | 'code' =
          note.editorType === 'wysiwyg' || note.editorType === 'code'
            ? note.editorType
            : 'markdown';

        await createNoteMutation.mutateAsync({
          title: newTitle,
          content: note.content,
          editorType: normalizedEditorType,
          color: note.color,
          isPinned: note.isPinned,
          isArchived: note.isArchived,
          isFavorite: note.isFavorite,
          tagIds: note.tags?.map((t: { tagId: string }) => t.tagId) || [],
          categoryIds: note.categories?.map((c: { categoryId: string }) => c.categoryId) || [],
          relatedNoteIds: (note.relations ?? []).map((related: { id: string }) => related.id),
          notebookId: note.notebookId ?? selectedNotebookId ?? null,
        });

        toast('Note duplicated successfully');
      } catch (error: unknown) {
        logClientCatch(error, {
          source: 'useNoteOperations.handleDuplicateNote',
          noteId,
        });
        toast('Failed to duplicate note', { variant: 'error' });
      }
    },
    [selectedNotebookId, notesRef, createNoteMutation, toast, queryClient]
  );

  const handleDeleteNoteFromTree = useCallback(
    async (noteId: string): Promise<void> => {
      confirmAction({
        title: 'Delete Note?',
        message: 'Are you sure you want to delete this note?',
        confirmText: 'Delete',
        isDangerous: true,
        onConfirm: async () => {
          try {
            await deleteNoteMutation.mutateAsync(noteId);
            if (selectedNote?.id === noteId) {
              setSelectedNote(null);
            }
            toast('Note deleted successfully');
          } catch (error: unknown) {
            logClientCatch(error, {
              source: 'useNoteOperations.handleDeleteNoteFromTree',
              noteId,
            });
            toast('Failed to delete note', { variant: 'error' });
          }
        },
      });
    },
    [deleteNoteMutation, selectedNote, setSelectedNote, toast, confirmAction]
  );

  const handleRenameNote = useCallback(
    async (noteId: string, newTitle: string): Promise<void> => {
      const currentNote = (notesRef.current || []).find(
        (note: NoteWithRelations) => note.id === noteId
      );
      const previousTitle = currentNote?.title ?? '';
      try {
        const updatedNote = await updateNoteMutation.mutateAsync({
          id: noteId,
          title: newTitle,
        });

        if (previousTitle && previousTitle !== newTitle) {
          setUndoStack((prev: UndoAction[]) => [
            {
              type: 'renameNote',
              noteId,
              fromTitle: previousTitle,
              toTitle: newTitle,
            },
            ...prev,
          ]);
        }

        if (selectedNote?.id === noteId) {
          setSelectedNote(updatedNote);
        }
        toast('Note renamed successfully');
      } catch (error: unknown) {
        logClientCatch(error, {
          source: 'useNoteOperations.handleRenameNote',
          noteId,
          newTitle,
        });
        toast('Failed to rename note', { variant: 'error' });
      }
    },
    [notesRef, updateNoteMutation, setUndoStack, selectedNote, setSelectedNote, toast]
  );

  const handleMoveNoteToFolder = useCallback(
    async (noteId: string, folderId: string | null): Promise<void> => {
      const currentNote = (notesRef.current || []).find(
        (note: NoteWithRelations) => note.id === noteId
      );
      const previousFolderId = currentNote?.categories?.[0]?.categoryId ?? null;
      try {
        await updateNoteMutation.mutateAsync({
          id: noteId,
          categoryIds: folderId ? [folderId] : [],
        });

        if (previousFolderId !== folderId) {
          setUndoStack((prev: UndoAction[]) => [
            {
              type: 'moveNote',
              noteId,
              fromFolderId: previousFolderId,
              toFolderId: folderId,
            },
            ...prev,
          ]);
        }
        toast('Note moved successfully');
      } catch (error: unknown) {
        logClientCatch(error, {
          source: 'useNoteOperations.handleMoveNoteToFolder',
          noteId,
          folderId,
        });
        toast('Failed to move note', { variant: 'error' });
      }
    },
    [notesRef, updateNoteMutation, setUndoStack, toast]
  );

  const handleMoveFolderToFolder = useCallback(
    async (folderId: string, targetParentId: string | null): Promise<void> => {
      const previousParentId = findTreeNodeParentId<CategoryWithChildren>(
        folderTreeRef.current || [],
        folderId
      );
      try {
        await updateCategoryMutation.mutateAsync({
          id: folderId,
          parentId: targetParentId,
        });

        if (previousParentId !== targetParentId) {
          setUndoStack((prev: UndoAction[]) => [
            {
              type: 'moveFolder',
              folderId,
              fromParentId: previousParentId,
              toParentId: targetParentId,
            },
            ...prev,
          ]);
        }
        toast('Folder moved successfully');
      } catch (error: unknown) {
        logClientCatch(error, {
          source: 'useNoteOperations.handleMoveFolderToFolder',
          folderId,
          targetParentId,
        });
        toast('Failed to move folder', { variant: 'error' });
      }
    },
    [folderTreeRef, updateCategoryMutation, setUndoStack, toast]
  );

  const handleReorderFolder = useCallback(
    async (folderId: string, targetId: string, position: 'before' | 'after'): Promise<void> => {
      const tree = folderTreeRef.current || [];
      const draggedFolder = findTreeNodeById<CategoryWithChildren>(tree, folderId);
      if (!draggedFolder) return;

      const targetParentId = findTreeNodeParentId<CategoryWithChildren>(tree, targetId);
      const draggedParentId = findTreeNodeParentId<CategoryWithChildren>(tree, folderId);

      const getSiblings = (parentId: string | null): CategoryWithChildren[] => {
        if (!parentId) return tree;
        const parent = findTreeNodeById<CategoryWithChildren>(tree, parentId);
        return parent?.children ?? [];
      };

      const siblings = getSiblings(targetParentId);
      const filtered = siblings.filter((sibling: CategoryWithChildren) => sibling.id !== folderId);
      const targetIndex = filtered.findIndex(
        (sibling: CategoryWithChildren) => sibling.id === targetId
      );
      if (targetIndex === -1) return;

      const insertIndex = position === 'before' ? targetIndex : targetIndex + 1;
      filtered.splice(insertIndex, 0, draggedFolder);

      try {
        await Promise.all(
          filtered.map((sibling: CategoryWithChildren, index: number) => {
            const update: Record<string, unknown> = { sortIndex: index };
            if (sibling.id === folderId && draggedParentId !== targetParentId) {
              update['parentId'] = targetParentId;
            }
            // Using mutation for each update
            return updateCategoryMutation.mutateAsync({
              id: sibling.id,
              sortIndex: index,
              ...(sibling.id === folderId && draggedParentId !== targetParentId
                ? { parentId: targetParentId }
                : {}),
            });
          })
        );
        toast('Folder reordered successfully');
      } catch (error: unknown) {
        logClientCatch(error, {
          source: 'useNoteOperations.handleReorderFolder',
          folderId,
          targetId,
          position,
        });
        toast('Failed to reorder folder', { variant: 'error' });
      }
    },
    [folderTreeRef, updateCategoryMutation, toast]
  );

  const handleRelateNotes = useCallback(
    async (sourceNoteId: string, targetNoteId: string): Promise<void> => {
      if (!sourceNoteId || !targetNoteId) return;
      if (sourceNoteId === targetNoteId) return;
      try {
        const [sourceNote, targetNote] = await Promise.all([
          fetchQueryV2<NoteWithRelations>(queryClient, {
            queryKey: QUERY_KEYS.notes.detail(sourceNoteId),
            queryFn: async (): Promise<NoteWithRelations> => {
              const res = await fetch(`/api/notes/${sourceNoteId}`);
              if (!res.ok) throw new ApiError('Failed to fetch source note', 400);
              return res.json() as Promise<NoteWithRelations>;
            },
            staleTime: NOTES_STALE_MS,
            meta: {
              source: 'notes.hooks.useNoteOperations.handleRelateNotes.source',
              operation: 'detail',
              resource: 'notes.detail',
              domain: 'notes',
              queryKey: QUERY_KEYS.notes.detail(sourceNoteId),
              tags: ['notes', 'detail', 'fetch'],
              description: 'Loads notes detail.'},
          })(),
          fetchQueryV2<NoteWithRelations>(queryClient, {
            queryKey: QUERY_KEYS.notes.detail(targetNoteId),
            queryFn: async (): Promise<NoteWithRelations> => {
              const res = await fetch(`/api/notes/${targetNoteId}`);
              if (!res.ok) throw new ApiError('Failed to fetch target note', 400);
              return res.json() as Promise<NoteWithRelations>;
            },
            staleTime: NOTES_STALE_MS,
            meta: {
              source: 'notes.hooks.useNoteOperations.handleRelateNotes.target',
              operation: 'detail',
              resource: 'notes.detail',
              domain: 'notes',
              queryKey: QUERY_KEYS.notes.detail(targetNoteId),
              tags: ['notes', 'detail', 'fetch'],
              description: 'Loads notes detail.'},
          })(),
        ]);

        const sourceRelatedIds =
          sourceNote.relationsFrom
            ?.map((rel: NoteRelationWithTarget) => rel.targetNote?.id)
            .filter((rid: string | undefined): rid is string => Boolean(rid)) || [];
        const alreadyLinked = sourceRelatedIds.includes(targetNoteId);
        if (alreadyLinked) {
          toast('Notes are already linked', { variant: 'info' });
          return;
        }

        const nextSourceIds = Array.from(new Set([...sourceRelatedIds, targetNoteId]));

        const targetRelatedIds =
          targetNote.relationsFrom
            ?.map((rel: NoteRelationWithTarget) => rel.targetNote?.id)
            .filter((rid: string | undefined): rid is string => Boolean(rid)) || [];
        const nextTargetIds = Array.from(new Set([...targetRelatedIds, sourceNoteId]));

        await Promise.all([
          updateNoteMutation.mutateAsync({
            id: sourceNoteId,
            relatedNoteIds: nextSourceIds,
          }),
          updateNoteMutation.mutateAsync({
            id: targetNoteId,
            relatedNoteIds: nextTargetIds,
          }),
        ]);

        toast('Notes linked');
      } catch (error: unknown) {
        logClientCatch(error, {
          source: 'useNoteOperations.handleRelateNotes',
          sourceNoteId,
          targetNoteId,
        });
        toast('Failed to link notes', { variant: 'error' });
      }
    },
    [updateNoteMutation, toast, queryClient]
  );

  return {
    handleCreateFolder,
    handleDeleteFolder,
    handleRenameFolder,
    handleDuplicateNote,
    handleDeleteNoteFromTree,
    handleRenameNote,
    handleMoveNoteToFolder,
    handleMoveFolderToFolder,
    handleReorderFolder,
    handleRelateNotes,
  };
}

'use client';

import { useState, useMemo } from 'react';

import { useCreateNoteTag } from '@/features/notesapp/api/useNoteMutations';
import type { TagRecord } from '@/shared/contracts/notes';
import { useToast } from '@/shared/ui/primitives.public';
import { logClientCatch } from '@/shared/utils/observability/client-error-logger';

// Why: Tag selection has complex state:
// - Input filtering against available tags
// - Dropdown visibility
// - Creating new tags with API call
// - Adding/removing tags from note
// Extracting prevents form bloat and makes tag logic testable.
export function useNoteTags(
  initialTagIds: string[] = [],
  availableTags: TagRecord[] = [],
  notebookId?: string | null,
  noteNotebookId?: string | null,
  onTagCreated?: () => void
): {
  selectedTagIds: string[];
  setSelectedTagIds: (ids: string[]) => void;
  tagInput: string;
  setTagInput: (input: string) => void;
  isTagDropdownOpen: boolean;
  setIsTagDropdownOpen: (isOpen: boolean) => void;
  filteredTags: TagRecord[];
  handleAddTag: (tag: TagRecord) => void;
  handleCreateTag: () => Promise<void>;
  handleRemoveTag: (tagId: string) => void;
} {
  const { toast } = useToast();
  const createTagMutation = useCreateNoteTag();
  const [selectedTagIds, setSelectedTagIds] = useState<string[]>(initialTagIds);
  const [tagInput, setTagInput] = useState('');
  const [isTagDropdownOpen, setIsTagDropdownOpen] = useState(false);

  const filteredTags = useMemo(
    (): TagRecord[] =>
      availableTags.filter(
        (tag: TagRecord) =>
          (tag.name || '').toLowerCase().includes(tagInput.toLowerCase()) &&
          !selectedTagIds.includes(tag.id)
      ),
    [availableTags, tagInput, selectedTagIds]
  );

  const handleAddTag = (tag: TagRecord): void => {
    setSelectedTagIds([...selectedTagIds, tag.id]);
    setTagInput('');
    setIsTagDropdownOpen(false);
  };

  const handleCreateTag = async (): Promise<void> => {
    if (!tagInput.trim()) return;

    const existingTag = availableTags.find(
      (t: TagRecord) => (t.name || '').toLowerCase() === tagInput.trim().toLowerCase()
    );

    if (existingTag) {
      if (!selectedTagIds.includes(existingTag.id)) {
        handleAddTag(existingTag);
      } else {
        setTagInput('');
        setIsTagDropdownOpen(false);
      }
      return;
    }

    try {
      const newTag = await createTagMutation.mutateAsync({
        name: tagInput.trim(),
        color: null,
        notebookId: notebookId ?? noteNotebookId ?? null,
      });
      onTagCreated?.();
      setSelectedTagIds((prev: string[]) => [...prev, newTag.id]);
      setTagInput('');
      setIsTagDropdownOpen(false);
    } catch (error: unknown) {
      logClientCatch(error, {
        source: 'useNoteTags',
        action: 'createTag',
        name: tagInput.trim(),
        notebookId: notebookId ?? noteNotebookId,
      });
      toast('Failed to create tag', { variant: 'error' });
    }
  };

  const handleRemoveTag = (tagId: string): void => {
    setSelectedTagIds(selectedTagIds.filter((id: string) => id !== tagId));
  };

  return {
    selectedTagIds,
    setSelectedTagIds,
    tagInput,
    setTagInput,
    isTagDropdownOpen,
    setIsTagDropdownOpen,
    filteredTags,
    handleAddTag,
    handleCreateTag,
    handleRemoveTag,
  };
}

'use client';

import { useMemo, useCallback } from 'react';

import { findFolderById } from '@/shared/lib/foldertree/public';
import type { UseNoteThemeProps } from '@/shared/contracts/notes';
import type { NoteWithRelations, NotebookRecord, ThemeRecord } from '@/shared/contracts/notes';
import { logClientCatch } from '@/shared/utils/observability/client-error-logger';

export function useNoteTheme({
  themes,
  notebook,
  folderTree,
  selectedFolderId,
  selectedNotebookId,
  selectedNote,
  fetchFolderTree,
  setNotebook,
}: UseNoteThemeProps): {
  getThemeForNote: (note: NoteWithRelations | null | undefined) => ThemeRecord | null;
  selectedNoteTheme: ThemeRecord | null;
  selectedFolderTheme: ThemeRecord | null;
  selectedFolderThemeId: string;
  handleThemeChange: (themeId: string | null) => Promise<void>;
} {
  const themeMap = useMemo(
    (): Map<string, ThemeRecord> =>
      new Map(themes.map((theme: ThemeRecord): [string, ThemeRecord] => [String(theme.id), theme])),
    [themes]
  );

  const defaultTheme: ThemeRecord | null = notebook?.defaultThemeId
    ? (themeMap.get(String(notebook.defaultThemeId)) ?? null)
    : null;

  const getThemeForFolderId = useCallback(
    (folderId: string | null | undefined): ThemeRecord | null => {
      if (!folderId) return null;
      const folder = findFolderById(folderTree, folderId);
      const themeId = folder?.themeId ? String(folder.themeId) : null;
      if (!themeId) return null;
      return themeMap.get(themeId) ?? null;
    },
    [folderTree, themeMap]
  );

  const selectedFolderTheme = useMemo(
    (): ThemeRecord | null => getThemeForFolderId(selectedFolderId),
    [getThemeForFolderId, selectedFolderId]
  );

  const selectedFolderThemeId: string = selectedFolderId
    ? ((): string => {
      const folder = findFolderById(folderTree, selectedFolderId);
      return folder?.themeId ? String(folder.themeId) : '';
    })()
    : notebook?.defaultThemeId
      ? String(notebook.defaultThemeId)
      : '';

  const getThemeForNote = useCallback(
    (note: NoteWithRelations | null | undefined): ThemeRecord | null => {
      if (!note) return null;
      // 1. Check selected folder's theme
      if (selectedFolderId) {
        const selectedTheme = getThemeForFolderId(selectedFolderId);
        if (selectedTheme) return selectedTheme;
      }
      // 2. Check note's category themes
      const categoryIds =
        note.categories?.map((category: { categoryId: string }): string => category.categoryId) ??
        [];
      for (const categoryId of categoryIds) {
        const theme = getThemeForFolderId(categoryId);
        if (theme) return theme;
      }
      // 3. Fall back to notebook's default theme
      return defaultTheme;
    },
    [getThemeForFolderId, selectedFolderId, defaultTheme]
  );

  const selectedNoteTheme: ThemeRecord | null = useMemo(
    (): ThemeRecord | null => getThemeForNote(selectedNote),
    [getThemeForNote, selectedNote]
  );

  const handleUpdateFolderTheme = useCallback(
    async (themeId: string | null): Promise<void> => {
      if (!selectedFolderId) return;
      try {
        const response = await fetch(`/api/notes/categories/${selectedFolderId}`, {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ themeId }),
        });
        if (response.ok) {
          await fetchFolderTree();
        }
      } catch (error: unknown) {
        logClientCatch(error, {
          source: 'useNoteTheme',
          action: 'updateFolderTheme',
          folderId: selectedFolderId,
          themeId,
        });
      }
    },
    [selectedFolderId, fetchFolderTree]
  );

  const handleUpdateNotebookDefaultTheme = useCallback(
    async (themeId: string | null): Promise<void> => {
      if (!selectedNotebookId) return;
      try {
        const response = await fetch(`/api/notes/notebooks/${selectedNotebookId}`, {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ defaultThemeId: themeId }),
        });
        if (response.ok) {
          const updated = (await response.json()) as NotebookRecord;
          setNotebook(updated);
        }
      } catch (error: unknown) {
        logClientCatch(error, {
          source: 'useNoteTheme',
          action: 'updateNotebookDefaultTheme',
          notebookId: selectedNotebookId,
          themeId,
        });
      }
    },
    [selectedNotebookId, setNotebook]
  );

  const handleThemeChange = useCallback(
    async (themeId: string | null): Promise<void> => {
      if (selectedFolderId) {
        await handleUpdateFolderTheme(themeId);
      } else {
        await handleUpdateNotebookDefaultTheme(themeId);
      }
    },
    [selectedFolderId, handleUpdateFolderTheme, handleUpdateNotebookDefaultTheme]
  );

  return {
    getThemeForNote,
    selectedNoteTheme,
    selectedFolderTheme,
    selectedFolderThemeId,
    handleThemeChange,
  };
}

'use client';

import { useMemo } from 'react';

import type {
  NoteTagWithDetails,
  NoteWithRelations,
  TagRecord,
  UndoAction,
} from '@/shared/contracts/notes';
import { UI_GRID_RELAXED_CLASSNAME, UI_GRID_SPACED_CLASSNAME } from '@/shared/ui/navigation-and-layout.public';
import { cn } from '@/shared/utils/ui-utils';

import type { NotesAppStateValue } from './NotesAppContext.types';

const formatUndoLabel = (action: UndoAction): string => {
  if (action.type === 'moveNote') return 'Moved note';
  if (action.type === 'moveFolder') return 'Moved folder';
  if (action.type === 'renameFolder') return `Renamed folder to "${action.toName}"`;
  return `Renamed note to "${action.toTitle}"`;
};

export function useNotesAppDerivedState({
  filters,
  notes,
  settings,
  undoStack,
}: {
  filters: NotesAppStateValue['filters'];
  notes: NoteWithRelations[];
  settings: NotesAppStateValue['settings'];
  undoStack: UndoAction[];
}): Pick<
  NotesAppStateValue,
  | 'sortedNotes'
  | 'pagedNotes'
  | 'totalPages'
  | 'noteLayoutClassName'
  | 'availableTagsInScope'
  | 'undoHistory'
> {
  const sortedNotes = useMemo((): NoteWithRelations[] => {
    const sorted: NoteWithRelations[] = [...notes].sort(
      (a: NoteWithRelations, b: NoteWithRelations): number => {
        if (settings.sortBy === 'name') {
          return a.title.localeCompare(b.title);
        }
        if (settings.sortBy === 'updated') {
          const aTime = a.updatedAt ? new Date(a.updatedAt).getTime() : 0;
          const bTime = b.updatedAt ? new Date(b.updatedAt).getTime() : 0;
          return aTime - bTime;
        }
        return new Date(a.createdAt || 0).getTime() - new Date(b.createdAt || 0).getTime();
      }
    );
    return settings.sortOrder === 'desc' ? sorted.reverse() : sorted;
  }, [notes, settings.sortBy, settings.sortOrder]);

  const totalPages = useMemo((): number => {
    return Math.max(1, Math.ceil(sortedNotes.length / (filters.pageSize || 1)));
  }, [sortedNotes.length, filters.pageSize]);

  const pagedNotes = useMemo((): NoteWithRelations[] => {
    const clampedPage: number = Math.min(filters.page, totalPages);
    const start: number = (clampedPage - 1) * filters.pageSize;
    return sortedNotes.slice(start, start + filters.pageSize);
  }, [sortedNotes, filters.page, filters.pageSize, totalPages]);

  const noteLayoutClassName = useMemo((): string => {
    if (settings.viewMode === 'list') {
      return cn(UI_GRID_SPACED_CLASSNAME, 'grid-cols-1');
    }
    if (settings.gridDensity === 8) {
      return cn(
        UI_GRID_SPACED_CLASSNAME,
        'grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 xl:grid-cols-6 2xl:grid-cols-8'
      );
    }
    return cn(UI_GRID_RELAXED_CLASSNAME, 'sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4');
  }, [settings.viewMode, settings.gridDensity]);

  const availableTagsInScope = useMemo((): TagRecord[] => {
    const tagMap: Map<string, TagRecord> = new Map<string, TagRecord>();
    notes.forEach((note: NoteWithRelations): void => {
      (note.tags as NoteTagWithDetails[]).forEach((noteTag: NoteTagWithDetails): void => {
        tagMap.set(noteTag.tagId, noteTag.tag);
      });
    });
    return Array.from(tagMap.values()).sort((a: TagRecord, b: TagRecord): number =>
      (a.name || '').localeCompare(b.name || '')
    );
  }, [notes]);

  const undoHistory = useMemo(
    (): { label: string }[] =>
      undoStack.map((action: UndoAction): { label: string } => ({
        label: formatUndoLabel(action),
      })),
    [undoStack]
  );

  return {
    sortedNotes,
    pagedNotes,
    totalPages,
    noteLayoutClassName,
    availableTagsInScope,
    undoHistory,
  };
}

'use client';

import { useCallback } from 'react';


import type {
  NoteRelationWithSource,
  NoteRelationWithTarget,
  NoteUpdateInput,
  NoteWithRelations,
} from '@/shared/contracts/notes';
import type { Toast } from '@/shared/contracts/ui/base';
import { api } from '@/shared/lib/api-client';
import { fetchQueryV2 } from '@/shared/lib/query-factories-v2';
import { QUERY_KEYS } from '@/shared/lib/query-keys';
import { logClientCatch } from '@/shared/utils/observability/client-error-logger';

import type { NotesAppActionsValue, NotesAppStateValue } from './NotesAppContext.types';
import type { UseNoteDataResult } from './useNoteData';
import type { QueryClient } from '@tanstack/react-query';

type UpdateNoteInput = NoteUpdateInput & { id: string };

export function useNotesAppEntityHandlers({
  confirmAction,
  deleteNote,
  fetchFolderTree,
  fetchNotes,
  fetchTags,
  filters,
  queryClient,
  selectedNote,
  setNotes,
  setIsCreating,
  setIsEditing,
  setSelectedFolderId,
  setSelectedNote,
  toast,
  updateNote,
  updateSettings,
}: {
  confirmAction: NotesAppActionsValue['confirmAction'];
  deleteNote: (noteId: string) => Promise<unknown>;
  fetchFolderTree: UseNoteDataResult['fetchFolderTree'];
  fetchNotes: UseNoteDataResult['fetchNotes'];
  fetchTags: UseNoteDataResult['fetchTags'];
  filters: NotesAppStateValue['filters'];
  queryClient: QueryClient;
  selectedNote: NotesAppStateValue['selectedNote'];
  setNotes: UseNoteDataResult['setNotes'];
  setIsCreating: NotesAppActionsValue['setIsCreating'];
  setIsEditing: NotesAppActionsValue['setIsEditing'];
  setSelectedFolderId: NotesAppActionsValue['setSelectedFolderId'];
  setSelectedNote: NotesAppActionsValue['setSelectedNote'];
  toast: Toast;
  updateNote: (input: UpdateNoteInput) => Promise<unknown>;
  updateSettings: NotesAppActionsValue['updateSettings'];
}) {
  const handleSelectNoteFromTree = useCallback(
    async (noteId: string): Promise<void> => {
      try {
        const note = await fetchQueryV2<NoteWithRelations>(queryClient, {
          queryKey: QUERY_KEYS.notes.detail(noteId),
          queryFn: () => api.get<NoteWithRelations>(`/api/notes/${noteId}`),
          staleTime: 10_000,
          meta: {
            source: 'notes.context.handleSelectNoteFromTree',
            operation: 'detail',
            resource: 'notes.detail',
            domain: 'notes',
            queryKey: QUERY_KEYS.notes.detail(noteId),
            tags: ['notes', 'detail', 'fetch'],
            description: 'Loads notes detail.',
          },
        })();
        setSelectedNote(note);
        updateSettings({ selectedNoteId: noteId });
        setIsEditing(false);
      } catch (error: unknown) {
        logClientCatch(error, {
          source: 'NotesAppProvider',
          action: 'fetchNote',
          noteId,
        });
      }
    },
    [queryClient, setIsEditing, setSelectedNote, updateSettings]
  );

  const handleCreateSuccess = useCallback((): void => {
    setIsCreating(false);
    void fetchNotes();
    void fetchFolderTree();
  }, [fetchFolderTree, fetchNotes, setIsCreating]);

  const handleFilterByTag = useCallback(
    (tagId: string): void => {
      filters.handleFilterByTag(tagId, setSelectedFolderId, setSelectedNote, setIsEditing);
    },
    [filters, setIsEditing, setSelectedFolderId, setSelectedNote]
  );

  const handleUpdateSuccess = useCallback((): void => {
    setIsEditing(false);
    void fetchNotes();
    void fetchFolderTree();
    if (selectedNote) {
      void queryClient.invalidateQueries({ queryKey: QUERY_KEYS.notes.detail(selectedNote.id) });
      void handleSelectNoteFromTree(selectedNote.id);
    }
  }, [
    fetchFolderTree,
    fetchNotes,
    handleSelectNoteFromTree,
    queryClient,
    selectedNote,
    setIsEditing,
  ]);

  const handleToggleFavorite = useCallback(
    async (note: NoteWithRelations): Promise<void> => {
      const nextFavorite: boolean = !note.isFavorite;
      try {
        await updateNote({
          id: note.id,
          isFavorite: nextFavorite,
        });

        setNotes((prev): NoteWithRelations[] => {
          return (
            prev?.map((item: NoteWithRelations): NoteWithRelations =>
              item.id === note.id ? { ...item, isFavorite: nextFavorite } : item
            ) ?? []
          );
        });

        queryClient.setQueriesData<NoteWithRelations[]>(
          { queryKey: QUERY_KEYS.notes.lists() },
          (prev): NoteWithRelations[] | undefined =>
            prev?.map((item: NoteWithRelations): NoteWithRelations =>
              item.id === note.id ? { ...item, isFavorite: nextFavorite } : item
            )
        );

        queryClient.setQueryData<NoteWithRelations | null>(
          QUERY_KEYS.notes.detail(note.id),
          (prev): NoteWithRelations | null | undefined =>
            prev ? { ...prev, isFavorite: nextFavorite } : prev
        );

        if (selectedNote?.id === note.id) {
          setSelectedNote({ ...selectedNote, isFavorite: nextFavorite });
        }
      } catch (error: unknown) {
        logClientCatch(error, {
          source: 'NotesAppProvider',
          action: 'toggleFavorite',
          noteId: note.id,
        });
        toast('Failed to update favorite', { variant: 'error' });
      }
    },
    [queryClient, selectedNote, setNotes, setSelectedNote, toast, updateNote]
  );

  const handleUnlinkRelatedNote = useCallback(
    async (relatedId: string): Promise<void> => {
      if (!selectedNote) return;
      try {
        const sourceRelations: string[] =
          selectedNote.relations?.map((rel: { id: string }): string => rel.id) ||
          [
            ...(selectedNote.relationsFrom ?? [])
              .map((rel: NoteRelationWithTarget) => rel.targetNote?.id)
              .filter((rid: string | undefined): rid is string => Boolean(rid)),
            ...(selectedNote.relationsTo ?? [])
              .map((rel: NoteRelationWithSource) => rel.sourceNote?.id)
              .filter((rid: string | undefined): rid is string => Boolean(rid)),
          ].filter(
            (id: string, index: number, array: string[]): boolean => array.indexOf(id) === index
          );

        const nextSourceIds: string[] = sourceRelations.filter(
          (id: string): boolean => id !== relatedId
        );

        await updateNote({
          id: selectedNote.id,
          relatedNoteIds: nextSourceIds,
        });

        toast('Note unlinked');
        await fetchNotes();
        void handleSelectNoteFromTree(selectedNote.id);
      } catch (error: unknown) {
        logClientCatch(error, {
          source: 'NotesAppProvider',
          action: 'unlinkNote',
          noteId: selectedNote.id,
          relatedId,
        });
        toast('Failed to unlink note', { variant: 'error' });
      }
    },
    [fetchNotes, handleSelectNoteFromTree, selectedNote, toast, updateNote]
  );

  const handleDeleteNote = useCallback(async (): Promise<void> => {
    if (!selectedNote) return;
    confirmAction({
      title: 'Delete Note?',
      message: 'Are you sure you want to delete this note?',
      confirmText: 'Delete',
      isDangerous: true,
      onConfirm: async () => {
        try {
          await deleteNote(selectedNote.id);
          setSelectedNote(null);
          setIsEditing(false);
        } catch (error: unknown) {
          logClientCatch(error, {
            source: 'NotesAppProvider',
            action: 'deleteNote',
            noteId: selectedNote.id,
          });
          toast('Failed to delete note', { variant: 'error' });
        }
      },
    });
  }, [confirmAction, deleteNote, selectedNote, setIsEditing, setSelectedNote, toast]);

  const fetchTagsAction = useCallback((): void => {
    void fetchTags();
  }, [fetchTags]);

  return {
    handleSelectNoteFromTree,
    handleCreateSuccess,
    handleFilterByTag,
    handleUpdateSuccess,
    handleToggleFavorite,
    handleUnlinkRelatedNote,
    handleDeleteNote,
    fetchTagsAction,
  };
}

'use client';

import { useRouter } from 'nextjs-toploader/app';
import { useEffect, useState, useMemo, useCallback, startTransition } from 'react';

import { useNotebookResource } from '@/features/notesapp/api/useNotebookResource';
import {
  useNoteSettingsActions,
  useNoteSettingsState,
} from '@/features/notesapp/hooks/NoteSettingsContext';
import type { NotebookRecord } from '@/shared/contracts/notes';
import { AdminNotesPageLayout } from '@/shared/ui/admin.public';
import { Button, useToast, Input } from '@/shared/ui/primitives.public';
import { FormSection, FormField, FormActions } from '@/shared/ui/forms-and-actions.public';
import { LoadingState, UI_STACK_RELAXED_CLASSNAME } from '@/shared/ui/navigation-and-layout.public';
import { StatusBadge } from '@/shared/ui/data-display.public';
import { StandardDataTablePanel, FilterPanel } from '@/shared/ui/templates.public';
import { ConfirmModal } from '@/shared/ui/templates/modals';
import { logClientCatch } from '@/shared/utils/observability/client-error-logger';

import type { ColumnDef } from '@tanstack/react-table';

export function AdminNotesNotebooksPage(): React.JSX.Element {
  const { toast } = useToast();
  const { settings } = useNoteSettingsState();
  const { updateSettings } = useNoteSettingsActions();
  const { selectedNotebookId } = settings;
  const router = useRouter();
  const [name, setName] = useState('');
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editingName, setEditingName] = useState('');
  const [search, setSearch] = useState('');
  const [notebookToDelete, setNotebookToDelete] = useState<string | null>(null);

  const {
    listQuery: notebooksQuery,
    createMutation: createNotebook,
    updateMutation: updateNotebook,
    deleteMutation: deleteNotebook,
  } = useNotebookResource();

  const notebooks = useMemo(
    (): NotebookRecord[] => notebooksQuery.data ?? [],
    [notebooksQuery.data]
  );
  const filteredNotebooks = useMemo(() => {
    if (!search.trim()) return notebooks;
    const q = search.toLowerCase().trim();
    return notebooks.filter((nb) => nb.name.toLowerCase().includes(q));
  }, [notebooks, search]);
  const loading = notebooksQuery.isPending;

  useEffect((): void => {
    if (!selectedNotebookId && notebooks.length > 0) {
      updateSettings({ selectedNotebookId: notebooks[0]!.id });
    }
  }, [selectedNotebookId, notebooks, updateSettings]);

  const handleCreate = async (): Promise<void> => {
    if (!name.trim()) {
      toast('Notebook name is required', { variant: 'error' });
      return;
    }
    try {
      await createNotebook.mutateAsync({
        name: name.trim(),
        description: null,
        color: null,
        defaultThemeId: null,
      });
      setName('');
      toast('Notebook created', { variant: 'success' });
    } catch (error: unknown) {
      logClientCatch(error, {
        source: 'AdminNotesNotebooksPage',
        action: 'createNotebook',
        name,
      });
      toast('Failed to create notebook', { variant: 'error' });
    }
  };

  const handleEditStart = useCallback((notebook: NotebookRecord): void => {
    setEditingId(notebook.id);
    setEditingName(notebook.name);
  }, []);

  const handleEditCancel = useCallback((): void => {
    setEditingId(null);
    setEditingName('');
  }, []);

  const handleUpdate = async (id: string): Promise<void> => {
    if (!editingName.trim()) {
      toast('Notebook name is required', { variant: 'error' });
      return;
    }
    try {
      await updateNotebook.mutateAsync({ id, name: editingName.trim() });
      toast('Notebook updated', { variant: 'success' });
      handleEditCancel();
    } catch (error: unknown) {
      logClientCatch(error, {
        source: 'AdminNotesNotebooksPage',
        action: 'updateNotebook',
        id,
      });
      toast('Failed to update notebook', { variant: 'error' });
    }
  };

  const handleDelete = async (id: string): Promise<void> => {
    try {
      await deleteNotebook.mutateAsync(id);
      if (selectedNotebookId === id) {
        updateSettings({ selectedNotebookId: null });
      }
      toast('Notebook deleted', { variant: 'success' });
      setNotebookToDelete(null);
    } catch (error: unknown) {
      logClientCatch(error, {
        source: 'AdminNotesNotebooksPage',
        action: 'deleteNotebook',
        id,
      });
      toast('Failed to delete notebook', { variant: 'error' });
    }
  };

  const handleDuplicate = async (notebook: NotebookRecord): Promise<void> => {
    const baseName = notebook.name.trim();
    const existing = notebooks
      .filter((item: NotebookRecord): boolean => item.name.startsWith(baseName))
      .map((item: NotebookRecord): number => {
        const match = item.name.match(/\((\d+)\)$/);
        return match ? Number(match[1]) : 0;
      });
    const nextNumber = existing.length > 0 ? Math.max(...existing) + 1 : 1;
    const newName = `${baseName} (${nextNumber})`;
    try {
      await createNotebook.mutateAsync({
        name: newName,
        color: notebook.color ?? null,
        defaultThemeId: notebook.defaultThemeId ?? null,
      });
      toast('Notebook duplicated', { variant: 'success' });
    } catch (error: unknown) {
      logClientCatch(error, {
        source: 'AdminNotesNotebooksPage',
        action: 'duplicateNotebook',
        originalId: notebook.id,
      });
      toast('Failed to duplicate notebook', { variant: 'error' });
    }
  };

  const columns = useMemo<ColumnDef<NotebookRecord>[]>(
    () => [
      {
        accessorKey: 'name',
        header: 'Notebook Name',
        cell: ({ row }) => {
          const nb = row.original;
          const isEditing = editingId === nb.id;

          if (isEditing) {
            return (
              <Input
                type='text'
                value={editingName}
                aria-label='Notebook name'
                onChange={(e) => setEditingName(e.target.value)}
                className='h-8 py-0'
                ref={(node) => {
                  node?.focus();
                }}
               title='Input field'/>
            );
          }

          return (
            <div className='flex items-center gap-2'>
              <span className='font-medium'>{nb.name}</span>
              {selectedNotebookId === nb.id && (
                <StatusBadge status='Active' variant='active' size='sm' className='font-bold' />
              )}
            </div>
          );
        },
      },
      {
        id: 'actions',
        header: () => <div className='text-right'>Actions</div>,
        cell: ({ row }) => {
          const nb = row.original;
          const isEditing = editingId === nb.id;

          return (
            <div className='flex items-center justify-end gap-2'>
              {isEditing ? (
                <FormActions
                  onSave={() => void handleUpdate(nb.id)}
                  onCancel={handleEditCancel}
                  saveText='Save'
                  isSaving={updateNotebook.isPending}
                  saveVariant='default'
                  cancelVariant='ghost'
                />
              ) : (
                <>
                  <Button
                    variant='outline'
                    size='xs'
                    onClick={(e) => {
                      e.stopPropagation();
                      updateSettings({ selectedNotebookId: nb.id });
                      startTransition(() => { router.push('/admin/notes'); });
                    }}
                  >
                    Open
                  </Button>
                  <Button
                    variant='outline'
                    size='xs'
                    onClick={(e) => {
                      e.stopPropagation();
                      handleEditStart(nb);
                    }}
                  >
                    Edit
                  </Button>
                  <Button
                    variant='outline'
                    size='xs'
                    onClick={(e) => {
                      e.stopPropagation();
                      void handleDuplicate(nb);
                    }}
                  >
                    Duplicate
                  </Button>
                  <Button
                    variant='outline'
                    size='xs'
                    className='text-red-300 hover:text-red-200'
                    onClick={(e) => {
                      e.stopPropagation();
                      setNotebookToDelete(nb.id);
                    }}
                  >
                    Delete
                  </Button>
                </>
              )}
            </div>
          );
        },
      },
    ],
    [
      editingId,
      editingName,
      selectedNotebookId,
      updateNotebook.isPending,
      updateSettings,
      router,
      handleUpdate,
      handleEditCancel,
      handleEditStart,
      handleDuplicate,
    ]
  );

  if (loading) {
    return (
      <AdminNotesPageLayout
        title='Notebooks'
        current='Notebooks'
        description='Loading notebooks...'
      >
        <div className='flex min-h-[400px] items-center justify-center'>
          <LoadingState message='Loading notebooks...' />
        </div>
      </AdminNotesPageLayout>
    );
  }

  return (
    <AdminNotesPageLayout
      title='Notebooks'
      current='Notebooks'
      description='Create and manage notebooks. Notes, folders, and tags are scoped per notebook.'
      refresh={{
        onRefresh: () => {
          void notebooksQuery.refetch();
        },
        isRefreshing: notebooksQuery.isFetching,
      }}
    >
      <div className='max-w-4xl space-y-6'>
        <FormSection title='Create Notebook' className='p-6'>
          <div className={`${UI_STACK_RELAXED_CLASSNAME} sm:flex-row sm:items-end`}>
            <FormField label='Notebook Name' className='flex-1'>
              <Input
                type='text'
                value={name}
                onChange={(event: React.ChangeEvent<HTMLInputElement>): void =>
                  setName(event.target.value)
                }
                className='w-full'
                placeholder='Enter notebook name'
               aria-label='Enter notebook name' title='Enter notebook name'/>
            </FormField>
            <Button
              onClick={(): void => {
                void handleCreate();
              }}
              disabled={createNotebook.isPending}
            >
              {createNotebook.isPending ? 'Saving...' : 'Create'}
            </Button>
          </div>
        </FormSection>

        <StandardDataTablePanel
          columns={columns}
          data={filteredNotebooks}
          filters={
            <FilterPanel
              filters={[]}
              values={{}}
              search={search}
              searchPlaceholder='Search notebooks by name...'
              onFilterChange={() => {}}
              onSearchChange={setSearch}
              onReset={() => setSearch('')}
              showHeader={false}
              compact
            />
          }
          isLoading={loading}
        />
      </div>

      <ConfirmModal
        isOpen={Boolean(notebookToDelete)}
        onClose={() => setNotebookToDelete(null)}
        title='Delete Notebook?'
        message='Delete this notebook and all its notes/tags/folders? This action cannot be undone.'
        confirmText='Destroy Notebook'
        isDangerous={true}
        onConfirm={(): void => {
          if (notebookToDelete) {
            void handleDelete(notebookToDelete);
          }
        }}
      />
    </AdminNotesPageLayout>
  );
}

