import type { TagRecord } from '@/shared/contracts/notes';
import { AdminNotesPageLayout } from '@/shared/ui/admin.public';
import { Button, useToast, Input } from '@/shared/ui/primitives.public';
import { FormSection, FormField, Tag, FormActions } from '@/shared/ui/forms-and-actions.public';
import { StandardDataTablePanel, FilterPanel } from '@/shared/ui/templates.public';
import { CompactEmptyState, UI_STACK_RELAXED_CLASSNAME } from '@/shared/ui/navigation-and-layout.public';
import { ConfirmModal } from '@/shared/ui/templates/modals';
import { logClientCatch } from '@/shared/utils/observability/client-error-logger';

import type { ColumnDef } from '@tanstack/react-table';

export function AdminNotesTagsPage(): React.JSX.Element {
  const { toast } = useToast();
  const { settings } = useNoteSettingsState();
  const { updateSettings } = useNoteSettingsActions();
  const { selectedNotebookId } = settings;
  const [name, setName] = useState('');
  const [color, setColor] = useState('#3b82f6');
  const [searchQuery, setSearchQuery] = useState('');
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editingName, setEditingName] = useState('');
  const [editingColor, setEditingColor] = useState('#3b82f6');
  const [toDelete, setToDelete] = useState<TagRecord | null>(null);

  const { listQuery: notebooksQuery } = useNotebookResource();
  const tagsQuery = useNoteTags(selectedNotebookId ?? undefined);
  const createTag = useCreateNoteTag();
  const updateTag = useUpdateNoteTag();
  const deleteTag = useDeleteNoteTag();

  const tags = useMemo((): TagRecord[] => tagsQuery.data ?? [], [tagsQuery.data]);
  const loading = tagsQuery.isLoading;

  useEffect((): void => {
    if (selectedNotebookId) return;
    const firstId = notebooksQuery.data?.[0]?.id;
    if (firstId) {
      updateSettings({ selectedNotebookId: firstId });
    }
  }, [selectedNotebookId, updateSettings, notebooksQuery.data]);

  const handleCreate = async (): Promise<void> => {
    if (!name.trim()) {
      toast('Tag name is required', { variant: 'error' });
      return;
    }
    try {
      if (!selectedNotebookId) return;
      await createTag.mutateAsync({
        name: name.trim(),
        color,
        notebookId: selectedNotebookId,
      });
      setName('');
      toast('Tag created', { variant: 'success' });
    } catch (error: unknown) {
      logClientCatch(error, {
        source: 'AdminNotesTagsPage',
        action: 'createTag',
        name,
        notebookId: selectedNotebookId,
      });
      toast('Failed to create tag', { variant: 'error' });
    }
  };

  const handleConfirmDelete = async (): Promise<void> => {
    if (!toDelete) return;
    try {
      await deleteTag.mutateAsync(toDelete.id);
      toast('Tag deleted', { variant: 'success' });
    } catch (error: unknown) {
      logClientCatch(error, {
        source: 'AdminNotesTagsPage',
        action: 'deleteTag',
        tagId: toDelete.id,
      });
      toast('Failed to delete tag', { variant: 'error' });
    } finally {
      setToDelete(null);
    }
  };

  const handleEditStart = useCallback((tag: TagRecord): void => {
    setEditingId(tag.id);
    setEditingName(tag.name);
    setEditingColor(tag.color || '#3b82f6');
  }, []);

  const handleEditCancel = useCallback((): void => {
    setEditingId(null);
    setEditingName('');
    setEditingColor('#3b82f6');
  }, []);

  const handleUpdate = async (tagId: string): Promise<void> => {
    if (!editingName.trim()) {
      toast('Tag name is required', { variant: 'error' });
      return;
    }
    try {
      await updateTag.mutateAsync({
        id: tagId,
        name: editingName.trim(),
        color: editingColor,
      });
      toast('Tag updated', { variant: 'success' });
      handleEditCancel();
    } catch (error: unknown) {
      logClientCatch(error, {
        source: 'AdminNotesTagsPage',
        action: 'updateTag',
        tagId,
      });
      toast('Failed to update tag', { variant: 'error' });
    }
  };

  const filteredTags = useMemo(
    (): TagRecord[] =>
      tags.filter((tag: TagRecord) =>
        tag.name.toLowerCase().includes(searchQuery.trim().toLowerCase())
      ),
    [tags, searchQuery]
  );

  const columns = useMemo<ColumnDef<TagRecord>[]>(
    () => [
      {
        accessorKey: 'name',
        header: 'Tag',
        cell: ({ row }) => {
          const tag = row.original;
          const isEditing = editingId === tag.id;

          if (isEditing) {
            return (
              <div className='flex flex-col gap-2 sm:flex-row sm:items-center'>
                <Input
                  type='text'
                  value={editingName}
                  aria-label='Tag name'
                  onChange={(event: React.ChangeEvent<HTMLInputElement>): void =>
                    setEditingName(event.target.value)
                  }
                  className='h-8 w-full sm:max-w-[200px]'
                  ref={(node) => {
                    node?.focus();
                  }}
                 title='Input field'/>
                <div className='flex items-center gap-2'>
                  <Input
                    type='color'
                    value={editingColor}
                    aria-label='Tag color'
                    onChange={(event: React.ChangeEvent<HTMLInputElement>): void =>
                      setEditingColor(event.target.value)
                    }
                    className='h-8 w-12 p-1'
                   title='Input field'/>
                  <span className='text-[10px] font-mono text-gray-500 uppercase'>
                    {editingColor}
                  </span>
                </div>
              </div>
            );
          }

          return (
            <Tag
              label={tag.name || 'Unnamed'}
              color={tag.color || '#3b82f6'}
              dot
              className='h-7 font-semibold'
            />
          );
        },
      },
      {
        id: 'actions',
        header: () => <div className='text-right'>Actions</div>,
        cell: ({ row }) => {
          const tag = row.original;
          const isEditing = editingId === tag.id;

          return (
            <div className='flex items-center justify-end gap-2'>
              {isEditing ? (
                <FormActions
                  onSave={() => void handleUpdate(tag.id)}
                  onCancel={handleEditCancel}
                  saveText='Save'
                  isSaving={updateTag.isPending}
                  saveVariant='default'
                  cancelVariant='ghost'
                />
              ) : (
                <>
                  <Button variant='outline' size='xs' onClick={(): void => handleEditStart(tag)}>
                    Edit
                  </Button>
                  <Button
                    type='button'
                    size='xs'
                    variant='outline'
                    onClick={(): void => setToDelete(tag)}
                    className='text-red-300 hover:text-red-200'
                    aria-label={`Delete ${tag.name}`}
                    title={`Delete ${tag.name}`}>
                    <Trash2 size={14} />
                  </Button>
                </>
              )}
            </div>
          );
        },
      },
    ],
    [
      editingId,
      editingName,
      editingColor,
      handleUpdate,
      updateTag.isPending,
      handleEditCancel,
      handleEditStart,
    ]
  );

  return (
    <AdminNotesPageLayout
      title='Note Tags'
      current='Tags'
      description='Create and remove tags used in the Notes app.'
      refresh={{
        onRefresh: () => {
          void tagsQuery.refetch();
        },
        isRefreshing: tagsQuery.isFetching,
      }}
    >
      <div className='max-w-4xl space-y-6'>
        <FormSection title='Create Tag' variant='subtle'>
          <div className={`${UI_STACK_RELAXED_CLASSNAME} sm:flex-row sm:items-end`}>
            <FormField label='Tag Name' className='flex-1'>
              <Input
                type='text'
                value={name}
                onChange={(event: React.ChangeEvent<HTMLInputElement>): void =>
                  setName(event.target.value)
                }
                className='w-full'
                placeholder='Enter tag name'
               aria-label='Enter tag name' title='Enter tag name'/>
            </FormField>
            <FormField label='Color'>
              <div className='flex items-center gap-2'>
                <Input
                  type='color'
                  value={color}
                  onChange={(event: React.ChangeEvent<HTMLInputElement>): void =>
                    setColor(event.target.value)
                  }
                  className='h-10 w-16 p-1'
                 aria-label='Color' title='Color'/>
                <span className='text-xs font-mono text-gray-500 uppercase'>{color}</span>
              </div>
            </FormField>
            <Button
              onClick={(): void => {
                void handleCreate();
              }}
              disabled={createTag.isPending}
            >
              <Plus className='mr-2 size-4' />
              {createTag.isPending ? 'Saving...' : 'Create'}
            </Button>
          </div>
        </FormSection>

        <StandardDataTablePanel
          filters={
            <FilterPanel
              filters={[]}
              values={{}}
              search={searchQuery}
              searchPlaceholder='Search tags by name...'
              onFilterChange={() => {}}
              onSearchChange={setSearchQuery}
              onReset={() => setSearchQuery('')}
              showHeader={false}
              compact
            />
          }
          columns={columns}
          data={filteredTags}
          isLoading={loading}
          emptyState={
            <CompactEmptyState
              title={searchQuery ? 'No tags found' : 'No tags created yet'}
              description={
                searchQuery
                  ? 'Try a different search query.'
                  : 'Create your first tag to start organizing notes.'
              }
              className='py-8'
             />
          }
        />
      </div>

      <ConfirmModal
        isOpen={Boolean(toDelete)}
        onClose={() => setToDelete(null)}
        onConfirm={handleConfirmDelete}
        title='Delete Tag'
        message={`Are you sure you want to delete tag "${toDelete?.name ?? ''}"? It will be removed from all notes.`}
        confirmText='Delete'
        isDangerous={true}
        loading={deleteTag.isPending}
      />
    </AdminNotesPageLayout>
  );
}

'use client';

import { Trash2 } from 'lucide-react';
import React, { useEffect, useState } from 'react';

import { useNotebookResource } from '@/features/notesapp/api/useNotebookResource';
import {
  useCreateNoteTheme,
  useDeleteNoteTheme,
  useUpdateNoteTheme,
} from '@/features/notesapp/api/useNoteMutations';
import { useNoteThemes } from '@/features/notesapp/api/useNoteQueries';
import {
  useNoteSettingsActions,
  useNoteSettingsState,
} from '@/features/notesapp/hooks/NoteSettingsContext';
import type { ThemeRecord } from '@/shared/contracts/notes';
import { AdminNotesPageLayout } from '@/shared/ui/admin.public';
import { Button, useToast, Input } from '@/shared/ui/primitives.public';
import { FormSection, FormField, FormActions } from '@/shared/ui/forms-and-actions.public';
import { ListPanel, UI_CENTER_ROW_SPACED_CLASSNAME, UI_GRID_RELAXED_CLASSNAME } from '@/shared/ui/navigation-and-layout.public';
import { ConfirmModal } from '@/shared/ui/templates/modals';
import { logClientCatch } from '@/shared/utils/observability/client-error-logger';

const defaultTheme: Omit<ThemeRecord, 'id' | 'createdAt' | 'updatedAt'> = {
  name: '',
  isDefault: false,
  notebookId: null,
  textColor: '#e5e7eb',
  backgroundColor: '#111827',
  markdownHeadingColor: '#ffffff',
  markdownLinkColor: '#60a5fa',
  markdownCodeBackground: '#1f2937',
  markdownCodeText: '#e5e7eb',
  relatedNoteBorderWidth: 1,
  relatedNoteBorderColor: '#374151',
  relatedNoteBackgroundColor: '#1f2937',
  relatedNoteTextColor: '#e5e7eb',
};

export function AdminNotesThemesPage(): React.JSX.Element {
  const { toast } = useToast();
  const { settings } = useNoteSettingsState();
  const { updateSettings } = useNoteSettingsActions();
  const { selectedNotebookId } = settings;
  const [form, setForm] =
    useState<Omit<ThemeRecord, 'id' | 'createdAt' | 'updatedAt'>>(defaultTheme);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editingForm, setEditingForm] =
    useState<Omit<ThemeRecord, 'id' | 'createdAt' | 'updatedAt'>>(defaultTheme);
  const { listQuery: notebooksQuery } = useNotebookResource();
  const themesQuery = useNoteThemes(selectedNotebookId ?? undefined);
  const createTheme = useCreateNoteTheme();
  const updateTheme = useUpdateNoteTheme();
  const deleteTheme = useDeleteNoteTheme();

  const [themeToDelete, setThemeToDelete] = useState<string | null>(null);

  const themes = themesQuery.data ?? [];
  const loading = themesQuery.isPending;
  const isSaving = createTheme.isPending;
  const isUpdating = updateTheme.isPending;

  useEffect((): void => {
    if (selectedNotebookId) return;
    const firstId = notebooksQuery.data?.[0]?.id;
    if (firstId) {
      updateSettings({ selectedNotebookId: firstId });
    }
  }, [selectedNotebookId, updateSettings, notebooksQuery.data]);

  const handleCreate = async (): Promise<void> => {
    if (!form.name.trim()) {
      toast('Theme name is required', { variant: 'error' });
      return;
    }
    try {
      if (!selectedNotebookId) return;
      await createTheme.mutateAsync({
        ...form,
        name: form.name.trim(),
        notebookId: selectedNotebookId,
      });
      setForm(defaultTheme);
      toast('Theme created', { variant: 'success' });
    } catch (error: unknown) {
      logClientCatch(error, {
        source: 'AdminNotesThemesPage',
        action: 'createTheme',
        name: form.name,
        notebookId: selectedNotebookId,
      });
      toast('Failed to create theme', { variant: 'error' });
    }
  };

  const handleDelete = async (themeId: string): Promise<void> => {
    try {
      await deleteTheme.mutateAsync(themeId);
      toast('Theme deleted', { variant: 'success' });
      setThemeToDelete(null);
    } catch (error: unknown) {
      logClientCatch(error, {
        source: 'AdminNotesThemesPage',
        action: 'deleteTheme',
        themeId,
      });
      toast('Failed to delete theme', { variant: 'error' });
    }
  };

  const handleEditStart = (theme: ThemeRecord): void => {
    setEditingId(theme.id);
    setEditingForm({ ...theme });
  };

  const handleEditCancel = (): void => {
    setEditingId(null);
    setEditingForm(defaultTheme);
  };

  const handleUpdate = async (themeId: string): Promise<void> => {
    if (!editingForm.name.trim()) {
      toast('Theme name is required', { variant: 'error' });
      return;
    }
    try {
      await updateTheme.mutateAsync({
        id: themeId,
        ...editingForm,
        name: editingForm.name.trim(),
      });
      toast('Theme updated', { variant: 'success' });
      handleEditCancel();
    } catch (error: unknown) {
      logClientCatch(error, {
        source: 'AdminNotesThemesPage',
        action: 'updateTheme',
        themeId,
      });
      toast('Failed to update theme', { variant: 'error' });
    }
  };

  return (
    <AdminNotesPageLayout
      title='Note Themes'
      current='Themes'
      description='Create and manage themes for your notes.'
    >
      <div className='max-w-5xl space-y-8'>
        <FormSection title='Create Theme' className='p-6'>
          <div className={`${UI_GRID_RELAXED_CLASSNAME} sm:grid-cols-2 lg:grid-cols-3`}>
            <FormField label='Theme Name' className='sm:col-span-2'>
              <Input
                type='text'
                value={form.name}
                onChange={(e) => setForm((prev) => ({ ...prev, name: e.target.value }))}
                placeholder='Enter theme name'
               aria-label='Enter theme name' title='Enter theme name'/>
            </FormField>
            <FormField label='Text Color'>
              <Input
                type='color'
                value={form.textColor}
                onChange={(e) => setForm((prev) => ({ ...prev, textColor: e.target.value }))}
                className='h-10 p-1'
               aria-label='Text Color' title='Text Color'/>
            </FormField>
            <FormField label='Background Color'>
              <Input
                type='color'
                value={form.backgroundColor}
                onChange={(e) =>
                  setForm((prev) => ({
                    ...prev,
                    backgroundColor: e.target.value,
                  }))
                }
                className='h-10 p-1'
               aria-label='Background Color' title='Background Color'/>
            </FormField>
            <FormField label='Markdown Heading'>
              <Input
                type='color'
                value={form.markdownHeadingColor}
                onChange={(e) =>
                  setForm((prev) => ({
                    ...prev,
                    markdownHeadingColor: e.target.value,
                  }))
                }
                className='h-10 p-1'
               aria-label='Markdown Heading' title='Markdown Heading'/>
            </FormField>
            <FormField label='Markdown Link'>
              <Input
                type='color'
                value={form.markdownLinkColor}
                onChange={(e) =>
                  setForm((prev) => ({
                    ...prev,
                    markdownLinkColor: e.target.value,
                  }))
                }
                className='h-10 p-1'
               aria-label='Markdown Link' title='Markdown Link'/>
            </FormField>
            <FormField label='Code Background'>
              <Input
                type='color'
                value={form.markdownCodeBackground}
                onChange={(e) =>
                  setForm((prev) => ({
                    ...prev,
                    markdownCodeBackground: e.target.value,
                  }))
                }
                className='h-10 p-1'
               aria-label='Code Background' title='Code Background'/>
            </FormField>
            <FormField label='Code Text'>
              <Input
                type='color'
                value={form.markdownCodeText}
                onChange={(e) =>
                  setForm((prev) => ({
                    ...prev,
                    markdownCodeText: e.target.value,
                  }))
                }
                className='h-10 p-1'
               aria-label='Code Text' title='Code Text'/>
            </FormField>
            <FormField label='Related Border Width'>
              <Input
                type='number'
                min={0}
                max={8}
                value={form.relatedNoteBorderWidth}
                onChange={(e) =>
                  setForm((prev) => ({
                    ...prev,
                    relatedNoteBorderWidth: Number(e.target.value),
                  }))
                }
               aria-label='Related Border Width' title='Related Border Width'/>
            </FormField>
            <FormField label='Related Border Color'>
              <Input
                type='color'
                value={form.relatedNoteBorderColor}
                onChange={(e) =>
                  setForm((prev) => ({
                    ...prev,
                    relatedNoteBorderColor: e.target.value,
                  }))
                }
                className='h-10 p-1'
               aria-label='Related Border Color' title='Related Border Color'/>
            </FormField>
            <FormField label='Related Background'>
              <Input
                type='color'
                value={form.relatedNoteBackgroundColor}
                onChange={(e) =>
                  setForm((prev) => ({
                    ...prev,
                    relatedNoteBackgroundColor: e.target.value,
                  }))
                }
                className='h-10 p-1'
               aria-label='Related Background' title='Related Background'/>
            </FormField>
            <FormField label='Related Text Color'>
              <Input
                type='color'
                value={form.relatedNoteTextColor}
                onChange={(e) =>
                  setForm((prev) => ({
                    ...prev,
                    relatedNoteTextColor: e.target.value,
                  }))
                }
                className='h-10 p-1'
               aria-label='Related Text Color' title='Related Text Color'/>
            </FormField>
          </div>
          <FormActions
            onSave={() => void handleCreate()}
            saveText='Create Theme'
            isSaving={isSaving}
            className='mt-6'
          />
        </FormSection>

        <ListPanel
          title='Existing Themes'
          refresh={{
            onRefresh: () => void themesQuery.refetch(),
            isRefreshing: loading,
          }}
          isLoading={loading}
        >
          <div className='space-y-4'>
            {themes.length === 0 ? (
              <p className='text-sm text-gray-400 italic py-4'>No themes created yet.</p>
            ) : (
              themes.map((theme) => {
                const isEditing = editingId === theme.id;
                const values = isEditing ? editingForm : theme;
                return (
                  <div
                    key={theme.id}
                    className='rounded-lg border border-border/60 bg-card/30 p-5 transition-colors hover:bg-card/40'
                  >
                    <div className='flex flex-wrap items-center justify-between gap-3 mb-4'>
                      <div className={UI_CENTER_ROW_SPACED_CLASSNAME}>
                        <div className='text-lg font-semibold text-white'>{theme.name}</div>
                        <div className='text-xs text-gray-500'>
                          Updated{' '}
                          {theme.updatedAt ? new Date(theme.updatedAt).toLocaleString() : '—'}
                        </div>
                      </div>
                      <div className='flex items-center gap-2'>
                        {isEditing ? (
                          <FormActions
                            onSave={() => void handleUpdate(theme.id)}
                            onCancel={handleEditCancel}
                            saveText='Save'
                            isSaving={isUpdating}
                            saveVariant='default'
                            cancelVariant='ghost'
                            size='sm'
                          />
                        ) : (
                          <Button
                            onClick={() => handleEditStart(theme)}
                            variant='outline'
                            size='sm'
                          >
                            Edit
                          </Button>
                        )}
                        {!isEditing && (
                          <Button
                            onClick={() => setThemeToDelete(theme.id)}
                            variant='outline'
                            size='sm'
                            className='border-red-500/40 text-red-300 hover:text-red-200'
                            aria-label={`Delete ${theme.name}`}
                            title='Delete theme'
                          >
                            <Trash2 className='size-4' />
                          </Button>
                        )}
                      </div>
                    </div>
                    <div
                      className={`${UI_GRID_RELAXED_CLASSNAME} sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4`}
                    >
                      <FormField label='Theme Name'>
                        <Input
                          type='text'
                          value={values.name}
                          disabled={!isEditing}
                          onChange={(e) =>
                            setEditingForm((prev) => ({
                              ...prev,
                              name: e.target.value,
                            }))
                          }
                          className='h-8 text-sm'
                         aria-label='Theme Name' title='Theme Name'/>
                      </FormField>
                      <FormField label='Text'>
                        <Input
                          type='color'
                          disabled={!isEditing}
                          value={values.textColor}
                          onChange={(e) =>
                            setEditingForm((prev) => ({
                              ...prev,
                              textColor: e.target.value,
                            }))
                          }
                          className='h-8 p-1'
                         aria-label='Text' title='Text'/>
                      </FormField>
                      <FormField label='Background'>
                        <Input
                          type='color'
                          disabled={!isEditing}
                          value={values.backgroundColor}
                          onChange={(e) =>
                            setEditingForm((prev) => ({
                              ...prev,
                              backgroundColor: e.target.value,
                            }))
                          }
                          className='h-8 p-1'
                         aria-label='Background' title='Background'/>
                      </FormField>
                      <FormField label='Heading'>
                        <Input
                          type='color'
                          disabled={!isEditing}
                          value={values.markdownHeadingColor}
                          onChange={(e) =>
                            setEditingForm((prev) => ({
                              ...prev,
                              markdownHeadingColor: e.target.value,
                            }))
                          }
                          className='h-8 p-1'
                         aria-label='Heading' title='Heading'/>
                      </FormField>
                      <FormField label='Link'>
                        <Input
                          type='color'
                          disabled={!isEditing}
                          value={values.markdownLinkColor}
                          onChange={(e) =>
                            setEditingForm((prev) => ({
                              ...prev,
                              markdownLinkColor: e.target.value,
                            }))
                          }
                          className='h-8 p-1'
                         aria-label='Link' title='Link'/>
                      </FormField>
                      <FormField label='Code Bg'>
                        <Input
                          type='color'
                          disabled={!isEditing}
                          value={values.markdownCodeBackground}
                          onChange={(e) =>
                            setEditingForm((prev) => ({
                              ...prev,
                              markdownCodeBackground: e.target.value,
                            }))
                          }
                          className='h-8 p-1'
                         aria-label='Code Bg' title='Code Bg'/>
                      </FormField>
                      <FormField label='Code Text'>
                        <Input
                          type='color'
                          disabled={!isEditing}
                          value={values.markdownCodeText}
                          onChange={(e) =>
                            setEditingForm((prev) => ({
                              ...prev,
                              markdownCodeText: e.target.value,
                            }))
                          }
                          className='h-8 p-1'
                         aria-label='Code Text' title='Code Text'/>
                      </FormField>
                      <FormField label='Border Width'>
                        <Input
                          type='number'
                          min={0}
                          max={8}
                          disabled={!isEditing}
                          value={values.relatedNoteBorderWidth}
                          onChange={(e) =>
                            setEditingForm((prev) => ({
                              ...prev,
                              relatedNoteBorderWidth: Number(e.target.value),
                            }))
                          }
                          className='h-8'
                         aria-label='Border Width' title='Border Width'/>
                      </FormField>
                    </div>
                  </div>
                );
              })
            )}
          </div>
        </ListPanel>
      </div>

      <ConfirmModal
        isOpen={Boolean(themeToDelete)}
        onClose={() => setThemeToDelete(null)}
        title='Delete Theme?'
        message='Are you sure you want to delete this theme? This action cannot be undone.'
        confirmText='Delete Theme'
        isDangerous={true}
        onConfirm={() => {
          if (themeToDelete) {
            void handleDelete(themeToDelete);
          }
        }}
      />
    </AdminNotesPageLayout>
  );
}

import 'server-only';

import { randomUUID } from 'crypto';
import fs from 'fs/promises';
import path from 'path';

import { noteService } from '@/features/notesapp/server';
import type { NoteFileRecord } from '@/shared/contracts/notes';
import { ALLOWED_MIME_EXACT, MAX_IMAGE_BYTES } from '@/shared/lib/files/constants';
import { deleteFileFromStorage } from '@/shared/lib/files/file-uploader';
import { notesRoot } from '@/shared/lib/files/server-constants';
import { createFileUploadEvent } from '@/shared/lib/files/services/file-upload-events';
import { uploadToConfiguredStorage } from '@/shared/lib/files/services/storage/file-storage-service';
import { ErrorSystem } from '@/shared/utils/observability/error-system';

function isAllowedMimeType(mime: string | null | undefined): boolean {
  const normalized = (mime ?? '').trim().toLowerCase();
  if (!normalized) return false;
  if (normalized.startsWith('image/')) return true;
  return ALLOWED_MIME_EXACT.has(normalized);
}

function isAllowedFilenameExtension(filename: string): boolean {
  const ext = path.extname(filename).toLowerCase();
  return new Set([
    '.jpg',
    '.jpeg',
    '.png',
    '.webp',
    '.gif',
    '.bmp',
    '.avif',
    '.heic',
    '.heif',
    '.tif',
    '.tiff',
    '.svg',
    '.pdf',
  ]).has(ext);
}

function sanitizeFilename(filename: string): string {
  const ext = path.extname(filename).toLowerCase();
  return `${randomUUID()}${ext}`;
}

export async function uploadNoteFile(
  file: File,
  noteId: string,
  slotIndex: number
): Promise<NoteFileRecord> {
  if (file.size > MAX_IMAGE_BYTES) {
    throw new Error(`File too large. Max size allowed is ${MAX_IMAGE_BYTES / 1024 / 1024}MB.`);
  }
  if (!isAllowedMimeType(file.type) && !isAllowedFilenameExtension(file.name)) {
    throw new Error(`Unsupported file type: ${file.type}`);
  }

  const fileBuffer = Buffer.from(await file.arrayBuffer());
  const filename = `slot-${slotIndex}-${sanitizeFilename(file.name)}`;
  const diskDir = path.join(notesRoot, noteId);
  const publicDir = `/uploads/notes/${noteId}`;
  const publicPath = `${publicDir}/${filename}`;
  const localDiskPath = path.join(diskDir, filename);
  let storageSource: 'local' | 'fastcomet' = 'local';

  try {
    const storageResult = await uploadToConfiguredStorage({
      buffer: fileBuffer,
      filename,
      mimetype: file.type || 'application/octet-stream',
      publicPath,
      category: 'notes',
      projectId: noteId,
      folder: null,
      writeLocalCopy: async (): Promise<void> => {
        await fs.mkdir(diskDir, { recursive: true });
        await fs.writeFile(localDiskPath, fileBuffer);
      },
    });
    const storedFilepath = storageResult.filepath;
    storageSource = storageResult.source;

    const noteFile = await noteService.createNoteFile({
      noteId,
      slotIndex,
      filename,
      filepath: storedFilepath,
      mimetype: file.type,
      size: file.size,
      width: null,
      height: null,
    });
    void createFileUploadEvent({
      status: 'success',
      category: 'notes',
      projectId: noteId,
      filename,
      filepath: `${publicDir}/${filename}`,
      mimetype: file.type,
      size: file.size,
      source: 'noteFileService.uploadNoteFile',
      meta: { storageSource },
    }).catch(() => {});

    return noteFile;
  } catch (error) {
    void ErrorSystem.captureException(error);
    void createFileUploadEvent({
      status: 'error',
      category: 'notes',
      projectId: noteId,
      filename,
      filepath: `${publicDir}/${filename}`,
      mimetype: file.type,
      size: file.size,
      source: 'noteFileService.uploadNoteFile',
      errorMessage: error instanceof Error ? error.message : 'Upload failed',
      meta: { storageSource },
    }).catch(() => {});
    await ErrorSystem.captureException(error, {
      service: 'noteFileService',
      action: 'uploadNoteFile',
      filename,
      noteId,
    });
    throw error;
  }
}

export async function deleteNoteFile(
  noteId: string,
  slotIndex: number,
  filepath: string
): Promise<boolean> {
  try {
    await deleteFileFromStorage(filepath);
    const noteDir = path.join(notesRoot, noteId);
    try {
      const remaining = await fs.readdir(noteDir);
      if (remaining.length === 0) {
        await fs.rmdir(noteDir);
      }
    } catch (error) {
      void ErrorSystem.captureException(error);

      // ignore cleanup errors
    }
    return await noteService.deleteNoteFile(noteId, slotIndex);
  } catch (error) {
    void ErrorSystem.captureException(error);
    await ErrorSystem.captureException(error, {
      service: 'noteFileService',
      action: 'deleteNoteFile',
      noteId,
      filepath,
    });
    return false;
  }
}

