export const buildTree = (
  categories: CategoryRecord[],
  notes: NoteRecord[] = []
): CategoryWithChildren[] => {
  const categoryMap: Record<string, CategoryWithChildren> = {};
  categories.forEach((cat: CategoryRecord): void => {
    categoryMap[cat.id] = { ...cat, children: [], notes: [] };
  });

  notes.forEach((note: NoteRecord): void => {
    const noteCategories = (note.categories || []) as Array<
      string | { categoryId: string }
    >;
    noteCategories.forEach((c): void => {
      const categoryId = typeof c === 'string' ? c : c.categoryId;
      const category = categoryMap[categoryId];
      if (category) {
        if (!category.notes) {
          category.notes = [];
        }
        category.notes.push(note);
      }
    });
  });

  const rootCategories: CategoryWithChildren[] = [];

  categories.forEach((cat: CategoryRecord): void => {
    const current = categoryMap[cat.id];
    if (!current) return;

    if (cat.parentId) {
      const parent = categoryMap[cat.parentId];
      if (parent) {
        parent.children.push(current);
      } else {
        rootCategories.push(current);
      }
    } else {
      rootCategories.push(current);
    }
  });

  return rootCategories;
};

export const buildIncomingRelationsMap = (
  incomingDocs: NoteDocument[],
  targetNoteIds: Set<string>
): Map<string, NoteRelationToEmbedded[]> => {
  const incoming = new Map<string, NoteRelationToEmbedded[]>();

  incomingDocs.forEach((incomingDoc: NoteDocument): void => {
    const sourceId = incomingDoc.id ?? incomingDoc._id;
    if (!incomingDoc.relationsFrom?.length) return;

    incomingDoc.relationsFrom.forEach((rel: NoteRelationFromEmbedded): void => {
      const targetId = rel.targetNote?.id ?? rel.targetNoteId;
      if (!targetId || !targetNoteIds.has(targetId)) return;

      const relation: NoteRelationToEmbedded = {
        id: rel.id,
        type: rel.type,
        sourceNoteId: sourceId,
        targetNoteId: targetId,
        assignedAt: toIsoCreatedAt(rel.assignedAt),
        sourceNote: {
          id: sourceId,
          title: incomingDoc.title,
          color: incomingDoc.color ?? null,
        },
      };

      const existing = incoming.get(targetId) ?? [];
      existing.push(relation);
      incoming.set(targetId, existing);
    });
  });

  return incoming;
};

const applyNoteSearchScopeFilter = (
  filter: Filter<NoteDocument>,
  search: string,
  searchScope: NoteFilters['searchScope']
): void => {
  const regex = { $regex: search, $options: 'i' };
  if (searchScope === 'both') {
    filter.$or = [{ title: regex }, { content: regex }];
    return;
  }
  if (searchScope === 'title') {
    filter['title'] = regex;
    return;
  }
  if (searchScope === 'content') {
    filter['content'] = regex;
  }
};

const applyBooleanNoteFilter = (
  filter: Filter<NoteDocument>,
  key: 'isPinned' | 'isArchived' | 'isFavorite',
  value: unknown
): void => {
  if (typeof value === 'boolean') {
    filter[key] = value;
  }
};

const applyEmbeddedIdFilter = (
  filter: Filter<NoteDocument>,
  key: 'tags' | 'categories',
  embeddedKey: 'tagId' | 'categoryId',
  values: string[] | undefined
): void => {
  if (values && values.length > 0) {
    filter[key] = { $elemMatch: { [embeddedKey]: { $in: values } } };
  }
};

export const buildSearchFilter = (filters: NoteFilters = {}): Filter<NoteDocument> => {
  const filter: Filter<NoteDocument> = {};
  if (filters['notebookId']) {
    filter['notebookId'] = filters['notebookId'];
  }

  if (filters['search']) {
    applyNoteSearchScopeFilter(filter, filters['search'], filters['searchScope'] || 'both');
  }

  applyBooleanNoteFilter(filter, 'isPinned', filters['isPinned']);
  applyBooleanNoteFilter(filter, 'isArchived', filters['isArchived']);
  applyBooleanNoteFilter(filter, 'isFavorite', filters['isFavorite']);
  applyEmbeddedIdFilter(filter, 'tags', 'tagId', filters['tagIds']);
  applyEmbeddedIdFilter(filter, 'categories', 'categoryId', filters['categoryIds']);

  return filter;
};

import { randomUUID } from 'crypto';

import type {
  CategoryRecord,
  CategoryWithChildren,
  CategoryCreateInput,
  CategoryUpdateInput,
} from '@/shared/contracts/notes';
import { notFoundError } from '@/shared/errors/app-error';
import { getMongoDb } from '@/shared/lib/db/mongo-client';

import type { CategoryDocument, NoteDocument } from '@/features/notesapp/contracts';
import type { Filter, UpdateFilter } from 'mongodb';


const categoryCollectionName = 'categories';
const noteCollectionName = 'notes';

const toCategoryRecord = (doc: CategoryDocument): CategoryRecord => ({
  id: doc.id ?? doc._id,
  name: doc.name,
  description: doc.description ?? null,
  color: doc.color ?? null,
  parentId: doc.parentId ?? null,
  notebookId: doc.notebookId ?? null,
  themeId: doc.themeId ?? null,
  sortIndex: doc.sortIndex ?? null,
  createdAt: typeof doc.createdAt === 'string' ? doc.createdAt : doc.createdAt.toISOString(),
  updatedAt:
    typeof doc.updatedAt === 'string' ? doc.updatedAt : (doc.updatedAt?.toISOString() ?? null),
});

const buildCategoryTree = (categories: CategoryRecord[]): CategoryWithChildren[] => {
  const categoryMap: Record<string, CategoryWithChildren> = {};
  categories.forEach((category) => {
    categoryMap[category.id] = { ...category, children: [], notes: [] };
  });

  const rootCategories: CategoryWithChildren[] = [];
  categories.forEach((category) => {
    const current = categoryMap[category.id];
    if (!current) return;
    if (!category.parentId) {
      rootCategories.push(current);
      return;
    }

    const parent = categoryMap[category.parentId];
    if (parent) {
      parent.children.push(current);
      return;
    }

    rootCategories.push(current);
  });

  return rootCategories;
};

type MongoCategoryImpl = {
  getAllCategories: (notebookId: string) => Promise<CategoryRecord[]>;
  getCategoryById: (id: string) => Promise<CategoryRecord | null>;
  getCategoryTree: (notebookId: string) => Promise<CategoryWithChildren[]>;
  createCategory: (data: CategoryCreateInput) => Promise<CategoryRecord>;
  updateCategory: (id: string, data: CategoryUpdateInput) => Promise<CategoryRecord>;
  deleteCategory: (id: string) => Promise<void>;
};

export const mongoCategoryImpl: MongoCategoryImpl = {
  async getAllCategories(notebookId: string): Promise<CategoryRecord[]> {
    const db = await getMongoDb();
    const collection = db.collection<CategoryDocument>(categoryCollectionName);
    const docs = await collection.find({ notebookId }).sort({ name: 1 }).toArray();
    return docs.map((doc) => toCategoryRecord(doc));
  },

  async getCategoryById(id: string): Promise<CategoryRecord | null> {
    const db = await getMongoDb();
    const collection = db.collection<CategoryDocument>(categoryCollectionName);
    const doc = await collection.findOne({
      $or: [{ id }, { _id: id }],
    } as Filter<CategoryDocument>);
    return doc ? toCategoryRecord(doc) : null;
  },

  async getCategoryTree(notebookId: string): Promise<CategoryWithChildren[]> {
    const categories = await mongoCategoryImpl.getAllCategories(notebookId);
    return buildCategoryTree(categories);
  },

  async createCategory(data: CategoryCreateInput): Promise<CategoryRecord> {
    const db = await getMongoDb();
    const collection = db.collection<CategoryDocument>(categoryCollectionName);
    const id = randomUUID();
    const now = new Date();
    const doc: CategoryDocument = {
      _id: id,
      id,
      name: data.name,
      color: data.color ?? null,
      parentId: data.parentId ?? null,
      notebookId: data.notebookId,
      createdAt: now.toISOString(),
      updatedAt: now.toISOString(),
    };
    await collection.insertOne(doc);
    return toCategoryRecord(doc);
  },

  async updateCategory(id: string, data: CategoryUpdateInput): Promise<CategoryRecord> {
    const db = await getMongoDb();
    const collection = db.collection<CategoryDocument>(categoryCollectionName);
    const now = new Date();
    const update: UpdateFilter<CategoryDocument> = {
      $set: {
        updatedAt: now.toISOString(),
        ...(data.name !== undefined && { name: data.name }),
        ...(data.color !== undefined && { color: data.color }),
        ...(data.parentId !== undefined && { parentId: data.parentId }),
      },
    };
    const result = await collection.findOneAndUpdate(
      { $or: [{ id }, { _id: id }] } as Filter<CategoryDocument>,
      update,
      { returnDocument: 'after' }
    );
    if (!result) throw notFoundError('Category not found');

    const category = toCategoryRecord(result);
    await db
      .collection<NoteDocument>(noteCollectionName)
      .updateMany(
        { 'categories.categoryId': category.id } as Filter<NoteDocument>,
        { $set: { 'categories.$.category': category } } as UpdateFilter<NoteDocument>
      );

    return category;
  },

  async deleteCategory(id: string): Promise<void> {
    const db = await getMongoDb();
    const collection = db.collection<CategoryDocument>(categoryCollectionName);
    const result = await collection.deleteOne({
      $or: [{ id }, { _id: id }],
    } as Filter<CategoryDocument>);
    if (result.deletedCount === 0) throw notFoundError('Category not found');

    // Update children parentId to null
    await collection.updateMany(
      { parentId: id } as Filter<CategoryDocument>,
      { $set: { parentId: null } } as UpdateFilter<CategoryDocument>
    );

    // Remove from notes
    await db
      .collection<NoteDocument>(noteCollectionName)
      .updateMany(
        {} as Filter<NoteDocument>,
        { $pull: { categories: { categoryId: id } } } as UpdateFilter<NoteDocument>
      );
  },
};

